"use client"

import * as React from "react"
import { useParams } from "next/navigation"
import { ChatInterface } from "@/components/chat-interface"

export default function ChatConversationPage() {
    const params = useParams()
    const id = params.id as string

    const [conversationMeta, setConversationMeta] = React.useState<{
        type: string
        projectId?: string
        workflowId?: string
    } | null>(null)
    const [isLoading, setIsLoading] = React.useState(true)

    React.useEffect(() => {
        const loadConversationMeta = async () => {
            try {
                const res = await fetch(`/api/chat/conversations/${id}`)
                if (res.ok) {
                    const data = await res.json()
                    setConversationMeta({
                        type: data.type || 'assistant',
                        projectId: data.projectId,
                        workflowId: data.workflowId
                    })
                }
            } catch (error) {
            } finally {
                setIsLoading(false)
            }
        }
        loadConversationMeta()
    }, [id])

    if (isLoading) {
        return (
            <div className="flex flex-1 items-center justify-center min-h-0">
                <div className="text-muted-foreground text-sm">Loading conversation...</div>
            </div>
        )
    }

    return (
        <div className="flex flex-1 min-h-0 flex-col">
            <ChatInterface
                initialConversationId={id}
                conversationType={(conversationMeta?.type as 'assistant' | 'documents' | 'templates') || 'assistant'}
                projectId={conversationMeta?.projectId}
                workflowId={conversationMeta?.workflowId}
            />
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { createPortal } from "react-dom"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Button } from "@/components/ui/button"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"
import {
    Shield,
    Key,
    Loader2,
    Save,
} from "lucide-react"

// =====================================================================

export default function ApiKeysTab({ canManage }: { canManage: boolean }) {
    const [provider, setProvider] = useState<string>("none")
    const [apiKey, setApiKey] = useState("")
    const [azureEndpoint, setAzureEndpoint] = useState("")
    const [azureDeployment, setAzureDeployment] = useState("")
    const [keyHint, setKeyHint] = useState<string | null>(null)
    const [loading, setLoading] = useState(false)
    const [fetching, setFetching] = useState(true)
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)

    // Fetch current BYOK config
    useEffect(() => {
        fetch("/api/org/byok")
            .then(r => r.json())
            .then(data => {
                if (data.success) {
                    setProvider(data.data.provider || "none")
                    setKeyHint(data.data.keyHint)
                    setAzureEndpoint(data.data.azureEndpoint || "")
                    setAzureDeployment(data.data.azureDeployment || "")
                }
            })
            .catch(() => { })
            .finally(() => setFetching(false))
    }, [])

    const handleSave = async () => {
        if (!apiKey.trim()) {
            toast.error("Please enter an API key")
            return
        }
        if (provider === "azure_openai" && (!azureEndpoint.trim() || !azureDeployment.trim())) {
            toast.error("Azure endpoint and deployment name are required")
            return
        }

        setLoading(true)
        try {
            const res = await fetch("/api/org/byok", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    provider: provider === "none" ? "openai" : provider,
                    apiKey: apiKey.trim(),
                    azureEndpoint: azureEndpoint.trim() || undefined,
                    azureDeployment: azureDeployment.trim() || undefined,
                })
            })
            const data = await res.json()
            if (data.success) {
                toast.success("API key saved and validated successfully")
                setKeyHint(data.data.keyHint)
                setProvider(data.data.provider)
                setApiKey("")
            } else {
                toast.error(data.error?.message || "Failed to save API key")
            }
        } catch {
            toast.error("An error occurred while saving")
        } finally {
            setLoading(false)
        }
    }

    const handleDelete = async () => {
        setLoading(true)
        try {
            const res = await fetch("/api/org/byok", { method: "DELETE" })
            const data = await res.json()
            if (data.success) {
                toast.success("API key removed. Reverted to Wesley default.")
                setProvider("none")
                setKeyHint(null)
                setApiKey("")
                setAzureEndpoint("")
                setAzureDeployment("")
                setShowDeleteConfirm(false)
            } else {
                toast.error(data.error?.message || "Failed to remove API key")
            }
        } catch {
            toast.error("An error occurred")
        } finally {
            setLoading(false)
        }
    }

    if (fetching) {
        return <div className="flex justify-center py-12"><Loader2 className="h-6 w-6 animate-spin text-muted-foreground" /></div>
    }

    const isConfigured = provider !== "none" && keyHint

    return (
        <>
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <Shield className="h-5 w-5 text-primary" /> Bring Your Own Key (BYOK)
                    </CardTitle>
                    <CardDescription>
                        Use your organization&apos;s own OpenAI or Azure OpenAI API key for all AI features. 
                        Your data routing and billing go through your own account. Wesley controls which models are used.
                    </CardDescription>
                </CardHeader>
                <CardContent className="space-y-6">
                    {/* Current Status */}
                    {isConfigured && (
                        <div className="rounded-md bg-emerald-500/10 p-3 border border-emerald-500/20 text-emerald-600 dark:text-emerald-400 text-sm flex items-center gap-2 font-medium">
                            <Shield className="h-4 w-4" /> 
                            BYOK Active — {provider === "azure_openai" ? "Azure OpenAI" : "OpenAI"} ({keyHint})
                        </div>
                    )}

                    {!isConfigured && (
                        <div className="rounded-md bg-muted p-3 border text-sm text-muted-foreground">
                            Using Wesley&apos;s default API key. Configure your own key below for dedicated billing and data routing.
                        </div>
                    )}

                    {canManage && (
                        <div className="space-y-4 pt-2">
                            {/* Provider Selection */}
                            <div className="space-y-2">
                                <Label>Provider</Label>
                                <Select
                                    value={provider === "none" ? "openai" : provider}
                                    onValueChange={(v) => setProvider(v)}
                                >
                                    <SelectTrigger>
                                        <SelectValue placeholder="Select provider" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="openai">OpenAI</SelectItem>
                                        <SelectItem value="azure_openai">Azure OpenAI</SelectItem>
                                    </SelectContent>
                                </Select>
                                <p className="text-xs text-muted-foreground">
                                    {provider === "azure_openai" 
                                        ? "Data stays in your Azure tenant. Requires a deployed OpenAI model in your Azure account." 
                                        : "Standard OpenAI API. Billing goes through your OpenAI account."
                                    }
                                </p>
                            </div>

                            {/* API Key */}
                            <div className="space-y-2">
                                <Label>API Key</Label>
                                <Input
                                    type="password"
                                    placeholder={isConfigured ? `Current: ${keyHint}  •  Enter new key to replace` : provider === "azure_openai" ? "Enter your Azure API key" : "sk-..."}
                                    value={apiKey}
                                    onChange={e => setApiKey(e.target.value)}
                                />
                                <p className="text-xs text-muted-foreground">
                                    Your key is encrypted at rest (AES-256-GCM) and never stored in plaintext.
                                </p>
                            </div>

                            {/* Azure-specific fields */}
                            {(provider === "azure_openai") && (
                                <>
                                    <div className="space-y-2">
                                        <Label>Azure Endpoint URL</Label>
                                        <Input
                                            placeholder="https://your-resource.openai.azure.com"
                                            value={azureEndpoint}
                                            onChange={e => setAzureEndpoint(e.target.value)}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Deployment Name</Label>
                                        <Input
                                            placeholder="gpt-4o"
                                            value={azureDeployment}
                                            onChange={e => setAzureDeployment(e.target.value)}
                                        />
                                        <p className="text-xs text-muted-foreground">
                                            The deployment must use the same model version Wesley requires (e.g., gpt-4o).
                                        </p>
                                    </div>
                                </>
                            )}

                            {/* Actions */}
                            <div className="flex justify-between pt-4 border-t">
                                {isConfigured ? (
                                    <Button variant="destructive" onClick={() => setShowDeleteConfirm(true)} disabled={loading}>
                                        Remove Key
                                    </Button>
                                ) : <div />}
                                <Button 
                                    onClick={handleSave} 
                                    disabled={loading || !apiKey.trim()}
                                >
                                    {loading ? (
                                        <span className="flex items-center"><Loader2 className="h-4 w-4 animate-spin mr-2" /> Validating & Saving...</span>
                                    ) : (
                                        isConfigured ? "Update Key" : "Save & Activate"
                                    )}
                                </Button>
                            </div>
                        </div>
                    )}

                    {!canManage && (
                        <p className="text-sm text-muted-foreground italic">
                            Only organization owners and admins can manage API keys.
                        </p>
                    )}
                </CardContent>
            </Card>

            {/* Delete Confirmation Portal */}
            {showDeleteConfirm && typeof window !== 'undefined' && createPortal(
                <div className="fixed inset-0 z-[100] flex items-center justify-center">
                    <div
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200"
                        onClick={() => { if (!loading) setShowDeleteConfirm(false) }}
                    />
                    <div className="relative z-[100] w-full max-w-md mx-4 bg-white dark:bg-zinc-900 rounded-xl border border-border/60 shadow-2xl p-6 animate-in fade-in-0 zoom-in-95 duration-200">
                        <div className="space-y-2">
                            <h2 className="text-lg font-semibold text-foreground">Remove API Key?</h2>
                            <p className="text-sm text-muted-foreground">
                                This will immediately revert all AI features to use Wesley&apos;s default API key. 
                                Your organization&apos;s key will be permanently deleted from our servers.
                            </p>
                        </div>
                        <div className="flex justify-end gap-3 mt-6">
                            <Button
                                variant="outline"
                                onClick={() => setShowDeleteConfirm(false)}
                                disabled={loading}
                                className="rounded-lg"
                            >
                                Cancel
                            </Button>
                            <Button
                                onClick={handleDelete}
                                disabled={loading}
                                className="rounded-lg bg-red-600 text-white hover:bg-red-700 dark:bg-red-600 dark:hover:bg-red-700"
                            >
                                {loading ? (
                                    <span className="flex items-center"><Loader2 className="h-4 w-4 animate-spin mr-2" /> Removing...</span>
                                ) : 'Remove Key'}
                            </Button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { useOrg } from "@/context/org-context"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"
import {
    ScrollText,
    Key,
    Loader2,
    Search,
    Filter,
} from "lucide-react"
import type { Team, Invite, AuditEntry } from "../types"

// =====================================================================

export default function AuditTab() {
    const { members } = useOrg()
    const [entries, setEntries] = useState<AuditEntry[]>([])
    const [loading, setLoading] = useState(true)
    const [total, setTotal] = useState(0)
    const [page, setPage] = useState(0)
    const [expandedId, setExpandedId] = useState<string | null>(null)
    const pageSize = 25

    // Filters
    const [actionFilter, setActionFilter] = useState('')
    const [userFilter, setUserFilter] = useState('')
    const [dateFrom, setDateFrom] = useState('')
    const [dateTo, setDateTo] = useState('')
    const [searchQuery, setSearchQuery] = useState('')
    const [debouncedSearch, setDebouncedSearch] = useState('')
    const [exporting, setExporting] = useState(false)

    // Debounce search
    useEffect(() => {
        const timer = setTimeout(() => setDebouncedSearch(searchQuery), 400)
        return () => clearTimeout(timer)
    }, [searchQuery])

    const fetchAudit = useCallback(async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams()
            params.set('limit', String(pageSize))
            params.set('offset', String(page * pageSize))
            if (actionFilter) params.set('action', actionFilter)
            if (userFilter) params.set('userId', userFilter)
            if (dateFrom) params.set('from', dateFrom)
            if (dateTo) params.set('to', dateTo)
            if (debouncedSearch) params.set('search', debouncedSearch)

            const res = await fetch(`/api/org/audit-log?${params}`)
            const data = await res.json()
            if (data.success) {
                setEntries(data.data || [])
                setTotal(data.total || 0)
            }
        } catch {
        } finally {
            setLoading(false)
        }
    }, [page, actionFilter, userFilter, dateFrom, dateTo, debouncedSearch])

    useEffect(() => { fetchAudit() }, [fetchAudit])

    // Reset to first page when filters change
    useEffect(() => { setPage(0) }, [actionFilter, userFilter, dateFrom, dateTo, debouncedSearch])

    const handleExport = async () => {
        setExporting(true)
        try {
            const params = new URLSearchParams()
            if (actionFilter) params.set('action', actionFilter)
            if (userFilter) params.set('userId', userFilter)
            if (dateFrom) params.set('from', dateFrom)
            if (dateTo) params.set('to', dateTo)
            if (debouncedSearch) params.set('search', debouncedSearch)

            const res = await fetch(`/api/org/audit-log/export?${params}`)
            if (!res.ok) throw new Error('Export failed')

            const blob = await res.blob()
            const url = URL.createObjectURL(blob)
            const a = document.createElement('a')
            a.href = url
            a.download = `audit_log_${new Date().toISOString().split('T')[0]}.csv`
            document.body.appendChild(a)
            a.click()
            document.body.removeChild(a)
            URL.revokeObjectURL(url)
            toast.success('Audit log exported')
        } catch {
            toast.error('Failed to export audit log')
        } finally {
            setExporting(false)
        }
    }

    const clearFilters = () => {
        setActionFilter('')
        setUserFilter('')
        setDateFrom('')
        setDateTo('')
        setSearchQuery('')
        setPage(0)
    }

    const hasFilters = actionFilter || userFilter || dateFrom || dateTo || debouncedSearch

    const totalPages = Math.ceil(total / pageSize)

    // Complete action label map
    const ACTION_LABELS: Record<string, string> = {
        "org.updated": "Updated organization",
        "member.invited": "Invited member",
        "member.joined": "Member joined",
        "member.role_changed": "Changed member role",
        "member.removed": "Removed member",
        "invite.created": "Created invitation",
        "invite.revoked": "Revoked invitation",
        "invite.accepted": "Accepted invitation",
        "team.created": "Created team",
        "team.updated": "Updated team",
        "team.deleted": "Deleted team",
        "team.member_added": "Added team member",
        "team.member_removed": "Removed team member",
        "project.created": "Created project",
        "project.deleted": "Deleted project",
        "sso.configured": "Configured SSO",
        "sso.disabled": "Disabled SSO",
        "byok.configured": "Configured API key (BYOK)",
        "byok.updated": "Updated API key (BYOK)",
        "byok.removed": "Removed API key (BYOK)",
        "ethical_wall.created": "Created ethical wall",
        "ethical_wall.updated": "Updated ethical wall",
        "ethical_wall.deleted": "Deleted ethical wall",
        "matter.created": "Created matter",
        "matter.updated": "Updated matter",
        "matter.archived": "Archived matter",
    }

    const getActionLabel = (action: string) => ACTION_LABELS[action] || action.replace(/[._]/g, ' ')

    // Action categories for filter dropdown
    const ACTION_CATEGORIES = [
        { value: '', label: 'All actions' },
        { value: 'org', label: 'Organization' },
        { value: 'member', label: 'Members' },
        { value: 'invite', label: 'Invitations' },
        { value: 'team', label: 'Teams' },
        { value: 'project', label: 'Projects' },
        { value: 'sso', label: 'SSO' },
        { value: 'byok', label: 'API Keys (BYOK)' },
        { value: 'ethical_wall', label: 'Ethical Walls' },
        { value: 'matter', label: 'Matters' },
    ]

    // Action badge color
    const getActionColor = (action: string) => {
        if (action.startsWith('ethical_wall')) return 'text-amber-600 bg-amber-50 dark:text-amber-400 dark:bg-amber-950'
        if (action.startsWith('sso') || action.startsWith('byok')) return 'text-violet-600 bg-violet-50 dark:text-violet-400 dark:bg-violet-950'
        if (action.includes('delete') || action.includes('removed') || action.includes('revoked') || action.includes('disabled')) return 'text-red-600 bg-red-50 dark:text-red-400 dark:bg-red-950'
        if (action.includes('created') || action.includes('joined') || action.includes('added') || action.includes('configured')) return 'text-emerald-600 bg-emerald-50 dark:text-emerald-400 dark:bg-emerald-950'
        return 'text-blue-600 bg-blue-50 dark:text-blue-400 dark:bg-blue-950'
    }

    return (
        <div className="space-y-4">
            {/* Header */}
            <Card>
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle className="flex items-center gap-2">
                                <ScrollText className="h-5 w-5 text-primary" />
                                Audit Log
                            </CardTitle>
                            <CardDescription>
                                {total.toLocaleString()} recorded actions · Track every change for compliance and security reviews
                            </CardDescription>
                        </div>
                        <Button onClick={handleExport} variant="outline" size="sm" className="gap-1.5" disabled={exporting || total === 0}>
                            {exporting ? <Loader2 className="h-4 w-4 animate-spin" /> : <ScrollText className="h-4 w-4" />}
                            Export CSV
                        </Button>
                    </div>
                </CardHeader>
                <CardContent className="space-y-4">
                    {/* Filters Row */}
                    <div className="flex flex-wrap items-center gap-3">
                        <div className="relative flex-1 min-w-[200px]">
                            <Input
                                placeholder="Search actions, users, targets..."
                                value={searchQuery}
                                onChange={e => setSearchQuery(e.target.value)}
                                className="pl-3"
                            />
                        </div>
                        <Select value={actionFilter || '_all'} onValueChange={v => setActionFilter(v === '_all' ? '' : v)}>
                            <SelectTrigger className="w-[170px]">
                                <SelectValue placeholder="All actions" />
                            </SelectTrigger>
                            <SelectContent>
                                {ACTION_CATEGORIES.map(cat => (
                                    <SelectItem key={cat.value || '_all'} value={cat.value || '_all'}>
                                        {cat.label}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <Select value={userFilter || '_all'} onValueChange={v => setUserFilter(v === '_all' ? '' : v)}>
                            <SelectTrigger className="w-[170px]">
                                <SelectValue placeholder="All users" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="_all">All users</SelectItem>
                                {members.map(m => (
                                    <SelectItem key={m.user_id} value={m.user_id}>
                                        {m.user_name || 'Unnamed User'}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <Input
                            type="date"
                            value={dateFrom}
                            onChange={e => setDateFrom(e.target.value)}
                            className="w-[145px]"
                            title="From date"
                        />
                        <Input
                            type="date"
                            value={dateTo}
                            onChange={e => setDateTo(e.target.value)}
                            className="w-[145px]"
                            title="To date"
                        />
                        {hasFilters && (
                            <Button variant="ghost" size="sm" onClick={clearFilters} className="text-muted-foreground">
                                Clear
                            </Button>
                        )}
                    </div>
                </CardContent>
            </Card>

            {/* Results */}
            <Card>
                <CardContent className="p-0">
                    {loading ? (
                        <div className="flex items-center justify-center py-16">
                            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                        </div>
                    ) : entries.length === 0 ? (
                        <div className="text-center py-16 text-muted-foreground">
                            <ScrollText className="h-12 w-12 mx-auto mb-4 opacity-20" />
                            <p className="text-sm">{hasFilters ? 'No entries match your filters.' : 'No audit entries yet.'}</p>
                        </div>
                    ) : (
                        <>
                            {/* Table header */}
                            <div className="grid grid-cols-[1fr_1.2fr_1fr_0.8fr_auto] gap-4 px-4 py-3 border-b text-xs font-medium text-muted-foreground uppercase tracking-wider">
                                <span>Timestamp</span>
                                <span>Action</span>
                                <span>User</span>
                                <span>Target</span>
                                <span className="w-8"></span>
                            </div>

                            {/* Table rows */}
                            <div className="divide-y">
                                {entries.map(entry => (
                                    <div key={entry.id}>
                                        <button
                                            className="grid grid-cols-[1fr_1.2fr_1fr_0.8fr_auto] gap-4 px-4 py-3 w-full text-left hover:bg-muted/40 transition-colors items-center"
                                            onClick={() => setExpandedId(expandedId === entry.id ? null : entry.id)}
                                            title="Click to expand details"
                                        >
                                            <span className="text-sm text-muted-foreground tabular-nums">
                                                {new Date(entry.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                                                {' '}
                                                <span className="text-xs">{new Date(entry.created_at).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })}</span>
                                            </span>
                                            <span>
                                                <span className={`inline-flex items-center px-2 py-0.5 rounded-md text-xs font-medium ${getActionColor(entry.action)}`}>
                                                    {getActionLabel(entry.action)}
                                                </span>
                                            </span>
                                            <span className="flex items-center gap-2 min-w-0">
                                                {entry.actor_image ? (
                                                    <span className="h-6 w-6 rounded-full bg-muted shrink-0 overflow-hidden border">
                                                        {/* eslint-disable-next-line @next/next/no-img-element */}
                                                        <img src={entry.actor_image} alt="" className="h-full w-full object-cover" />
                                                    </span>
                                                ) : (
                                                    <span className="h-6 w-6 rounded-full bg-muted flex items-center justify-center text-[10px] font-medium shrink-0 border border-primary/10 text-primary">
                                                        {entry.actor_name
                                                            ? entry.actor_name.substring(0, 2).toUpperCase()
                                                            : (entry.actor_name || 'S').substring(0, 2).toUpperCase()}
                                                    </span>
                                                )}
                                                <span className="text-sm truncate">{entry.actor_name || 'System'}</span>
                                            </span>
                                            <span className="text-sm text-muted-foreground truncate">
                                                {entry.target_entity || '—'}
                                            </span>
                                            <span className="w-8 flex justify-center">
                                                <svg className={`h-4 w-4 text-muted-foreground transition-transform ${expandedId === entry.id ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                                </svg>
                                            </span>
                                        </button>

                                        {/* Expanded detail */}
                                        {expandedId === entry.id && (
                                            <div className="px-4 py-3 bg-muted/20 border-t">
                                                <div className="grid grid-cols-2 gap-4 text-sm">
                                                    <div>
                                                        <p className="text-xs text-muted-foreground mb-1">Full Timestamp</p>
                                                        <p className="font-mono text-xs">{new Date(entry.created_at).toISOString()}</p>
                                                    </div>
                                                    <div>
                                                        <p className="text-xs text-muted-foreground mb-1">Action Code</p>
                                                        <p className="font-mono text-xs">{entry.action}</p>
                                                    </div>
                                                    <div>
                                                        <p className="text-xs text-muted-foreground mb-1">Actor ID</p>
                                                        <p className="font-mono text-xs break-all">{entry.actor_user_id}</p>
                                                    </div>
                                                    {entry.target_id && (
                                                        <div>
                                                            <p className="text-xs text-muted-foreground mb-1">Target ID</p>
                                                            <p className="font-mono text-xs break-all">{entry.target_id}</p>
                                                        </div>
                                                    )}
                                                </div>
                                                {entry.metadata && Object.keys(entry.metadata).length > 0 && (
                                                    <div className="mt-3">
                                                        <p className="text-xs text-muted-foreground mb-1">Metadata</p>
                                                        <pre className="text-xs font-mono bg-muted/50 rounded-md p-2 overflow-x-auto max-h-32">
                                                            {JSON.stringify(entry.metadata, null, 2)}
                                                        </pre>
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>

                            {/* Pagination */}
                            {totalPages > 1 && (
                                <div className="flex items-center justify-between px-4 py-3 border-t">
                                    <p className="text-sm text-muted-foreground">
                                        Showing {page * pageSize + 1}–{Math.min((page + 1) * pageSize, total)} of {total.toLocaleString()}
                                    </p>
                                    <div className="flex items-center gap-1">
                                        <Button variant="outline" size="sm" disabled={page === 0} onClick={() => setPage(0)}>
                                            First
                                        </Button>
                                        <Button variant="outline" size="sm" disabled={page === 0} onClick={() => setPage(p => p - 1)}>
                                            Previous
                                        </Button>
                                        <span className="px-3 text-sm text-muted-foreground">
                                            Page {page + 1} of {totalPages}
                                        </span>
                                        <Button variant="outline" size="sm" disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>
                                            Next
                                        </Button>
                                        <Button variant="outline" size="sm" disabled={page >= totalPages - 1} onClick={() => setPage(totalPages - 1)}>
                                            Last
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </CardContent>
            </Card>
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { createPortal } from "react-dom"
import type { EthicalWallData, OrgProject } from "../types"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Textarea } from "@/components/ui/textarea"
import { toast } from "sonner"
import {
    Shield,
    Trash2,
    Loader2,
    ShieldAlert,
    Plus,
    X,
    AlertTriangle,
    CheckCircle2,
    Save,
} from "lucide-react"

export default function EthicalWallsTab({ canManage, members }: {
    canManage: boolean
    members: { user_id: string; user_name?: string | null; profile_image?: string | null; role: string }[]
}) {
    const [walls, setWalls] = useState<EthicalWallData[]>([])
    const [loading, setLoading] = useState(true)
    const [showCreate, setShowCreate] = useState(false)
    const [editing, setEditing] = useState<EthicalWallData | null>(null)
    const [deleteTarget, setDeleteTarget] = useState<EthicalWallData | null>(null)
    const [orgProjects, setOrgProjects] = useState<OrgProject[]>([])
    const [saving, setSaving] = useState(false)

    // Form state
    const [formName, setFormName] = useState('')
    const [formDescription, setFormDescription] = useState('')
    const [selectedMembers, setSelectedMembers] = useState<string[]>([])
    const [selectedProjects, setSelectedProjects] = useState<string[]>([])

    const fetchWalls = useCallback(async () => {
        try {
            const res = await fetch('/api/org/ethical-walls')
            const data = await res.json()
            if (data.success) setWalls(data.data || [])
        } catch { /* */ } finally { setLoading(false) }
    }, [])

    const fetchProjects = useCallback(async () => {
        try {
            const res = await fetch('/api/documents/projects')
            const data = await res.json()
            if (Array.isArray(data)) setOrgProjects(data.map((p: { id: string; title: string }) => ({ id: p.id, title: p.title })))
        } catch { /* */ }
    }, [])

    useEffect(() => { fetchWalls(); fetchProjects() }, [fetchWalls, fetchProjects])

    const resetForm = () => {
        setFormName(''); setFormDescription(''); setSelectedMembers([]); setSelectedProjects([])
    }

    const openCreate = () => {
        resetForm()
        setEditing(null)
        setShowCreate(true)
    }

    const openEdit = (wall: EthicalWallData) => {
        setFormName(wall.name)
        setFormDescription(wall.description || '')
        setSelectedMembers(wall.members.map(m => m.user_id))
        setSelectedProjects(wall.projects.map(p => p.project_id))
        setEditing(wall)
        setShowCreate(true)
    }

    const handleSave = async () => {
        if (!formName.trim() || selectedMembers.length === 0 || selectedProjects.length === 0) {
            toast.error('Name, at least one member, and at least one project are required')
            return
        }
        setSaving(true)
        try {
            const method = editing ? 'PUT' : 'POST'
            const body = editing
                ? { wallId: editing.id, name: formName, description: formDescription, memberUserIds: selectedMembers, projectIds: selectedProjects }
                : { name: formName, description: formDescription, memberUserIds: selectedMembers, projectIds: selectedProjects }

            const res = await fetch('/api/org/ethical-walls', {
                method, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body)
            })
            const data = await res.json()
            if (data.success) {
                toast.success(editing ? 'Wall updated' : 'Wall created')
                setShowCreate(false)
                resetForm()
                setEditing(null)
                await fetchWalls()
            } else {
                toast.error(data.error?.message || 'Failed to save wall')
            }
        } catch { toast.error('Failed to save wall') }
        finally { setSaving(false) }
    }

    const handleDelete = async () => {
        if (!deleteTarget) return
        setSaving(true)
        try {
            const res = await fetch(`/api/org/ethical-walls?wallId=${deleteTarget.id}`, { method: 'DELETE' })
            const data = await res.json()
            if (data.success) {
                toast.success('Wall deleted')
                setDeleteTarget(null)
                await fetchWalls()
            } else {
                toast.error(data.error?.message || 'Failed to delete')
            }
        } catch { toast.error('Failed to delete wall') }
        finally { setSaving(false) }
    }

    const handleToggleStatus = async (wall: EthicalWallData) => {
        const newStatus = wall.status === 'active' ? 'inactive' : 'active'
        try {
            const res = await fetch('/api/org/ethical-walls', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ wallId: wall.id, status: newStatus })
            })
            const data = await res.json()
            if (data.success) {
                toast.success(`Wall ${newStatus === 'active' ? 'activated' : 'deactivated'}`)
                await fetchWalls()
            }
        } catch { toast.error('Failed to update status') }
    }

    const toggleMember = (uid: string) => {
        setSelectedMembers(prev => prev.includes(uid) ? prev.filter(id => id !== uid) : [...prev, uid])
    }

    const toggleProject = (pid: string) => {
        setSelectedProjects(prev => prev.includes(pid) ? prev.filter(id => id !== pid) : [...prev, pid])
    }

    if (loading) return <div className="flex items-center justify-center py-12"><Loader2 className="h-6 w-6 animate-spin text-muted-foreground" /></div>

    return (
        <>
            <Card>
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <div>
                            <CardTitle className="flex items-center gap-2">
                                <ShieldAlert className="h-5 w-5 text-amber-500" />
                                Information Barriers
                            </CardTitle>
                            <CardDescription>
                                Prevent lawyers on conflicting matters from accessing each other&apos;s projects and data. Required by ABA rules.
                            </CardDescription>
                        </div>
                        {canManage && (
                            <Button onClick={openCreate} size="sm" className="gap-1">
                                <Plus className="h-4 w-4" /> New Wall
                            </Button>
                        )}
                    </div>
                </CardHeader>
                <CardContent>
                    {walls.length === 0 ? (
                        <div className="text-center py-12 text-muted-foreground">
                            <ShieldAlert className="h-12 w-12 mx-auto mb-4 opacity-30" />
                            <p className="text-sm">No ethical walls configured.</p>
                            <p className="text-xs mt-2">Create a wall to restrict project access between conflicting practice groups.</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {walls.map(wall => (
                                <div key={wall.id} className="rounded-lg border p-4 space-y-3">
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-3">
                                            <h4 className="font-semibold">{wall.name}</h4>
                                            <Badge variant={wall.status === 'active' ? 'default' : 'secondary'}>
                                                {wall.status === 'active' ? (
                                                    <><CheckCircle2 className="h-3 w-3 mr-1" /> Active</>
                                                ) : 'Inactive'}
                                            </Badge>
                                        </div>
                                        {canManage && (
                                            <div className="flex items-center gap-2">
                                                <Button variant="outline" size="sm" onClick={() => handleToggleStatus(wall)}>
                                                    {wall.status === 'active' ? 'Deactivate' : 'Activate'}
                                                </Button>
                                                <Button variant="outline" size="sm" onClick={() => openEdit(wall)}>Edit</Button>
                                                <Button variant="outline" size="sm" className="text-red-600 hover:text-red-700" onClick={() => setDeleteTarget(wall)} aria-label="Delete wall">
                                                    <Trash2 className="h-4 w-4" />
                                                </Button>
                                            </div>
                                        )}
                                    </div>
                                    {wall.description && <p className="text-sm text-muted-foreground">{wall.description}</p>}
                                    <div className="flex gap-6 text-sm">
                                        <div>
                                            <span className="text-muted-foreground">Members: </span>
                                            <span className="font-medium">{wall.members.length}</span>
                                            {wall.members.length > 0 && (
                                                <span className="text-muted-foreground ml-1">
                                                    ({wall.members.map(m => m.user_name || 'Unknown').join(', ')})
                                                </span>
                                            )}
                                        </div>
                                        <div>
                                            <span className="text-muted-foreground">Projects: </span>
                                            <span className="font-medium">{wall.projects.length}</span>
                                            {wall.projects.length > 0 && (
                                                <span className="text-muted-foreground ml-1">
                                                    ({wall.projects.map(p => p.title || 'Untitled').join(', ')})
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                    <p className="text-xs text-muted-foreground">
                                        Created {new Date(wall.created_at).toLocaleDateString()}
                                    </p>
                                </div>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Create/Edit Modal */}
            {showCreate && createPortal(
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
                    <div className="bg-background rounded-xl shadow-2xl border max-w-lg w-full mx-4 max-h-[85vh] overflow-y-auto">
                        <div className="p-6 space-y-5">
                            <div className="flex items-center justify-between">
                                <h3 className="font-semibold text-lg">{editing ? 'Edit Wall' : 'Create Ethical Wall'}</h3>
                                <button onClick={() => { setShowCreate(false); setEditing(null); resetForm() }} className="text-muted-foreground hover:text-foreground" title="Close">
                                    <X className="h-5 w-5" />
                                </button>
                            </div>

                            <div className="space-y-2">
                                <Label>Wall Name *</Label>
                                <Input value={formName} onChange={e => setFormName(e.target.value)} placeholder="e.g. Acme Corp v. Beta Inc" />
                            </div>

                            <div className="space-y-2">
                                <Label>Description</Label>
                                <Textarea value={formDescription} onChange={e => setFormDescription(e.target.value)} placeholder="Reason for this information barrier..." rows={2} />
                            </div>

                            <div className="space-y-2">
                                <Label>Authorized Members * <span className="text-xs text-muted-foreground font-normal">(only these users can access walled projects)</span></Label>
                                <div className="max-h-40 overflow-y-auto rounded-md border p-2 space-y-1">
                                    {members.map(m => (
                                        <label key={m.user_id} className="flex items-center gap-2 p-1.5 rounded hover:bg-muted cursor-pointer text-sm">
                                            <input type="checkbox" checked={selectedMembers.includes(m.user_id)} onChange={() => toggleMember(m.user_id)} className="rounded" />
                                            <span>{m.user_name || 'Unnamed User'}</span>
                                            <Badge variant="outline" className="ml-auto text-xs">{m.role}</Badge>
                                        </label>
                                    ))}
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label>Restricted Projects * <span className="text-xs text-muted-foreground font-normal">(these projects will be hidden from non-members)</span></Label>
                                <div className="max-h-40 overflow-y-auto rounded-md border p-2 space-y-1">
                                    {orgProjects.length === 0 ? (
                                        <p className="text-sm text-muted-foreground py-2 text-center">No projects found</p>
                                    ) : orgProjects.map(p => (
                                        <label key={p.id} className="flex items-center gap-2 p-1.5 rounded hover:bg-muted cursor-pointer text-sm">
                                            <input type="checkbox" checked={selectedProjects.includes(p.id)} onChange={() => toggleProject(p.id)} className="rounded" />
                                            <span>{p.title}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>

                            <div className="flex items-center gap-2 p-3 rounded-lg bg-amber-500/10 border border-amber-500/20">
                                <AlertTriangle className="h-4 w-4 text-amber-500 shrink-0" />
                                <p className="text-xs text-amber-700 dark:text-amber-400">
                                    When active, non-members will be unable to see, access, or query any data in the restricted projects.
                                </p>
                            </div>

                            <div className="flex justify-end gap-2 pt-2">
                                <Button variant="outline" onClick={() => { setShowCreate(false); setEditing(null); resetForm() }}>Cancel</Button>
                                <Button onClick={handleSave} disabled={saving}>
                                    {saving ? <><Loader2 className="h-4 w-4 animate-spin mr-2" /> Saving...</> : (editing ? 'Update Wall' : 'Create Wall')}
                                </Button>
                            </div>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* Delete Confirmation Modal */}
            {deleteTarget && createPortal(
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
                    <div className="bg-background rounded-xl shadow-2xl border max-w-md w-full mx-4 p-6 space-y-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-full bg-red-100 dark:bg-red-900/30">
                                <AlertTriangle className="h-5 w-5 text-red-600" />
                            </div>
                            <h3 className="font-semibold text-lg">Delete Ethical Wall</h3>
                        </div>
                        <p className="text-sm text-muted-foreground">
                            Are you sure you want to delete <strong>&quot;{deleteTarget.name}&quot;</strong>?
                            This will remove all access restrictions. Previously hidden projects will become visible to all org members.
                        </p>
                        <div className="flex justify-end gap-2">
                            <Button variant="outline" onClick={() => setDeleteTarget(null)}>Cancel</Button>
                            <Button onClick={handleDelete} disabled={saving} className="bg-red-600 text-white hover:bg-red-700">
                                {saving ? <><Loader2 className="h-4 w-4 animate-spin mr-2" /> Deleting...</> : 'Delete Wall'}
                            </Button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Button } from "@/components/ui/button"
import { toast } from "sonner"
import {
    Save,
} from "lucide-react"

// =====================================================================

export default function GeneralTab({ org, canManage, refreshOrg }: {
    org: { id: string; name: string; slug: string; status: string; member_count: number; licensed_seats: number; created_at: string }
    canManage: boolean
    refreshOrg: () => Promise<void>
}) {
    const [name, setName] = useState(org.name)
    const [slug, setSlug] = useState(org.slug)
    const [saving, setSaving] = useState(false)

    const handleSave = async () => {
        setSaving(true)
        try {
            const res = await fetch("/api/org", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ name, slug })
            })
            const data = await res.json()
            if (data.success) {
                toast.success("Organization updated")
                await refreshOrg()
            } else {
                toast.error(data.error?.message || "Failed to update")
            }
        } catch {
            toast.error("Failed to save changes")
        } finally {
            setSaving(false)
        }
    }

    return (
        <Card>
            <CardHeader>
                <CardTitle>Organization Details</CardTitle>
                <CardDescription>Basic information about your organization.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                <div className="grid gap-4 sm:grid-cols-2">
                    <div className="space-y-2">
                        <Label>Name</Label>
                        <Input value={name} onChange={e => setName(e.target.value)} disabled={!canManage} />
                    </div>
                    <div className="space-y-2">
                        <Label>Slug</Label>
                        <Input
                            value={slug}
                            onChange={e => {
                                const sanitized = e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '')
                                setSlug(sanitized)
                            }}
                            disabled={!canManage}
                        />
                        <p className="text-xs text-muted-foreground">Used in URLs. Letters, numbers, and hyphens only.</p>
                    </div>
                </div>

                <div className="grid gap-4 sm:grid-cols-3">
                    <div className="space-y-1">
                        <Label className="text-xs text-muted-foreground">Status</Label>
                        <p className="font-medium capitalize">{org.status}</p>
                    </div>
                    <div className="space-y-1">
                        <Label className="text-xs text-muted-foreground">Seat Usage</Label>
                        <p className="font-medium">{org.member_count} / {org.licensed_seats} seats</p>
                        <div className="w-full h-2 rounded-full bg-muted overflow-hidden mt-1">
                            <div
                                className={`h-full rounded-full transition-all duration-300 ${
                                    (org.member_count / org.licensed_seats) >= 0.9 ? 'bg-red-500' :
                                    (org.member_count / org.licensed_seats) >= 0.7 ? 'bg-amber-500' : 'bg-emerald-500'
                                }`}
                                style={{ width: `${Math.min((org.member_count / org.licensed_seats) * 100, 100)}%` }}
                            />
                        </div>
                    </div>
                    <div className="space-y-1">
                        <Label className="text-xs text-muted-foreground">Created</Label>
                        <p className="font-medium">{new Date(org.created_at).toLocaleDateString()}</p>
                    </div>
                </div>

                {canManage && (
                    <div className="flex justify-end pt-4 border-t">
                        <Button onClick={handleSave} disabled={saving}>
                            {saving ? "Saving…" : "Save Changes"}
                        </Button>
                    </div>
                )}
            </CardContent>
        </Card>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { toast } from "sonner"
import {
    Trash2,
} from "lucide-react"
import { roleIcon, roleBadgeVariant } from "../helpers"

// =====================================================================

export default function MembersTab({ members, canManage, refreshMembers }: {
    members: { id: string; user_id: string; role: string; joined_at?: string; created_at: string; user_name?: string | null; profile_image?: string | null }[]
    canManage: boolean
    refreshMembers: () => Promise<void>
}) {
    const handleRoleChange = async (userId: string, newRole: string) => {
        try {
            const res = await fetch("/api/org/members", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ user_id: userId, role: newRole })
            })
            const data = await res.json()
            if (data.success) {
                toast.success("Role updated")
                await refreshMembers()
            } else {
                toast.error(data.error?.message || "Failed to update role")
            }
        } catch {
            toast.error("Failed to update role")
        }
    }

    const handleRemove = async (userId: string) => {
        if (!confirm("Remove this member from the organization?")) return
        try {
            const res = await fetch(`/api/org/members?user_id=${encodeURIComponent(userId)}`, {
                method: "DELETE"
            })
            const data = await res.json()
            if (data.success) {
                toast.success("Member removed")
                await refreshMembers()
            } else {
                toast.error(data.error?.message || "Failed to remove member")
            }
        } catch {
            toast.error("Failed to remove member")
        }
    }

    return (
        <Card>
            <CardHeader>
                <CardTitle>Members</CardTitle>
                <CardDescription>{members.length} member{members.length !== 1 ? "s" : ""} in this organization.</CardDescription>
            </CardHeader>
            <CardContent>
                <div className="space-y-2">
                    {members.map(member => (
                        <div key={member.id} className="flex items-center justify-between p-3 rounded-lg border bg-card hover:bg-muted/30 transition-colors">
                            <div className="flex items-center gap-3 min-w-0">
                                {member.profile_image ? (
                                    <div className="h-9 w-9 rounded-full bg-muted shrink-0 overflow-hidden border">
                                        {/* eslint-disable-next-line @next/next/no-img-element */}
                                        <img src={member.profile_image} alt={member.user_name || member.user_id} className="h-full w-full object-cover" />
                                    </div>
                                ) : (
                                    <div className="h-9 w-9 rounded-full bg-muted flex items-center justify-center text-sm font-medium shrink-0 border border-primary/10 text-primary">
                                        {member.user_name
                                            ? member.user_name.substring(0, 2).toUpperCase()
                                            : (member.user_name || 'U').substring(0, 2).toUpperCase()}
                                    </div>
                                )}
                                <div className="truncate">
                                    <p className="text-sm font-medium truncate">{member.user_name || 'Unnamed User'}</p>
                                    <p className="text-xs text-muted-foreground">Joined {new Date(member.joined_at || member.created_at).toLocaleDateString()}</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-2 shrink-0">
                                {canManage && member.role !== "owner" ? (
                                    <Select value={member.role} onValueChange={val => handleRoleChange(member.user_id, val)}>
                                        <SelectTrigger className="w-[110px] h-8 text-xs">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="admin">Admin</SelectItem>
                                            <SelectItem value="member">Member</SelectItem>
                                            <SelectItem value="viewer">Viewer</SelectItem>
                                        </SelectContent>
                                    </Select>
                                ) : (
                                    <Badge variant={roleBadgeVariant(member.role)} className="gap-1">
                                        {roleIcon(member.role)}
                                        {member.role}
                                    </Badge>
                                )}
                                {canManage && member.role !== "owner" && (
                                    <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive hover:text-destructive" onClick={() => handleRemove(member.user_id)}>
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                )}
                            </div>
                        </div>
                    ))}
                    {members.length === 0 && (
                        <p className="text-sm text-muted-foreground text-center py-8">No members found.</p>
                    )}
                </div>
            </CardContent>
        </Card>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import type { OrgMemory } from "../types"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { Switch } from "@/components/ui/switch"
import { toast } from "sonner"
import {
    Users,
    Trash2,
    X,
    Brain,
    Search,
    RefreshCw,
    Filter,
    ChevronLeft,
    ChevronRight,
    Pin,
    PinOff,
    Edit3,
    Save,
} from "lucide-react"

export default function MemoryTab({ canManage }: { canManage: boolean }) {
    const [orgMemoryEnabled, setOrgMemoryEnabled] = useState(true)
    const [loadingToggle, setLoadingToggle] = useState(true)
    const [togglingMemory, setTogglingMemory] = useState(false)
    const [memories, setMemories] = useState<OrgMemory[]>([])
    const [loading, setLoading] = useState(true)
    const [search, setSearch] = useState("")
    const [filterType, setFilterType] = useState("all")
    const [sortBy, setSortBy] = useState("created_at")
    const [page, setPage] = useState(1)
    const [totalPages, setTotalPages] = useState(1)
    const [total, setTotal] = useState(0)
    const [orgStats, setOrgStats] = useState<{ totalActive: number; totalPinned: number; uniqueUsers: number } | null>(null)
    const [editingId, setEditingId] = useState<string | null>(null)
    const [editContent, setEditContent] = useState("")

    // Fetch org-level toggle state
    useEffect(() => {
        fetch('/api/memory/toggle/org')
            .then(r => r.json())
            .then(data => {
                setOrgMemoryEnabled(data.enabled ?? true)
                setLoadingToggle(false)
            })
            .catch(() => setLoadingToggle(false))
    }, [])

    // Toggle org-level memory
    const handleOrgToggle = async (enabled: boolean) => {
        setTogglingMemory(true)
        try {
            const res = await fetch('/api/memory/toggle/org', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ enabled }),
            })
            const data = await res.json()
            if (data.success) {
                setOrgMemoryEnabled(enabled)
                toast.success(data.message)
            } else {
                toast.error(data.error?.message || "Failed to update")
            }
        } catch {
            toast.error("Failed to update setting")
        } finally {
            setTogglingMemory(false)
        }
    }

    // Fetch org memories
    const fetchMemories = useCallback(async () => {
        setLoading(true)
        try {
            const params = new URLSearchParams({
                page: String(page),
                limit: "20",
                sortBy,
                order: "desc",
            })
            if (filterType !== "all") params.set("type", filterType)
            if (search.trim()) params.set("search", search.trim())

            const res = await fetch(`/api/memory/org?${params}`)
            const data = await res.json()
            setMemories(data.memories || [])
            setTotal(data.total || 0)
            setTotalPages(data.totalPages || 1)
            if (data.orgStats) setOrgStats(data.orgStats)
        } catch {
            toast.error("Failed to load organization memories")
        } finally {
            setLoading(false)
        }
    }, [page, filterType, sortBy, search])

    useEffect(() => {
        fetchMemories()
    }, [fetchMemories])

    // Pin/unpin
    const handlePin = async (mem: OrgMemory) => {
        try {
            await fetch(`/api/memory/${mem.id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ is_pinned: !mem.is_pinned }),
            })
            setMemories(prev => prev.map(m =>
                m.id === mem.id ? { ...m, is_pinned: !m.is_pinned } : m
            ))
            toast.success(mem.is_pinned ? "Unpinned" : "Pinned")
        } catch {
            toast.error("Failed to update")
        }
    }

    // Delete
    const handleDelete = async (id: string) => {
        if (!confirm("Delete this memory? This action cannot be undone.")) return
        try {
            await fetch(`/api/memory/${id}`, { method: "DELETE" })
            setMemories(prev => prev.filter(m => m.id !== id))
            setTotal(prev => prev - 1)
            toast.success("Memory deleted")
        } catch {
            toast.error("Failed to delete")
        }
    }

    // Save edit
    const handleSave = async (id: string) => {
        try {
            const res = await fetch(`/api/memory/${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ content: editContent }),
            })
            const data = await res.json()
            if (data.memory) {
                setMemories(prev => prev.map(m => m.id === id ? { ...m, ...data.memory } : m))
                toast.success("Memory updated")
            }
        } catch {
            toast.error("Failed to update")
        } finally {
            setEditingId(null)
        }
    }

    const MEMORY_TYPE_OPTIONS = [
        { value: "fact", label: "Fact" },
        { value: "decision", label: "Decision" },
        { value: "risk", label: "Risk" },
        { value: "obligation", label: "Obligation" },
        { value: "insight", label: "Insight" },
        { value: "preference", label: "Preference" },
        { value: "argument", label: "Argument" },
        { value: "outcome", label: "Outcome" },
        { value: "procedure", label: "Procedure" },
        { value: "pattern", label: "Pattern" },
        { value: "correction", label: "Correction" },
    ]

    return (
        <div className="space-y-6">
            {/* Org-Level Toggle */}
            <Card>
                <CardHeader className="pb-3">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Brain className="h-5 w-5 text-primary" />
                            <div>
                                <CardTitle className="text-base">Organization Memory Control</CardTitle>
                                <CardDescription className="text-sm mt-0.5">
                                    {orgMemoryEnabled
                                        ? "AI memory is enabled for all users in this organization."
                                        : "AI memory is disabled organization-wide. No users can create new memories."}
                                </CardDescription>
                            </div>
                        </div>
                        {canManage && (
                            <Switch
                                checked={orgMemoryEnabled}
                                onCheckedChange={handleOrgToggle}
                                disabled={togglingMemory || loadingToggle}
                            />
                        )}
                    </div>
                </CardHeader>
                {!orgMemoryEnabled && (
                    <CardContent className="pt-0">
                        <div className="bg-red-500/5 border border-red-500/20 rounded-lg p-3 text-xs text-red-600 dark:text-red-400">
                            <strong>Warning:</strong> When disabled, no user in this organization can create new memories or enable their personal memory toggle.
                            Existing memories are preserved and remain accessible.
                        </div>
                    </CardContent>
                )}
            </Card>

            {/* Org Stats */}
            {orgStats && (
                <div className="grid grid-cols-3 gap-3">
                    <Card className="bg-gradient-to-br from-primary/5 to-primary/10 border-primary/10">
                        <CardContent className="pt-4 pb-3 px-4">
                            <span className="text-xs text-muted-foreground uppercase tracking-wide">Active Memories</span>
                            <p className="text-2xl font-bold mt-1">{orgStats.totalActive}</p>
                        </CardContent>
                    </Card>
                    <Card className="bg-gradient-to-br from-amber-500/5 to-amber-500/10 border-amber-500/10">
                        <CardContent className="pt-4 pb-3 px-4">
                            <span className="text-xs text-muted-foreground uppercase tracking-wide">Pinned</span>
                            <p className="text-2xl font-bold mt-1">{orgStats.totalPinned}</p>
                        </CardContent>
                    </Card>
                    <Card className="bg-gradient-to-br from-emerald-500/5 to-emerald-500/10 border-emerald-500/10">
                        <CardContent className="pt-4 pb-3 px-4">
                            <span className="text-xs text-muted-foreground uppercase tracking-wide">Users</span>
                            <p className="text-2xl font-bold mt-1">{orgStats.uniqueUsers}</p>
                        </CardContent>
                    </Card>
                </div>
            )}

            {/* Search & Filters */}
            <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center justify-between">
                <div className="flex items-center gap-2 flex-1 min-w-0 w-full sm:w-auto">
                    <div className="relative flex-1 min-w-0">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Search all memories across users..."
                            value={search}
                            onChange={(e) => { setSearch(e.target.value); setPage(1) }}
                            className="pl-9"
                        />
                    </div>
                    <Select value={filterType} onValueChange={(v) => { setFilterType(v); setPage(1) }}>
                        <SelectTrigger className="w-[140px]">
                            <Filter className="h-3.5 w-3.5 mr-1.5 text-muted-foreground" />
                            <SelectValue placeholder="All types" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All types</SelectItem>
                            {MEMORY_TYPE_OPTIONS.map(t => (
                                <SelectItem key={t.value} value={t.value}>{t.label}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>
                </div>
                <div className="flex items-center gap-2">
                    <Select value={sortBy} onValueChange={setSortBy}>
                        <SelectTrigger className="w-[130px]">
                            <SelectValue placeholder="Sort by" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="created_at">Date</SelectItem>
                            <SelectItem value="importance">Importance</SelectItem>
                            <SelectItem value="confidence">Confidence</SelectItem>
                        </SelectContent>
                    </Select>
                    <Button variant="ghost" size="icon" onClick={fetchMemories} className="h-9 w-9">
                        <RefreshCw className="h-4 w-4" />
                    </Button>
                </div>
            </div>

            {/* Memory List */}
            {loading ? (
                <div className="space-y-3">
                    {[1, 2, 3].map(i => (
                        <Card key={i} className="animate-pulse">
                            <CardContent className="py-4">
                                <div className="h-4 bg-muted rounded w-3/4 mb-2" />
                                <div className="h-3 bg-muted rounded w-1/2" />
                            </CardContent>
                        </Card>
                    ))}
                </div>
            ) : memories.length === 0 ? (
                <Card className="border-dashed">
                    <CardContent className="py-12 text-center">
                        <Brain className="h-10 w-10 text-muted-foreground/40 mx-auto mb-3" />
                        <p className="text-muted-foreground font-medium">No memories found</p>
                        <p className="text-sm text-muted-foreground/70 mt-1">
                            {orgMemoryEnabled
                                ? "No memories have been created by users in this organization yet."
                                : "Memory is disabled for this organization."}
                        </p>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-2">
                    {memories.map(mem => (
                        <Card
                            key={mem.id}
                            className={`group transition-all hover:shadow-sm ${
                                mem.is_pinned ? 'border-primary/30 bg-primary/[0.02]' : ''
                            }`}
                        >
                            <CardContent className="py-3 px-4">
                                <div className="flex items-start gap-3">
                                    {/* User avatar */}
                                    <div className="shrink-0">
                                        {mem.user_profile_image ? (
                                            <div className="h-8 w-8 rounded-full overflow-hidden border">
                                                {/* eslint-disable-next-line @next/next/no-img-element */}
                                                <img src={mem.user_profile_image} alt={mem.user_name || ''} className="h-full w-full object-cover" />
                                            </div>
                                        ) : (
                                            <div className="h-8 w-8 rounded-full bg-muted flex items-center justify-center text-xs font-medium border border-primary/10 text-primary">
                                                {(mem.user_name || 'U').substring(0, 2).toUpperCase()}
                                            </div>
                                        )}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0">
                                        {editingId === mem.id ? (
                                            <div className="space-y-2">
                                                <Textarea
                                                    value={editContent}
                                                    onChange={e => setEditContent(e.target.value)}
                                                    rows={3}
                                                    className="text-sm"
                                                />
                                                <div className="flex gap-2">
                                                    <Button size="sm" variant="default" onClick={() => handleSave(mem.id)} className="gap-1 h-7 text-xs">
                                                        <Save className="h-3 w-3" /> Save
                                                    </Button>
                                                    <Button size="sm" variant="ghost" onClick={() => setEditingId(null)} className="gap-1 h-7 text-xs">
                                                        <X className="h-3 w-3" /> Cancel
                                                    </Button>
                                                </div>
                                            </div>
                                        ) : (
                                            <p className="text-sm leading-relaxed">{mem.content}</p>
                                        )}

                                        {/* Meta row */}
                                        <div className="flex items-center gap-2 mt-2 flex-wrap">
                                            <Badge variant="outline" className="text-[10px] px-1.5 py-0 h-5 font-medium">
                                                {mem.memory_type}
                                            </Badge>
                                            <span className="text-[10px] text-muted-foreground/60">by</span>
                                            <span className="text-[10px] font-medium text-foreground/80">
                                                {mem.user_name || 'Unnamed User'}
                                            </span>
                                            <span className="text-[10px] text-muted-foreground/60">•</span>
                                            <span className="text-[10px] text-muted-foreground/60 capitalize">{mem.source}</span>
                                            <span className="text-[10px] text-muted-foreground/60">•</span>
                                            <span className="text-[10px] text-muted-foreground/60">
                                                {new Date(mem.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                                            </span>
                                            {mem.is_pinned && (
                                                <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-5 gap-0.5">
                                                    <Pin className="h-2.5 w-2.5" /> Pinned
                                                </Badge>
                                            )}
                                        </div>
                                    </div>

                                    {/* Admin Actions */}
                                    {canManage && (
                                        <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity shrink-0">
                                            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => handlePin(mem)}>
                                                {mem.is_pinned
                                                    ? <PinOff className="h-3.5 w-3.5 text-primary" />
                                                    : <Pin className="h-3.5 w-3.5" />}
                                            </Button>
                                            <Button variant="ghost" size="icon" className="h-7 w-7"
                                                onClick={() => { setEditingId(mem.id); setEditContent(mem.content) }}>
                                                <Edit3 className="h-3.5 w-3.5" />
                                            </Button>
                                            <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive"
                                                onClick={() => handleDelete(mem.id)}>
                                                <Trash2 className="h-3.5 w-3.5" />
                                            </Button>
                                        </div>
                                    )}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}

            {/* Pagination */}
            {totalPages > 1 && (
                <div className="flex items-center justify-between pt-2">
                    <p className="text-xs text-muted-foreground">
                        {total} memor{total === 1 ? 'y' : 'ies'} total
                    </p>
                    <div className="flex items-center gap-2">
                        <Button variant="ghost" size="sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)} className="h-8">
                            <ChevronLeft className="h-4 w-4" />
                        </Button>
                        <span className="text-sm text-muted-foreground">{page} / {totalPages}</span>
                        <Button variant="ghost" size="sm" disabled={page >= totalPages} onClick={() => setPage(p => p + 1)} className="h-8">
                            <ChevronRight className="h-4 w-4" />
                        </Button>
                    </div>
                </div>
            )}
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { createPortal } from "react-dom"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Button } from "@/components/ui/button"
import { Textarea } from "@/components/ui/textarea"
import { toast } from "sonner"
import {
    Users,
    Key,
    Loader2,
    X,
    Save,
} from "lucide-react"

// =====================================================================

export default function SsoTab({ canManage }: { canManage: boolean }) {
    const [domain, setDomain] = useState("")
    const [signInUrl, setSignInUrl] = useState("")
    const [cert, setCert] = useState("")
    const [loading, setLoading] = useState(false)
    const [checking, setChecking] = useState(false)
    const [status, setStatus] = useState<"none" | "active">("none")
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false)

    const handleCheck = async () => {
        if (!domain) return
        setChecking(true)
        try {
            const res = await fetch(`/api/org/sso?domain=${domain}`)
            const data = await res.json()
            if (data.exists && data.connection) {
                setStatus("active")
                setSignInUrl(data.connection.options?.signInEndpoint || "")
                setCert(data.connection.options?.signingCert || "")
            } else {
                toast.error("No SSO configuration found for this domain.")
                setStatus("none")
                setSignInUrl("")
                setCert("")
            }
        } catch (err) {
            toast.error(`Failed to check SSO status: ${err instanceof Error ? err.message : 'Unknown error'}`)
        } finally {
            setChecking(false)
        }
    }

    const handleSave = async () => {
        setLoading(true)
        try {
            const res = await fetch("/api/org/sso", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ domain, signInEndpoint: signInUrl, cert })
            })
            const data = await res.json()
            if (data.success) {
                toast.success("SSO Configuration Applied")
                setStatus("active")
            } else {
                toast.error(data.error?.message || data.detail || "Failed to save SSO config")
            }
        } catch {
            toast.error("An error occurred")
        } finally {
            setLoading(false)
        }
    }

    const handleDelete = async () => {
        setLoading(true)
        try {
            const res = await fetch(`/api/org/sso?domain=${domain}`, { method: "DELETE" })
            const data = await res.json()
            if (data.success) {
                toast.success("SSO Configuration Removed")
                setStatus("none")
                setSignInUrl("")
                setCert("")
                setShowDeleteConfirm(false)
            }
        } catch {
            toast.error("An error occurred")
        } finally {
            setLoading(false)
        }
    }

    return (
        <>
            <Card>
            <CardHeader>
                <CardTitle className="flex items-center gap-2">
                    <Key className="h-5 w-5 text-primary" /> Single Sign-On (SAML)
                </CardTitle>
                <CardDescription>Configure Enterprise SSO via Okta, Azure AD, or any SAML 2.0 Identity Provider. When active, members logging in with this domain will instantly be redirected to your secure portal.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
                <div className="space-y-4">
                    <div className="space-y-2">
                        <Label>Email Domain</Label>
                        <div className="flex gap-2">
                            <Input 
                                placeholder="lawfirm.com" 
                                value={domain} 
                                onChange={e => {
                                    setDomain(e.target.value.toLowerCase().trim())
                                    setStatus("none")
                                }} 
                            />
                            <Button variant="secondary" onClick={handleCheck} disabled={checking || !domain}>
                                {checking ? "Checking..." : "Load Domain"}
                            </Button>
                        </div>
                        <p className="text-xs text-muted-foreground">The domain used to route users to your Identity Provider. Avoid prefixes like @.</p>
                    </div>

                    {status === "active" && (
                        <div className="rounded-md bg-emerald-500/10 p-3 border border-emerald-500/20 text-emerald-600 dark:text-emerald-400 text-sm flex items-center gap-2 font-medium">
                            <Key className="h-4 w-4" /> SSO is Active for this Domain
                        </div>
                    )}

                    <div className="space-y-2 pt-4 border-t">
                        <Label>IdP Sign-In URL</Label>
                        <Input 
                            placeholder="https://company.okta.com/app/.../sso/saml" 
                            value={signInUrl} 
                            onChange={e => setSignInUrl(e.target.value)} 
                            disabled={!canManage}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label>X.509 Public Certificate</Label>
                        <Textarea 
                            placeholder="-----BEGIN CERTIFICATE-----\nMIIDpDCCAoyg...\n-----END CERTIFICATE-----" 
                            value={cert} 
                            onChange={e => setCert(e.target.value)} 
                            disabled={!canManage}
                            className="font-mono text-xs min-h-[150px]"
                        />
                    </div>

                    {canManage && (
                        <div className="flex justify-between pt-4 border-t">
                            {status === "active" ? (
                                <Button variant="destructive" onClick={() => setShowDeleteConfirm(true)} disabled={loading}>Disable & Delete</Button>
                            ) : <div></div>}
                            <Button onClick={handleSave} disabled={loading || !domain || !signInUrl || !cert}>
                                {loading ? "Saving..." : "Save Configuration"}
                            </Button>
                        </div>
                    )}
                </div>
            </CardContent>
            </Card>
            {showDeleteConfirm && typeof window !== 'undefined' && createPortal(
                <div className="fixed inset-0 z-[100] flex items-center justify-center">
                    {/* Overlay */}
                    <div
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200"
                        onClick={() => { if (!loading) setShowDeleteConfirm(false) }}
                    />
                    {/* Dialog */}
                    <div className="relative z-[100] w-full max-w-md mx-4 bg-white dark:bg-zinc-900 rounded-xl border border-border/60 shadow-2xl p-6 animate-in fade-in-0 zoom-in-95 duration-200">
                        <div className="space-y-2">
                            <h2 className="text-lg font-semibold text-foreground">Disable SSO connection?</h2>
                            <p className="text-sm text-muted-foreground">
                                This will instantly sever the SAML connection for <strong>{domain}</strong>. Users will immediately fall back to standard password login. This action cannot be undone.
                            </p>
                        </div>
                        <div className="flex justify-end gap-3 mt-6">
                            <Button
                                variant="outline"
                                onClick={() => setShowDeleteConfirm(false)}
                                disabled={loading}
                                className="rounded-lg"
                            >
                                Cancel
                            </Button>
                            <Button
                                onClick={handleDelete}
                                disabled={loading}
                                className="rounded-lg bg-red-600 text-white hover:bg-red-700 dark:bg-red-600 dark:hover:bg-red-700 block text-center"
                            >
                                {loading ? (
                                    <span className="flex items-center"><Loader2 className="h-4 w-4 animate-spin mr-2" /> Disabling...</span>
                                ) : (
                                    'Disable SSO'
                                )}
                            </Button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </>
    )
}

"use client"

import * as React from "react"
