}

type TabType = "all" | "assistant" | "vault" | "workflow"

export default function RecentChatsPage() {
    const router = useRouter()
    const { projects, decrementQueryCount } = useDocuments() // Use global vault context
    const [activeTab, setActiveTab] = React.useState<TabType>("all")
    const [conversations, setConversations] = React.useState<Conversation[]>([])
    // Removed local projects state
    const [workflows, setWorkflows] = React.useState<WorkflowDef[]>([])
    const [isLoading, setIsLoading] = React.useState(true)

    // Sub-filters
    const [selectedProject, setSelectedProject] = React.useState<string>("all")
    const [selectedWorkflow, setSelectedWorkflow] = React.useState<string>("all")

    // Delete confirmation
    const [deleteTarget, setDeleteTarget] = React.useState<Conversation | null>(null)
    const [isDeleting, setIsDeleting] = React.useState(false)

    // Rename
    const [renamingId, setRenamingId] = React.useState<string | null>(null)
    const [renameValue, setRenameValue] = React.useState('')

    React.useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true)
            try {
                const [convsRes, workflowsRes] = await Promise.all([
                    fetch('/api/chat/conversations?limit=100'),
                    // projects are fetched via context
                    fetch('/api/templates/list')
                ])

                if (convsRes.ok) {
                    setConversations(await convsRes.json())
                } else {
                    const errBody = await convsRes.text()
                    toast.error(`Failed to load conversations (${convsRes.status})`)
                }
                if (workflowsRes.ok) {
                    setWorkflows(await workflowsRes.json())
                } else {
                }
            } catch (error) {
                toast.error('Failed to load recent chats data')
            } finally {
                setIsLoading(false)
            }
        }
        fetchData()
    }, [])

    const handleDelete = async () => {
        if (!deleteTarget) return
        setIsDeleting(true)
        try {
            const res = await fetch(`/api/chat/conversations/${deleteTarget.id}`, { method: 'DELETE' })
            if (res.ok) {
                setConversations(prev => prev.filter(c => c.id !== deleteTarget.id))

                // Live update of query count if it's a vault project conversation
                if (deleteTarget.projectId) {
                    decrementQueryCount(deleteTarget.projectId)
                }

                toast.success('Conversation deleted')
            } else {
                toast.error('Failed to delete conversation')
            }
        } catch {
            toast.error('Failed to delete conversation')
        } finally {
            setIsDeleting(false)
            setDeleteTarget(null)
        }
    }

    const handlePin = async (conv: Conversation) => {
        const res = await fetch(`/api/chat/conversations/${conv.id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ pinned: !conv.pinned })
        })
        if (res.ok) {
            setConversations(prev => {
                const updated = prev.map(c => c.id === conv.id ? { ...c, pinned: !c.pinned } : c)
                return updated.sort((a, b) => {
                    if (a.pinned && !b.pinned) return -1
                    if (!a.pinned && b.pinned) return 1
                    return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime()
                })
            })
            toast.success(conv.pinned ? 'Unpinned' : 'Pinned')
        }
    }

    const handleRename = async (conv: Conversation) => {
        const res = await fetch(`/api/chat/conversations/${conv.id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title: renameValue })
        })
        if (res.ok) {
            setConversations(prev => prev.map(c => c.id === conv.id ? { ...c, title: renameValue } : c))
            toast.success('Renamed')
        }
        setRenamingId(null)
    }

    // Helper to check type across both old ('documents','templates') and new ('vault','workflow') names
    const isVaultType = (type: string) => type === 'vault' || type === 'documents'
    const isWorkflowType = (type: string) => type === 'workflow' || type === 'templates'

    // Filtered conversations
    const filteredConversations = React.useMemo(() => {
        let filtered = conversations
        if (activeTab === "assistant") {
            filtered = conversations.filter(c => c.type === 'assistant')
        } else if (activeTab === "vault") {
            filtered = conversations.filter(c => isVaultType(c.type))
            if (selectedProject !== "all") {
                filtered = filtered.filter(c => c.projectId === selectedProject)
            }
        } else if (activeTab === "workflow") {
            filtered = conversations.filter(c => isWorkflowType(c.type))
            if (selectedWorkflow !== "all") {
                filtered = filtered.filter(c => c.workflowId === selectedWorkflow)
            }
        }
        return filtered
    }, [conversations, activeTab, selectedProject, selectedWorkflow])

    const pinnedConvs = filteredConversations.filter(c => c.pinned)
    const unpinnedConvs = filteredConversations.filter(c => !c.pinned)

    const projectsWithConversations = React.useMemo(() => {
        const ids = new Set(conversations.filter(c => isVaultType(c.type)).map(c => c.projectId))
        return projects.filter((p: Project) => ids.has(p.id))
    }, [conversations, projects])

    const workflowsWithConversations = React.useMemo(() => {
        const ids = new Set(conversations.filter(c => isWorkflowType(c.type)).map(c => c.workflowId))
        return workflows.filter(w => ids.has(w.id))
    }, [conversations, workflows])

    // Stats
    const stats = React.useMemo(() => ({
        total: conversations.length,
        assistant: conversations.filter(c => c.type === 'assistant').length,
        vault: conversations.filter(c => isVaultType(c.type)).length,
        workflow: conversations.filter(c => isWorkflowType(c.type)).length,
    }), [conversations])

    const getTypeIcon = (type: string) => {
        if (type === 'assistant') return <Sparkles className="h-4 w-4" />
        if (isVaultType(type)) return <Folder className="h-4 w-4" />
        if (isWorkflowType(type)) return <Workflow className="h-4 w-4" />
        return <MessageSquare className="h-4 w-4" />
    }

    const getTypeBadge = (type: string) => {
        const variants: Record<string, string> = {
            assistant: 'bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-500/20',
            vault: 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/20',
            documents: 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/20',
            workflow: 'bg-purple-500/10 text-purple-600 dark:text-purple-400 border-purple-500/20',
            templates: 'bg-purple-500/10 text-purple-600 dark:text-purple-400 border-purple-500/20',
        }
        const labels: Record<string, string> = {
            assistant: 'Chat', vault: 'Documents', documents: 'Documents', workflow: 'Templates', templates: 'Templates'
        }
        return (
            <span className={`inline-flex items-center gap-1 text-[11px] font-medium px-2 py-0.5 rounded-full border ${variants[type] || ''}`}>
                {getTypeIcon(type)}
                {labels[type] || type}
            </span>
        )
    }

    const ConversationRow = ({ conv }: { conv: Conversation }) => {
        const project = projects.find((p: Project) => p.id === conv.projectId)
        const workflow = workflows.find(w => w.id === conv.workflowId)
        const isRenaming = renamingId === conv.id

        return (
            <div
                className="group flex items-center gap-4 px-4 py-3 rounded-xl hover:bg-muted/60 cursor-pointer transition-all duration-200 border border-transparent hover:border-border/50"
                onClick={() => {
                    if (isRenaming) return
                    if (conv.projectId) {
                        router.push(`/documents/${conv.projectId}/chat/${conv.id}`)
                    } else if (conv.workflowId) {
                        router.push(`/templates/${conv.workflowId}/chat/${conv.id}`)
                    } else {
                        router.push(`/chat/${conv.id}`)
                    }
                }}
            >
                {/* Icon */}
                <div className={`flex-shrink-0 w-10 h-10 rounded-lg flex items-center justify-center ${conv.type === 'assistant' ? 'bg-blue-500/10 text-blue-600 dark:text-blue-400' :
                    isVaultType(conv.type) ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' :
                        'bg-purple-500/10 text-purple-600 dark:text-purple-400'
                    }`}>
                    {getTypeIcon(conv.type)}
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                    {isRenaming ? (
                        <div className="flex items-center gap-1.5">
                            <Input
                                value={renameValue}
                                onChange={(e) => setRenameValue(e.target.value)}
                                className="h-8 text-sm"
                                autoFocus
                                onClick={(e) => e.stopPropagation()}
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter') { e.stopPropagation(); handleRename(conv) }
                                    if (e.key === 'Escape') setRenamingId(null)
                                }}
                            />
                            <Button variant="ghost" size="icon" className="h-8 w-8 shrink-0" onClick={(e) => { e.stopPropagation(); handleRename(conv) }}>
                                <Check className="h-4 w-4" />
                            </Button>
                            <Button variant="ghost" size="icon" className="h-8 w-8 shrink-0" onClick={(e) => { e.stopPropagation(); setRenamingId(null) }}>
                                <X className="h-4 w-4" />
                            </Button>
                        </div>
                    ) : (
                        <>
                            <div className="flex items-center gap-2">
                                <span className="font-medium text-sm truncate flex items-center gap-1.5">
                                    {conv.pinned && <Pin className="h-3.5 w-3.5 text-primary shrink-0" />}
                                    {conv.title || 'New Conversation'}
                                </span>
                                {activeTab === 'all' && getTypeBadge(conv.type)}
                            </div>
                            <div className="flex items-center gap-2 mt-0.5">
                                {isVaultType(conv.type) && project && (
                                    <span className="text-xs text-muted-foreground truncate">{project.title}</span>
                                )}
                                {isWorkflowType(conv.type) && workflow && (
                                    <span className="text-xs text-muted-foreground truncate">{workflow.title}</span>
                                )}
                                {((isVaultType(conv.type) && project) || (isWorkflowType(conv.type) && workflow)) && (
                                    <span className="text-muted-foreground/40">•</span>
                                )}
                                <span className="text-xs text-muted-foreground flex items-center gap-1">
                                    <Clock className="h-3 w-3" />
                                    {formatDistanceToNow(new Date(conv.updatedAt), { addSuffix: true })}
                                </span>
                                {conv.messageCount && conv.messageCount > 0 && (
                                    <>
                                        <span className="text-muted-foreground/40">•</span>
                                        <span className="text-xs text-muted-foreground">
                                            {conv.messageCount} message{conv.messageCount !== 1 ? 's' : ''}
                                        </span>
                                    </>
                                )}
                            </div>
                        </>
                    )}
                </div>

                {/* Actions */}
                {!isRenaming && (
                    <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Button
                            variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-primary"
                            title={conv.pinned ? 'Unpin' : 'Pin'}
                            onClick={(e) => { e.stopPropagation(); handlePin(conv) }}
                        >
                            {conv.pinned ? <PinOff className="h-4 w-4" /> : <Pin className="h-4 w-4" />}
                        </Button>
                        <Button
                            variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-foreground"
                            title="Rename"
                            onClick={(e) => {
                                e.stopPropagation()
                                setRenamingId(conv.id)
                                setRenameValue(conv.title || '')
                            }}
                        >
                            <Pencil className="h-4 w-4" />
                        </Button>
                        <Button
                            variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-foreground"
                            title="Open"
                            onClick={(e) => {
                                e.stopPropagation()
                                if (conv.projectId) {
                                    router.push(`/documents/${conv.projectId}/chat/${conv.id}`)
                                } else if (conv.workflowId) {
                                    router.push(`/templates/${conv.workflowId}/chat/${conv.id}`)
                                } else {
                                    router.push(`/chat/${conv.id}`)
                                }
                            }}
                        >
                            <ArrowRight className="h-4 w-4" />
                        </Button>
                        <Button
                            variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground hover:text-destructive"
                            title="Delete"
                            onClick={(e) => { e.stopPropagation(); setDeleteTarget(conv) }}
                        >
                            <Trash2 className="h-4 w-4" />
                        </Button>
                    </div>
                )}
            </div>
        )
    }

    const EmptyState = () => (
        <div className="flex flex-col items-center justify-center py-24 text-center space-y-4">
            <div className="p-5 rounded-2xl bg-gradient-to-br from-muted/80 to-muted/30 border border-border/50">
                <MessageSquare className="h-10 w-10 text-muted-foreground/40" />
            </div>
            <div className="space-y-1">
                <h3 className="font-semibold text-lg">No conversations yet</h3>
                <p className="text-muted-foreground text-sm max-w-sm">
                    Start chatting with the AI assistant to see your recent chats here.
                </p>
            </div>
        </div>
    )

    return (
        <div className="flex flex-col flex-1 h-full bg-background overflow-hidden">
            <HistoryHeader />

            <div className="flex-1 overflow-y-auto scrollbar-none sm:scrollbar-thin scrollbar-thumb-muted-foreground/20 scrollbar-track-transparent">
                <div className="max-w-5xl mx-auto w-full px-4 sm:px-8 py-6 sm:py-8 space-y-8">
                    {/* Stats bar */}
                    {!isLoading && conversations.length > 0 && (
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                            {[
                                { label: 'Total', value: stats.total, color: 'from-slate-500/10 to-transparent border-slate-500/20' },
                                { label: 'Assistant', value: stats.assistant, color: 'from-blue-500/10 to-transparent border-blue-500/20' },
                                { label: 'Documents', value: stats.vault, color: 'from-emerald-500/10 to-transparent border-emerald-500/20' },
                                { label: 'Templates', value: stats.workflow, color: 'from-purple-500/10 to-transparent border-purple-500/20' },
                            ].map((stat) => (
                                <div key={stat.label} className={`rounded-2xl bg-gradient-to-br ${stat.color} border px-6 py-4 shadow-sm transition-all hover:shadow-md`}>
                                    <div className="text-3xl font-bold tracking-tight">{stat.value}</div>
                                    <div className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest mt-1">{stat.label}</div>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Content Area */}
                    <div className="space-y-6">
                        {/* Tabs + Filters */}
                        <div className="space-y-4">
                            <Tabs value={activeTab} className="w-full" onValueChange={(v) => setActiveTab(v as TabType)}>
                                <TabsList className="grid w-full grid-cols-2 h-auto sm:grid-cols-4 sm:h-12 gap-1 bg-muted/20 p-1 rounded-xl border border-border/50">
                                    <TabsTrigger value="all" className="rounded-lg text-sm data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all h-full">All</TabsTrigger>
                                    <TabsTrigger value="assistant" className="rounded-lg text-sm data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all h-full">Assistant</TabsTrigger>
                                    <TabsTrigger value="vault" className="rounded-lg text-sm data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all h-full">Documents</TabsTrigger>
                                    <TabsTrigger value="workflow" className="rounded-lg text-sm data-[state=active]:bg-background data-[state=active]:shadow-sm transition-all h-full">Templates</TabsTrigger>
                                </TabsList>
                            </Tabs>

                            <div className="flex flex-wrap gap-4">
                                {activeTab === "vault" && projectsWithConversations.length > 0 && (
                                    <Select value={selectedProject} onValueChange={setSelectedProject}>
                                        <SelectTrigger className="w-full sm:w-[240px] rounded-xl h-10 shadow-sm border-border/60 bg-muted/5">
                                            <SelectValue placeholder="Filter by project" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Projects</SelectItem>
                                            {projectsWithConversations.map((p: Project) => (
                                                <SelectItem key={p.id} value={p.id}>
                                                    <div className="flex items-center gap-2">
                                                        <Folder className="h-3.5 w-3.5" />
                                                        {p.title}
                                                    </div>
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                )}

                                {activeTab === "workflow" && workflowsWithConversations.length > 0 && (
                                    <Select value={selectedWorkflow} onValueChange={setSelectedWorkflow}>
                                        <SelectTrigger className="w-full sm:w-[240px] rounded-xl h-10 shadow-sm border-border/60 bg-muted/5">
                                            <SelectValue placeholder="Filter by workflow" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Templates</SelectItem>
                                            {workflowsWithConversations.map(w => (
                                                <SelectItem key={w.id} value={w.id}>
                                                    <div className="flex items-center gap-2">
                                                        <Workflow className="h-3.5 w-3.5" />
                                                        {w.title}
                                                    </div>
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                )}
                            </div>
                        </div>

                        {/* Conversation list */}
                        <div className="pb-24">
                            {isLoading ? (
                                <div className="flex items-center justify-center py-24">
                                    <div className="flex flex-col items-center gap-3">
                                        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground/30" />
                                        <span className="text-sm text-muted-foreground/60">Loading recent chats...</span>
                                    </div>
                                </div>
                            ) : filteredConversations.length === 0 ? (
                                <EmptyState />
                            ) : (
                                <div className="space-y-1">
                                    {/* Pinned section */}
                                    {pinnedConvs.length > 0 && (
                                        <>
                                            <div className="flex items-center gap-2 px-4 py-3 text-[11px] font-bold text-muted-foreground/60 uppercase tracking-widest">
                                                <Pin className="h-3 w-3" /> Pinned
                                            </div>
                                            {pinnedConvs.map(conv => (
                                                <ConversationRow key={conv.id} conv={conv} />
                                            ))}
                                            {unpinnedConvs.length > 0 && (
                                                <div className="px-4 py-4 text-[11px] font-bold text-muted-foreground/60 uppercase tracking-widest mt-4">
                                                    Recent
                                                </div>
                                            )}
                                        </>
                                    )}
                                    {/* Unpinned section */}
                                    {unpinnedConvs.map(conv => (
                                        <ConversationRow key={conv.id} conv={conv} />
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Delete Confirmation Dialog - Portal to body for proper centering */}
            {!!deleteTarget && createPortal(
                <div className="fixed inset-0 z-50 flex items-center justify-center">
                    {/* Overlay */}
                    <div
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200"
                        onClick={() => { if (!isDeleting) setDeleteTarget(null) }}
                    />
                    {/* Dialog */}
                    <div className="relative z-50 w-full max-w-md mx-4 bg-white dark:bg-zinc-900 rounded-xl border border-border/60 shadow-2xl p-6 animate-in fade-in-0 zoom-in-95 duration-200">
                        <div className="space-y-2">
                            <h2 className="text-lg font-semibold text-foreground">Delete conversation?</h2>
                            <p className="text-sm text-muted-foreground">
                                This will permanently delete &quot;{deleteTarget?.title || 'New Conversation'}&quot; and all its messages. This action cannot be undone.
                            </p>
                        </div>
                        <div className="flex justify-end gap-3 mt-6">
                            <Button
                                variant="outline"
                                onClick={() => setDeleteTarget(null)}
                                disabled={isDeleting}
                                className="rounded-lg"
                            >
                                Cancel
                            </Button>
                            <Button
                                onClick={handleDelete}
                                disabled={isDeleting}
                                className="rounded-lg bg-red-600 text-white hover:bg-red-700 dark:bg-red-600 dark:hover:bg-red-700"
                            >
                                {isDeleting ? (
                                    <><Loader2 className="h-4 w-4 animate-spin mr-2" /> Deleting...</>
                                ) : (
                                    'Delete'
                                )}
                            </Button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Activity, Server, AlertTriangle, Database, Loader2 } from "lucide-react"
import type { ActivityEntry, SystemHealth } from "../types"

// =====================================================================
// SYSTEM TAB
// =====================================================================

export default function SystemTab() {
    const [health, setHealth] = useState<SystemHealth | null>(null)
    const [activity, setActivity] = useState<ActivityEntry[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        Promise.all([
            fetch("/api/super-admin/system").then(r => r.json()),
            fetch("/api/super-admin/activity").then(r => r.json()),
        ]).then(([healthRes, activityRes]) => {
            if (healthRes.success) setHealth(healthRes.data)
            if (activityRes.success) setActivity(activityRes.data || [])
        }).finally(() => setLoading(false))
    }, [])

    if (loading) return <div className="flex justify-center py-16"><Loader2 className="h-5 w-5 animate-spin text-muted-foreground" /></div>

    return (
        <div className="space-y-6">
            {/* Database overview */}
            {health && (
                <div>
                    <h3 className="text-sm font-medium mb-3 flex items-center gap-2">
                        <Database className="h-4 w-4" /> Database Tables
                        <Badge variant="outline" className="text-[10px] ml-1">{health.totalTables || health.tableSizes.length} tables</Badge>
                        <Badge variant="outline" className="text-[10px]">{(health.totalRows || 0).toLocaleString()} rows</Badge>
                    </h3>
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2">
                        {health.tableSizes.map(t => (
                            <div key={t.table} className="p-3 rounded-lg border bg-muted/20">
                                <p className="text-[11px] text-muted-foreground font-mono truncate">{t.table}</p>
                                <p className="text-lg font-semibold tabular-nums">{t.count.toLocaleString()}</p>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Recent Errors */}
            {health && (
                <Card className="border-0 bg-muted/20">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium flex items-center gap-2">
                            <AlertTriangle className="h-4 w-4 text-red-500" /> Errors
                            <Badge variant="outline" className="ml-1 text-[10px]">{health.recentErrors.length}</Badge>
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        {health.recentErrors.length === 0 ? (
                            <div className="py-4 text-center">
                                <p className="text-xs text-emerald-600 font-medium">✓ No recent errors</p>
                            </div>
                        ) : (
                            <div className="space-y-1">
                                {health.recentErrors.map(err => (
                                    <div key={err.id} className="flex items-center justify-between py-2 px-2 rounded hover:bg-red-50 dark:hover:bg-red-950/20 transition-colors">
                                        <span className="text-xs font-medium text-red-600 dark:text-red-400">{err.event_type}</span>
                                        <span className="text-[10px] text-muted-foreground tabular-nums">{new Date(err.created_at).toLocaleString()}</span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>
            )}

            {/* System Logs */}
            <Card className="border-0 bg-muted/20">
                <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-medium flex items-center gap-2">
                        <Activity className="h-4 w-4" /> System Logs
                        <Badge variant="outline" className="ml-1 text-[10px]">{activity.length}</Badge>
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    {activity.length === 0 ? (
                        <p className="text-xs text-muted-foreground text-center py-6">No system logs yet.</p>
                    ) : (
                        <div className="max-h-80 overflow-y-auto space-y-0.5 pr-1">
                            {activity.map(entry => (
                                <div key={entry.id} className="flex items-center gap-3 py-1.5 px-2 rounded hover:bg-muted/40 transition-colors">
                                    <div className={`h-1.5 w-1.5 rounded-full shrink-0 ${entry.event_type.toLowerCase().includes("error") ? "bg-red-500" : "bg-emerald-500"}`} />
                                    <span className="text-xs font-medium flex-1 truncate">{entry.event_type}</span>
                                    <span className="text-[10px] text-muted-foreground tabular-nums shrink-0">
                                        {new Date(entry.created_at).toLocaleString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                </div>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Jobs */}
            {health && health.recentJobs.length > 0 && (
                <Card className="border-0 bg-muted/20">
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium flex items-center gap-2">
                            <Server className="h-4 w-4" /> Background Jobs
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-1">
                            {health.recentJobs.map(job => (
                                <div key={job.id} className="flex items-center justify-between py-2 px-2 rounded hover:bg-muted/40 transition-colors">
                                    <span className="text-xs font-medium">{String(job.job_type || job.type || "Unknown")}</span>
                                    <div className="flex items-center gap-2">
                                        <span className="text-[10px] text-muted-foreground tabular-nums">{new Date(job.created_at).toLocaleString()}</span>
                                        <Badge variant={
                                            job.status === "completed" ? "default" :
                                                job.status === "failed" ? "destructive" : "outline"
                                        } className="text-[10px]">{job.status || "unknown"}</Badge>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>
            )}
        </div>
    )
}

"use client"

import { useState, useEffect, useCallback } from "react"
import { createPortal } from "react-dom"
import { Input } from "@/components/ui/input"
import { Users, Search, Loader2, Plus, Trash2 } from "lucide-react"
import type { Org, PlatformUser } from "../types"

// =====================================================================
// USERS TAB
// =====================================================================

export default function UsersTab() {
    const [users, setUsers] = useState<PlatformUser[]>([])
    const [loading, setLoading] = useState(true)
    const [search, setSearch] = useState("")
    const [showCreate, setShowCreate] = useState(false)
    const [saving, setSaving] = useState(false)
    const [orgs, setOrgs] = useState<Org[]>([])

    // Create user form state
    const [formName, setFormName] = useState("")
    const [formEmail, setFormEmail] = useState("")
    const [formPassword, setFormPassword] = useState("")
    const [formOrgId, setFormOrgId] = useState("")
    const [formRole, setFormRole] = useState("member")
    const [formError, setFormError] = useState("")

    const fetchUsers = useCallback(async (s?: string) => {
        setLoading(true)
        try {
            const url = s ? `/api/super-admin/users?search=${encodeURIComponent(s)}` : "/api/super-admin/users"
            const res = await fetch(url)
            const data = await res.json()
            if (data.success) setUsers(data.data || [])
        } catch {
        } finally {
            setLoading(false)
        }
    }, [])

    const fetchOrgs = useCallback(async () => {
        try {
            const res = await fetch("/api/super-admin/organizations")
            const data = await res.json()
            if (data.success) setOrgs(data.data || [])
        } catch {
        }
    }, [])

    useEffect(() => { fetchUsers() }, [fetchUsers])

    const handleSearch = () => fetchUsers(search)

    const openCreate = () => {
        setFormName(""); setFormEmail(""); setFormPassword(""); setFormOrgId(""); setFormRole("member"); setFormError("")
        setShowCreate(true)
        fetchOrgs() // Load orgs for the dropdown
    }

    const handleCreate = async () => {
        setSaving(true); setFormError("")
        try {
            if (!formEmail.trim()) { setFormError("Email is required"); setSaving(false); return }
            if (!formPassword || formPassword.length < 8) { setFormError("Password must be at least 8 characters"); setSaving(false); return }

            const res = await fetch("/api/super-admin/users", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    email: formEmail.trim(),
                    name: formName.trim() || undefined,
                    password: formPassword,
                    org_id: formOrgId || undefined,
                    role: formRole,
                })
            })
            const data = await res.json()
            if (!data.success) { setFormError(data.error || "Failed to create user"); return }
            setShowCreate(false)
            fetchUsers()
        } catch { setFormError("Network error") } finally { setSaving(false) }
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-sm font-medium">Users</h2>
                    <p className="text-xs text-muted-foreground">{users.length} across all organizations</p>
                </div>
                <div className="flex items-center gap-2">
                    <div className="relative w-64">
                        <Search className="absolute left-2.5 top-2.5 h-3.5 w-3.5 text-muted-foreground" />
                        <Input
                            placeholder="Search…"
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            onKeyDown={e => e.key === "Enter" && handleSearch()}
                            className="pl-8 h-8 text-xs"
                        />
                    </div>
                    <button onClick={openCreate} className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-primary text-primary-foreground hover:bg-primary/90 transition-colors">
                        <Plus className="h-3.5 w-3.5" /> New User
                    </button>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-8"><Loader2 className="h-5 w-5 animate-spin text-muted-foreground" /></div>
            ) : (
                <div className="rounded-lg border overflow-hidden">
                    <table className="w-full text-xs">
                        <thead>
                            <tr className="bg-muted/50 border-b">
                                <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">User</th>
                                <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Organization</th>
                                <th className="text-center py-2.5 px-3 font-medium text-muted-foreground">Role</th>
                                <th className="text-right py-2.5 px-3 font-medium text-muted-foreground">Joined</th>
                                <th className="py-2.5 px-3 text-right font-medium text-muted-foreground">Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {users.map((user, idx) => (
                                <tr key={`${user.user_id}-${idx}`} className="border-b last:border-0 hover:bg-muted/20 transition-colors">
                                    <td className="py-2.5 px-3">
                                        <div className="flex items-center gap-2">
                                            {user.display_image ? (
                                                <div className="h-6 w-6 rounded-full overflow-hidden border shrink-0">
                                                    {/* eslint-disable-next-line @next/next/no-img-element */}
                                                    <img src={user.display_image} alt="" className="h-full w-full object-cover" />
                                                </div>
                                            ) : (
                                                <div className="h-6 w-6 rounded-full bg-muted flex items-center justify-center text-[10px] font-medium shrink-0 border">
                                                    {user.display_name.substring(0, 2).toUpperCase()}
                                                </div>
                                            )}
                                            <span className="font-medium">{user.display_name}</span>
                                        </div>
                                    </td>
                                    <td className="py-2.5 px-3 text-muted-foreground">{user.org_name}</td>
                                    <td className="py-2.5 px-3 text-center">
                                        <select
                                            title="Change role"
                                            value={user.role}
                                            onChange={async (e) => {
                                                const newRole = e.target.value
                                                await fetch("/api/super-admin/users", {
                                                    method: "PATCH",
                                                    headers: { "Content-Type": "application/json" },
                                                    body: JSON.stringify({ user_id: user.user_id, role: newRole })
                                                })
                                                fetchUsers()
                                            }}
                                            className="px-1.5 py-0.5 rounded text-[10px] font-medium border bg-background cursor-pointer"
                                        >
                                            <option value="owner">owner</option>
                                            <option value="admin">admin</option>
                                            <option value="member">member</option>
                                        </select>
                                    </td>
                                    <td className="py-2.5 px-3 text-right text-muted-foreground tabular-nums">{new Date(user.joined_at).toLocaleDateString()}</td>
                                    <td className="py-2.5 px-3 text-right">
                                        <button
                                            onClick={async () => {
                                                if (!confirm(`Remove ${user.display_name} from the platform?`)) return
                                                await fetch("/api/super-admin/users", {
                                                    method: "DELETE",
                                                    headers: { "Content-Type": "application/json" },
                                                    body: JSON.stringify({ user_id: user.user_id })
                                                })
                                                fetchUsers()
                                            }}
                                            className="p-1 rounded hover:bg-red-100 dark:hover:bg-red-950/30 text-muted-foreground hover:text-red-600 transition-colors"
                                            title="Remove user"
                                        >
                                            <Trash2 className="h-3.5 w-3.5" />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                    {users.length === 0 && <p className="text-center py-8 text-xs text-muted-foreground">No users found.</p>}
                </div>
            )}

            {/* Create User Modal */}
            {showCreate && typeof window !== 'undefined' && createPortal(
                <div className="fixed inset-0 z-[100] flex items-center justify-center">
                    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200" onClick={() => { if (!saving) setShowCreate(false) }} />
                    <div className="relative z-[100] w-full max-w-lg mx-4 bg-white dark:bg-zinc-900 rounded-xl border border-border/60 shadow-2xl p-6 animate-in fade-in-0 zoom-in-95 duration-200">
                        <h2 className="text-lg font-semibold text-foreground mb-4">Create User</h2>
                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1.5">
                                    <label className="text-xs font-medium text-muted-foreground">Full Name</label>
                                    <Input value={formName} onChange={e => setFormName(e.target.value)} placeholder="Harvey Specter" className="h-9 text-sm" />
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-medium text-muted-foreground">Email <span className="text-red-500">*</span></label>
                                    <Input type="email" value={formEmail} onChange={e => setFormEmail(e.target.value)} placeholder="harvey@pearsonhardman.com" className="h-9 text-sm" />
                                </div>
                            </div>
                            <div className="space-y-1.5">
                                <label className="text-xs font-medium text-muted-foreground">Password <span className="text-red-500">*</span></label>
                                <Input type="password" value={formPassword} onChange={e => setFormPassword(e.target.value)} placeholder="Min 8 characters" className="h-9 text-sm" />
                                <p className="text-[10px] text-muted-foreground">The user can change this later from their profile. Must be at least 8 characters.</p>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1.5">
                                    <label className="text-xs font-medium text-muted-foreground">Organization <span className="text-muted-foreground/60">(optional)</span></label>
                                    <select title="Select organization" value={formOrgId} onChange={e => setFormOrgId(e.target.value)} className="w-full h-9 px-3 rounded-md border bg-background text-sm">
                                        <option value="">— No org —</option>
                                        {orgs.map(o => (
                                            <option key={o.id} value={o.id}>{o.name} ({o.member_count}/{o.licensed_seats})</option>
                                        ))}
                                    </select>
                                </div>
                                <div className="space-y-1.5">
                                    <label className="text-xs font-medium text-muted-foreground">Role</label>
                                    <select title="User role" value={formRole} onChange={e => setFormRole(e.target.value)} className="w-full h-9 px-3 rounded-md border bg-background text-sm">
                                        <option value="member">Member</option>
                                        <option value="admin">Admin</option>
                                        <option value="owner">Owner</option>
                                    </select>
                                </div>
                            </div>
                            {formError && <p className="text-xs text-red-500 font-medium">{formError}</p>}
                        </div>
                        <div className="flex justify-end gap-3 mt-6">
                            <button onClick={() => setShowCreate(false)} disabled={saving} className="px-4 py-2 text-xs font-medium rounded-lg border hover:bg-muted transition-colors">Cancel</button>
                            <button onClick={handleCreate} disabled={saving || !formEmail.trim() || !formPassword} className="px-4 py-2 text-xs font-medium rounded-lg bg-primary text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50 flex items-center gap-1.5">
                                {saving && <Loader2 className="h-3.5 w-3.5 animate-spin" />}
                                {saving ? "Creating…" : "Create User"}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    )
}

"use client"

import { SidebarTrigger } from "@/components/ui/sidebar"
import * as React from "react"
import { createPortal } from "react-dom"
import { usePathname, useRouter, useParams, useSearchParams } from "next/navigation"
import { History, MessageSquare, Loader2, MoreVertical, Pencil, Trash2, Pin, PinOff, Check, X } from "lucide-react"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { Button } from "@/components/ui/button"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu"
import { toast } from "sonner"
import { Input } from "@/components/ui/input"
import { cn } from "@/lib/utils"

interface RecentConversation {
    id: string
    title: string
    type: string
    pinned: boolean
    projectId?: string
    workflowId?: string
    updatedAt: string
}

export function AppHeader() {
    const pathname = usePathname()
    const router = useRouter()
    const params = useParams()
    const searchParams = useSearchParams()
    const [isOpen, setIsOpen] = React.useState(false)
    const [conversations, setConversations] = React.useState<RecentConversation[]>([])
    const [isLoading, setIsLoading] = React.useState(false)
    const [error, setError] = React.useState<string | null>(null)
    const [renamingId, setRenamingId] = React.useState<string | null>(null)
    const [editTitle, setEditTitle] = React.useState("")
    const [deleteTarget, setDeleteTarget] = React.useState<RecentConversation | null>(null)
    const [isDeleting, setIsDeleting] = React.useState(false)
    const [isActionLoading, setIsActionLoading] = React.useState(false)

    // Determine context from the current route
    const getContext = React.useCallback(() => {
        if (pathname?.startsWith('/documents/')) {
            const projectId = Array.isArray(params?.id) ? params.id[0] : params?.id as string
            return { type: 'vault', projectId, label: 'this project' }
        }
        if (pathname?.startsWith('/templates/')) {
            const workflowId = Array.isArray(params?.id) ? params.id[0] : params?.id as string
            return { type: 'workflow', workflowId, label: 'this template' }
        }
        return { type: 'assistant', label: 'chat' }
    }, [pathname, params])

    // Fetch recent conversations when popover opens
    const handleOpen = async (open: boolean) => {
        setIsOpen(open)
        if (!open) return

        setIsLoading(true)
        setError(null)
        const ctx = getContext()

        try {
            const urlParams = new URLSearchParams({ limit: '5' })
            if (ctx.type) urlParams.set('type', ctx.type)
            if (ctx.projectId) urlParams.set('projectId', ctx.projectId)
            if (ctx.workflowId) urlParams.set('workflowId', ctx.workflowId)

            const res = await fetch(`/api/chat/conversations?${urlParams.toString()}`)
            if (!res.ok) {
                setError(`Failed to load (${res.status})`)
                return
            }
            const data = await res.json()

            if (Array.isArray(data)) {
                setConversations(data)
            }
        } catch (err) {
            setError('Failed to load conversations')
        } finally {
            setIsLoading(false)
        }
    }

    // Navigate to a conversation
    const navigateTo = (conv: RecentConversation) => {
        if (renamingId) return // Don't navigate while renaming
        setIsOpen(false)

        if (conv.type === 'vault' && conv.projectId) {
            router.push(`/documents/${conv.projectId}/chat/${conv.id}`)
        } else if (conv.type === 'workflow' && conv.workflowId) {
            router.push(`/templates/${conv.workflowId}/chat/${conv.id}`)
        } else {
            router.push(`/chat/${conv.id}`)
        }
    }

    const togglePin = async (e: React.MouseEvent, conv: RecentConversation) => {
        e.stopPropagation()
        setIsActionLoading(true)
        try {
            const res = await fetch(`/api/chat/conversations/${conv.id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ pinned: !conv.pinned })
            })

            if (!res.ok) throw new Error('Failed to toggle pin')

            setConversations(prev => prev.map(c =>
                c.id === conv.id ? { ...c, pinned: !c.pinned } : c
            ))
            toast.success(conv.pinned ? "Conversation unpinned" : "Conversation pinned")
        } catch (err) {
            toast.error("Failed to update pin status")
        } finally {
            setIsActionLoading(false)
        }
    }

    const openDeleteDialog = (e: React.MouseEvent, conv: RecentConversation) => {
        e.stopPropagation()
        setDeleteTarget(conv)
    }

    const handleDelete = async () => {
        if (!deleteTarget) return
        setIsDeleting(true)
        try {
            const res = await fetch(`/api/chat/conversations/${deleteTarget.id}`, {
                method: 'DELETE'
            })

            if (!res.ok) throw new Error('Failed to delete')

            setConversations(prev => prev.filter(c => c.id !== deleteTarget.id))
            toast.success("Conversation deleted")

            // If the deleted conversation is the current one, redirect to a new chat
            const currentChatId = searchParams.get('chatId')
            if (currentChatId === deleteTarget.id) {
                router.push(pathname)
            }
        } catch (err) {
            toast.error("Failed to delete conversation")
        } finally {
            setIsDeleting(false)
            setDeleteTarget(null)
        }
    }

    const startRename = (e: React.MouseEvent, conv: RecentConversation) => {
        e.stopPropagation()
        setRenamingId(conv.id)
        setEditTitle(conv.title)
    }

    const saveRename = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation()
        if (!editTitle.trim()) return

        setIsActionLoading(true)
        try {
            const res = await fetch(`/api/chat/conversations/${id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ title: editTitle.trim() })
            })

            if (!res.ok) throw new Error('Failed to rename')

            setConversations(prev => prev.map(c =>
                c.id === id ? { ...c, title: editTitle.trim() } : c
            ))
            setRenamingId(null)
            toast.success("Conversation renamed")
        } catch (err) {
            toast.error("Failed to rename conversation")
        } finally {
            setIsActionLoading(false)
        }
    }

    // Format relative time
    const formatTime = (dateStr: string) => {
        const diff = Date.now() - new Date(dateStr).getTime()
        const mins = Math.floor(diff / 60000)
        if (mins < 1) return 'Just now'
        if (mins < 60) return `${mins}m ago`
        const hrs = Math.floor(mins / 60)
        if (hrs < 24) return `${hrs}h ago`
        const days = Math.floor(hrs / 24)
        return `${days}d ago`
    }

    const ctx = getContext()

    // Hide Recents on listing/index pages where there's no active chat context
    const hideRecents = pathname === '/documents' || pathname === '/templates' || pathname === '/recent-chats'

    return (
        <>
            <div className="flex h-14 shrink-0 items-center gap-4 px-6 w-full justify-between bg-transparent relative z-10">
                <div className="flex items-center gap-2" id="sidebar-trigger">
                    <SidebarTrigger className="text-muted-foreground hover:text-foreground hover:bg-foreground/5 transition-colors rounded-full" />
                </div>
                <div className="flex items-center gap-2">
                    {!hideRecents && (
                        <Popover open={isOpen} onOpenChange={handleOpen}>
                            <PopoverTrigger asChild>
                                <Button variant="ghost" size="sm" className="h-8 gap-2 text-muted-foreground hover:text-foreground rounded-full px-3">
                                    <History className="h-4 w-4" />
                                    <span className="text-xs font-medium hidden sm:inline">Recents</span>
                                </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-[320px] p-0" align="end" sideOffset={8}>
                                <div className="px-4 py-3 border-b">
                                    <h4 className="text-sm font-semibold">Recent Conversations</h4>
                                    <p className="text-[11px] text-muted-foreground mt-0.5">From {ctx.label}</p>
                                </div>

                                <div className="max-h-[300px] overflow-y-auto">
                                    {isLoading ? (
                                        <div className="flex items-center justify-center py-8">
                                            <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                                        </div>
                                    ) : error ? (
                                        <div className="text-center py-8 text-sm text-destructive">
                                            {error}
                                        </div>
                                    ) : conversations.length === 0 ? (
                                        <div className="text-center py-8 text-sm text-muted-foreground">
                                            No recent conversations
                                        </div>
                                    ) : (
                                        <div className="py-1">
                                            {[...conversations].sort((a, b) => (a.pinned === b.pinned ? 0 : a.pinned ? -1 : 1)).map((conv) => (
                                                <div
                                                    key={conv.id}
                                                    className={cn(
                                                        "group relative w-full flex items-center gap-3 px-4 py-2.5 text-left hover:bg-muted/50 transition-colors cursor-pointer border-l-2",
                                                        conv.pinned ? "border-primary bg-primary/5" : "border-transparent"
                                                    )}
                                                    onClick={() => navigateTo(conv)}
                                                >
                                                    <div className="h-7 w-7 rounded-lg bg-muted/80 flex items-center justify-center shrink-0">
                                                        {conv.pinned ? (
                                                            <Pin className="h-3.5 w-3.5 text-primary fill-primary" />
                                                        ) : (
                                                            <MessageSquare className="h-3.5 w-3.5 text-muted-foreground" />
                                                        )}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        {renamingId === conv.id ? (
                                                            <div className="flex items-center gap-1" onClick={(e) => e.stopPropagation()}>
                                                                <Input
                                                                    value={editTitle}
                                                                    onChange={(e) => setEditTitle(e.target.value)}
                                                                    disabled={isActionLoading}
                                                                    className="h-7 text-sm py-0 px-2 flex-1"
                                                                    autoFocus
                                                                />
                                                                <Button
                                                                    size="icon"
                                                                    variant="ghost"
                                                                    className="h-7 w-7 text-green-500"
                                                                    onClick={(e) => saveRename(e, conv.id)}
                                                                    disabled={isActionLoading || !editTitle.trim()}
                                                                >
                                                                    {isActionLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <Check className="h-3.5 w-3.5" />}
                                                                </Button>
                                                                <Button
                                                                    size="icon"
                                                                    variant="ghost"
                                                                    className="h-7 w-7 text-destructive"
                                                                    onClick={() => setRenamingId(null)}
                                                                    disabled={isActionLoading}
                                                                >
                                                                    <X className="h-3.5 w-3.5" />
                                                                </Button>
                                                            </div>
                                                        ) : (
                                                            <>
                                                                <p className="text-sm font-medium truncate flex items-center gap-1.5">
                                                                    {conv.title}
                                                                </p>
                                                                <p className="text-[11px] text-muted-foreground">{formatTime(conv.updatedAt)}</p>
                                                            </>
                                                        )}
                                                    </div>

                                                    {!renamingId && (
                                                        <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <DropdownMenu>
                                                                <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
                                                                    <Button
                                                                        variant="ghost"
                                                                        size="icon"
                                                                        className="h-7 w-7 hover:bg-muted-foreground/10"
                                                                        disabled={isActionLoading}
                                                                    >
                                                                        <MoreVertical className="h-3.5 w-3.5" />
                                                                    </Button>
                                                                </DropdownMenuTrigger>
                                                                <DropdownMenuContent align="end" className="w-40">
                                                                    <DropdownMenuItem onClick={(e) => togglePin(e, conv)}>
                                                                        {conv.pinned ? (
                                                                            <>
                                                                                <PinOff className="h-4 w-4 mr-2" />
                                                                                <span>Unpin</span>
                                                                            </>
                                                                        ) : (
                                                                            <>
                                                                                <Pin className="h-4 w-4 mr-2" />
                                                                                <span>Pin</span>
                                                                            </>
                                                                        )}
                                                                    </DropdownMenuItem>
                                                                    <DropdownMenuItem onClick={(e) => startRename(e, conv)}>
                                                                        <Pencil className="h-4 w-4 mr-2" />
                                                                        <span>Rename</span>
                                                                    </DropdownMenuItem>
                                                                    <DropdownMenuItem
                                                                        className="text-destructive focus:text-destructive"
                                                                        onClick={(e) => openDeleteDialog(e, conv)}
                                                                    >
                                                                        <Trash2 className="h-4 w-4 mr-2" />
                                                                        <span>Delete</span>
                                                                    </DropdownMenuItem>
                                                                </DropdownMenuContent>
                                                            </DropdownMenu>
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </PopoverContent>
                        </Popover>
                    )}
                </div>
            </div>

            {/* Delete Confirmation Dialog - Portal to body */}
            {
                !!deleteTarget && createPortal(
                    <div className="fixed inset-0 z-[100] flex items-center justify-center">
                        {/* Overlay */}
                        <div
                            className="fixed inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200"
                            onClick={() => { if (!isDeleting) setDeleteTarget(null) }}
                        />
                        {/* Dialog */}
                        <div className="relative z-[101] w-full max-w-md mx-4 bg-white dark:bg-zinc-900 rounded-xl border border-border/60 shadow-2xl p-6 animate-in fade-in-0 zoom-in-95 duration-200">
                            <div className="space-y-2">
                                <h2 className="text-lg font-semibold text-foreground">Delete conversation?</h2>
                                <p className="text-sm text-muted-foreground">
                                    This will permanently delete &quot;{deleteTarget?.title || 'New Conversation'}&quot; and all its messages. This action cannot be undone.
                                </p>
                            </div>
                            <div className="flex justify-end gap-3 mt-6">
                                <Button
                                    variant="outline"
                                    onClick={() => setDeleteTarget(null)}
                                    disabled={isDeleting}
                                    className="rounded-lg"
                                >
                                    Cancel
                                </Button>
                                <Button
                                    onClick={handleDelete}
                                    disabled={isDeleting}
                                    className="rounded-lg bg-red-600 text-white hover:bg-red-700 dark:bg-red-600 dark:hover:bg-red-700"
                                >
                                    {isDeleting ? (
                                        <><Loader2 className="h-4 w-4 animate-spin mr-2" /> Deleting...</>
                                    ) : (
                                        'Delete'
                                    )}
                                </Button>
                            </div>
                        </div>
                    </div>,
                    document.body
                )}
        </>
    )
}

"use client"

import * as React from "react"

import { Paperclip, Globe, FileText, Wand2, UploadCloud, X, Cloud, Sparkles, Brain, ShieldAlert, Table, Square } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Textarea } from "@/components/ui/textarea"
