                                </div>
                                Regulatory Matters
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {profile.regulatoryMatters.compliance.length > 0 && (
                                <div>
                                    <p className="text-xs font-bold tracking-wide uppercase text-emerald-600 dark:text-emerald-400 mb-2">Compliance Framework</p>
                                    <ul className="space-y-1.5">
                                        {profile.regulatoryMatters.compliance.map((item, i) => (
                                            <li key={i} className="text-sm flex items-start gap-2 border-l-2 border-emerald-500/40 pl-3 py-0.5 text-foreground/90">{item}</li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                            {profile.regulatoryMatters.investigations.length > 0 && (
                                <div>
                                    <p className="text-xs font-bold tracking-wide uppercase text-amber-600 dark:text-amber-400 mb-2">Investigations</p>
                                    <ul className="space-y-1.5">
                                        {profile.regulatoryMatters.investigations.map((item, i) => (
                                            <li key={i} className="text-sm flex items-start gap-2">
                                                <AlertTriangle className="h-3.5 w-3.5 text-amber-500 mt-0.5 shrink-0" />
                                                <span className="text-foreground/90">{item}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    {/* Ownership */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-teal-500/10 flex items-center justify-center">
                                    <DollarSign className="h-3.5 w-3.5 text-teal-600 dark:text-teal-400" />
                                </div>
                                Ownership Structure
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <div className="grid md:grid-cols-2 gap-4">
                                <div className="bg-muted/20 p-3 rounded-lg border text-center">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">Insider Ownership</p>
                                    <p className="text-lg font-bold font-mono">{profile.ownership.insiderOwnership}</p>
                                </div>
                                <div className="bg-muted/20 p-3 rounded-lg border text-center">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">Institutional Ownership</p>
                                    <p className="text-lg font-bold font-mono">{profile.ownership.institutionalOwnership}</p>
                                </div>
                            </div>
                            <div>
                                <p className="text-xs font-bold tracking-wide uppercase text-muted-foreground mb-2">Major Shareholders</p>
                                <ul className="space-y-1.5">
                                    {profile.ownership.majorShareholders.map((holder, i) => (
                                        <li key={i} className="text-sm flex items-start gap-2 border-l-2 border-teal-500/30 pl-3 py-0.5 text-foreground/90">{holder}</li>
                                    ))}
                                </ul>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Legal Risks */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-red-500/10 flex items-center justify-center">
                                    <AlertTriangle className="h-3.5 w-3.5 text-red-600 dark:text-red-400" />
                                </div>
                                Legal Risk Assessment
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {profile.legalRisks.high.length > 0 && (
                                <div>
                                    <p className="text-xs font-bold tracking-wide uppercase text-red-600 dark:text-red-400 mb-2">High Risk</p>
                                    <ul className="space-y-1.5">
                                        {profile.legalRisks.high.map((risk, i) => (
                                            <li key={i} className="text-sm flex items-start gap-2 rounded-md bg-red-500/5 p-2.5 border border-red-500/20">
                                                <AlertTriangle className="h-3.5 w-3.5 text-red-500 mt-0.5 shrink-0" />
                                                <span className="text-foreground/90 font-medium">{risk}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                            {profile.legalRisks.medium.length > 0 && (
                                <div>
                                    <p className="text-xs font-bold tracking-wide uppercase text-amber-600 dark:text-amber-400 mb-2">Medium Risk</p>
                                    <ul className="space-y-1.5">
                                        {profile.legalRisks.medium.map((risk, i) => (
                                            <li key={i} className="text-sm flex items-start gap-2 border-l-2 border-amber-500/40 pl-3 py-0.5 text-foreground/90">{risk}</li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                        </CardContent>
                    </Card>

                    <Button onClick={resetSearch} variant="outline" className="gap-2">
                        <Search className="h-4 w-4" />
                        New Search
                    </Button>
                </div>
            )}
        </ToolPageLayout>
    )
}

"use client"

import * as React from "react"
import { Loader2, FileText, CheckCircle2, AlertTriangle, DollarSign, Calendar, Shield, ScanSearch } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { toast } from "sonner"
import { useParams } from "next/navigation"
import { DuplicateFileModal } from "@/components/ui/duplicate-file-modal"
import { ToolPageLayout } from "@/components/ui/tool-page-layout"
import { FileUploadZone } from "@/components/ui/file-upload-zone"

interface ContractAnalysisResult {
    summary: string
    parties: Array<{
        name: string
        role: string
    }>
    keyTerms: Array<{
        term: string
        description: string
        importance: 'high' | 'medium' | 'low'
    }>
    obligations: Array<{
        party: string
        obligation: string
        deadline?: string
    }>
    financialTerms: Array<{
        type: string
        amount: string
        conditions: string
    }>
    risks: Array<{
        category: string
        description: string
        severity: 'high' | 'medium' | 'low'
    }>
    terminationProvisions: string[]
    unusualClauses: string[]
    recommendations: string[]
}

export default function ContractAnalysis() {
    const params = useParams()
    const chatIdParam = params.chatId as string[] | undefined
    const chatId = chatIdParam && chatIdParam[0] === 'chat' && chatIdParam[1] ? chatIdParam[1] : undefined

    const [contractFile, setContractFile] = React.useState<File | null>(null)
    const [isAnalyzing, setIsAnalyzing] = React.useState(false)
    const [analysis, setAnalysis] = React.useState<ContractAnalysisResult | null>(null)
    const [isDuplicateModalOpen, setIsDuplicateModalOpen] = React.useState(false)

    // Load history if chatId is present
    React.useEffect(() => {
        if (!chatId) return

        const loadHistory = async () => {
            setIsAnalyzing(true)
            try {
                const res = await fetch(`/api/chat/conversations/${chatId}/messages`)
                if (res.ok) {
                    const messages = await res.json()
                    // Find the assistant message with the JSON result
                    const assistantMsg = messages.find((m: { role: string; content: string }) => m.role === 'assistant')
                    if (assistantMsg) {
                        try {
                            const parsedData = JSON.parse(assistantMsg.content)
                            setAnalysis(parsedData)
                        } catch (e) {
                            toast.error("Failed to load past result")
                        }
                    }
                }
            } catch (error) {
            } finally {
                setIsAnalyzing(false)
            }
        }

        loadHistory()
    }, [chatId])

    const handleFileSelect = (file: File) => {
        if (contractFile && contractFile.name === file.name) {
            setIsDuplicateModalOpen(true)
            return
        }
        setContractFile(file)
        toast.success("Contract uploaded")
    }

    const handleAnalyze = async () => {
        if (!contractFile) {
            toast.error("Please upload a contract")
            return
        }

        setIsAnalyzing(true)
        const formData = new FormData()
        formData.append('contract', contractFile)

        try {
            const response = await fetch('/api/templates/contract-analysis', {
                method: 'POST',
                body: formData
            })

            if (!response.ok) {
                const error = await response.json()
                throw new Error(error.error || 'Failed to analyze contract')
            }

            const data = await response.json()
            setAnalysis(data)
            toast.success("Contract analyzed successfully!")
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : "Failed to analyze contract"
            toast.error(message)
        } finally {
            setIsAnalyzing(false)
        }
    }

    const resetAnalysis = () => {
        setContractFile(null)
        setAnalysis(null)
    }


    const severityBorder: Record<string, string> = {
        high: 'border-l-red-500',
        medium: 'border-l-amber-500',
        low: 'border-l-emerald-500',
    }

    const severityBadge: Record<string, 'destructive' | 'default' | 'secondary'> = {
        high: 'destructive',
        medium: 'default',
        low: 'secondary',
    }

    return (
        <ToolPageLayout
            title="Contract Analysis"
            description="Comprehensive contract review and risk assessment"
            icon={<ScanSearch className="h-4 w-4" />}
            accentColor="bg-blue-500/10 text-blue-600 dark:text-blue-400"
        >

            {!analysis ? (
                /* Upload Section */
                <Card className="max-w-2xl mx-auto border-dashed">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <FileText className="h-5 w-5 text-blue-500" />
                            Upload Contract
                        </CardTitle>
                        <CardDescription>Upload a contract document for AI-powered comprehensive analysis</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <FileUploadZone id="contract" file={contractFile} onFileSelect={handleFileSelect} />
                        <Button
                            onClick={handleAnalyze}
                            disabled={!contractFile || isAnalyzing}
                            size="lg"
                            className="w-full gap-2"
                        >
                            {isAnalyzing ? (
                                <>
                                    <Loader2 className="h-4 w-4 animate-spin" />
                                    Analyzing Contract...
                                </>
                            ) : (
                                <>
                                    <ScanSearch className="h-4 w-4" />
                                    Analyze Contract
                                </>
                            )}
                        </Button>
                    </CardContent>
                </Card>
            ) : (
                /* Analysis Results */
                <div className="space-y-5">
                    {/* Summary */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-blue-500/10 flex items-center justify-center">
                                    <FileText className="h-3.5 w-3.5 text-blue-600 dark:text-blue-400" />
                                </div>
                                Executive Summary
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm leading-relaxed text-foreground/90">{analysis.summary}</p>
                        </CardContent>
                    </Card>

                    {/* Parties */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="text-base">Parties</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="grid sm:grid-cols-2 gap-3">
                                {analysis.parties.map((party, i) => (
                                    <div key={i} className="rounded-lg border bg-muted/30 p-4">
                                        <p className="font-semibold text-sm">{party.name}</p>
                                        <p className="text-xs text-muted-foreground mt-0.5">{party.role}</p>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Key Terms */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="text-base">Key Terms</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-3">
                                {analysis.keyTerms.map((term, i) => (
                                    <div key={i} className={`border-l-2 ${term.importance === 'high' ? 'border-l-primary' : 'border-l-muted-foreground/30'} pl-4 py-0.5`}>
                                        <div className="flex items-center gap-2 mb-0.5">
                                            <h3 className="font-semibold text-sm">{term.term}</h3>
                                            <Badge variant={term.importance === 'high' ? 'default' : 'secondary'} className="text-[10px] px-1.5 py-0">
                                                {term.importance}
                                            </Badge>
                                        </div>
                                        <p className="text-sm text-muted-foreground">{term.description}</p>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Obligations */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-emerald-500/10 flex items-center justify-center">
                                    <CheckCircle2 className="h-3.5 w-3.5 text-emerald-600 dark:text-emerald-400" />
                                </div>
                                Obligations
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-2.5">
                                {analysis.obligations.map((obligation, i) => (
                                    <div key={i} className="flex items-start gap-3 text-sm">
                                        <Badge variant="outline" className="shrink-0 mt-0.5 text-[11px] font-medium">
                                            {obligation.party}
                                        </Badge>
                                        <div className="flex-1">
                                            <span className="text-foreground/90">{obligation.obligation}</span>
                                            {obligation.deadline && (
                                                <span className="text-muted-foreground ml-1.5 text-xs">— {obligation.deadline}</span>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Financial Terms */}
                    {analysis.financialTerms.length > 0 && (
                        <Card>
                            <CardHeader className="pb-3">
                                <CardTitle className="flex items-center gap-2 text-base">
                                    <div className="h-7 w-7 rounded-md bg-green-500/10 flex items-center justify-center">
                                        <DollarSign className="h-3.5 w-3.5 text-green-600 dark:text-green-400" />
                                    </div>
                                    Financial Terms
                                </CardTitle>
                            </CardHeader>
                            <CardContent>
                                <div className="grid sm:grid-cols-2 gap-3">
                                    {analysis.financialTerms.map((term, i) => (
                                        <div key={i} className="rounded-lg border bg-green-500/5 p-3.5">
                                            <div className="flex items-center justify-between mb-1.5">
                                                <span className="font-medium text-sm">{term.type}</span>
                                                <span className="font-bold text-sm font-mono text-green-700 dark:text-green-400">{term.amount}</span>
                                            </div>
                                            <p className="text-xs text-muted-foreground leading-relaxed">{term.conditions}</p>
                                        </div>
                                    ))}
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* Risks */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-amber-500/10 flex items-center justify-center">
                                    <AlertTriangle className="h-3.5 w-3.5 text-amber-600 dark:text-amber-400" />
                                </div>
                                Risk Assessment
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-3">
                                {analysis.risks.map((risk, i) => (
                                    <div key={i} className={`border-l-2 ${severityBorder[risk.severity] || 'border-l-muted'} pl-4 py-0.5`}>
                                        <div className="flex items-center gap-2 mb-0.5">
                                            <Badge variant={severityBadge[risk.severity] || 'secondary'} className="text-[10px] px-1.5 py-0">
                                                {risk.severity}
                                            </Badge>
                                            <span className="text-sm font-medium">{risk.category}</span>
                                        </div>
                                        <p className="text-sm text-muted-foreground">{risk.description}</p>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Termination Provisions */}
                    {analysis.terminationProvisions.length > 0 && (
                        <Card>
                            <CardHeader className="pb-3">
                                <CardTitle className="flex items-center gap-2 text-base">
                                    <div className="h-7 w-7 rounded-md bg-orange-500/10 flex items-center justify-center">
                                        <Calendar className="h-3.5 w-3.5 text-orange-600 dark:text-orange-400" />
                                    </div>
                                    Termination Provisions
                                </CardTitle>
                            </CardHeader>
                            <CardContent>
                                <ul className="space-y-2">
                                    {analysis.terminationProvisions.map((provision, i) => (
                                        <li key={i} className="flex items-start gap-2.5 text-sm">
                                            <span className="h-5 w-5 rounded-full bg-muted flex items-center justify-center text-[10px] font-medium shrink-0 mt-0.5">{i + 1}</span>
                                            <span className="text-foreground/90">{provision}</span>
                                        </li>
                                    ))}
                                </ul>
                            </CardContent>
                        </Card>
                    )}

                    {/* Unusual Clauses */}
                    {analysis.unusualClauses.length > 0 && (
                        <Card className="border-amber-500/30">
                            <CardHeader className="pb-3">
                                <CardTitle className="flex items-center gap-2 text-base">
                                    <div className="h-7 w-7 rounded-md bg-amber-500/10 flex items-center justify-center">
                                        <Shield className="h-3.5 w-3.5 text-amber-600 dark:text-amber-400" />
                                    </div>
                                    Unusual or Notable Clauses
                                </CardTitle>
                            </CardHeader>
                            <CardContent>
                                <ul className="space-y-2.5">
                                    {analysis.unusualClauses.map((clause, i) => (
                                        <li key={i} className="flex items-start gap-2.5 text-sm rounded-md bg-amber-500/5 p-3">
                                            <AlertTriangle className="h-4 w-4 text-amber-500 mt-0.5 shrink-0" />
                                            <span className="text-foreground/90">{clause}</span>
                                        </li>
                                    ))}
                                </ul>
                            </CardContent>
                        </Card>
                    )}

                    {/* Recommendations */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-emerald-500/10 flex items-center justify-center">
                                    <CheckCircle2 className="h-3.5 w-3.5 text-emerald-600 dark:text-emerald-400" />
                                </div>
                                Recommendations
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <ul className="space-y-2">
                                {analysis.recommendations.map((rec, i) => (
                                    <li key={i} className="flex items-start gap-2.5 text-sm">
                                        <span className="h-5 w-5 rounded-full bg-emerald-500/10 flex items-center justify-center shrink-0 mt-0.5">
                                            <CheckCircle2 className="h-3 w-3 text-emerald-600 dark:text-emerald-400" />
                                        </span>
                                        <span className="text-foreground/90">{rec}</span>
                                    </li>
                                ))}
                            </ul>
                        </CardContent>
                    </Card>

                    <Button onClick={resetAnalysis} variant="outline" className="gap-2">
                        <FileText className="h-4 w-4" />
                        Analyze New Contract
                    </Button>
                </div>
            )}
            {/* Duplicate File Warning */}
            <DuplicateFileModal
                isOpen={isDuplicateModalOpen}
                onOpenChange={setIsDuplicateModalOpen}
            />
        </ToolPageLayout>
    )
}

"use client"

import { useState } from "react"
import { Project } from "@/types"
import { CrossReferenceToolbar } from "./cross-reference-toolbar"
import { CrossReferenceMatrix } from "./cross-reference-matrix"
import { Loader2 } from "lucide-react"

export interface CrossReferenceResult {
    targetDocumentId: string
    clauseName: string
    anchorSummary: string
    targetSummary: string
    isContradiction: boolean
    riskLevel: "None" | "Low" | "Medium" | "High"
    explanation: string
}

interface CrossReferenceViewProps {
    project: Project
    projectId: string
}

export function CrossReferenceView({ project, projectId }: CrossReferenceViewProps) {
    const [anchorDocumentId, setAnchorDocumentId] = useState<string>("")
    const [targetDocumentIds, setTargetDocumentIds] = useState<string[]>([])
    const [prompt, setPrompt] = useState("")

    const [isAnalyzing, setIsAnalyzing] = useState(false)
    const [results, setResults] = useState<CrossReferenceResult[]>([])

    const handleAnalyze = async () => {
        if (!anchorDocumentId || targetDocumentIds.length === 0 || !prompt.trim()) return

        setIsAnalyzing(true)

        try {
            const anchorDoc = project.files.find(f => f.id === anchorDocumentId)
            const targetDocs = project.files.filter(f => targetDocumentIds.includes(f.id))

            if (!anchorDoc) throw new Error("Anchor document not found")

            // We assume extracted_text exists because it's processed after upload
            const response = await fetch("/api/cross-reference/analyze", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    projectId,
                    prompt,
                    anchorDocument: {
                        id: anchorDoc.id,
                        name: anchorDoc.name,
                        text: anchorDoc.extracted_text || ""
                    },
                    targetDocuments: targetDocs.map(doc => ({
                        id: doc.id,
                        name: doc.name,
                        text: doc.extracted_text || ""
                    }))
                })
            })

            if (!response.ok) throw new Error("Failed to analyze cross-references")

            const data = await response.json()
            setResults(data.results || [])
        } catch (error) {
            // Handle error toast here
        } finally {
            setIsAnalyzing(false)
        }
    }

    return (
        <div className="flex flex-col h-full bg-background rounded-l-md overflow-hidden relative">
            <CrossReferenceToolbar 
                project={project}
                anchorDocumentId={anchorDocumentId}
                setAnchorDocumentId={setAnchorDocumentId}
                targetDocumentIds={targetDocumentIds}
                setTargetDocumentIds={setTargetDocumentIds}
                prompt={prompt}
                setPrompt={setPrompt}
                onAnalyze={handleAnalyze}
                isAnalyzing={isAnalyzing}
            />

            <div className="flex-1 overflow-auto relative bg-muted/20">
                {isAnalyzing ? (
                    <div className="flex flex-col items-center justify-center h-full gap-4 opacity-70">
                        <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        <p className="text-sm font-medium">Cross-referencing documents...</p>
                        <p className="text-xs text-muted-foreground">Checking clauses against the anchor document.</p>
                    </div>
                ) : results.length > 0 ? (
                    <CrossReferenceMatrix 
                        results={results}
                        project={project} 
                        anchorDocumentId={anchorDocumentId} 
                    />
                ) : (
                    <div className="flex flex-col items-center justify-center h-full text-muted-foreground p-8 text-center max-w-sm mx-auto">
                        <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center mb-4">
                            <span className="text-primary font-bold text-lg">⚖️</span>
                        </div>
                        <h3 className="font-semibold text-foreground mb-1">Multi-Document Cross-Reference</h3>
                        <p className="text-sm mb-6">Select an anchor document and multiple target documents. Ask a question to compare clauses and spot contradictions.</p>
                    </div>
                )}
            </div>
        </div>
    )
}

"use client"

import React, { useState, useRef, useEffect } from "react"
import { createPortal } from "react-dom"
import { Button } from "@/components/ui/button"
import { X, Send, Loader2, Sparkles, FileText, ExternalLink, Trash2 } from "lucide-react"
import { DocumentFile } from "@/types"
import type { ReviewColumn, ReviewCell } from "./tabular-review-view"
import { MarkdownRenderer } from "@/components/ui/markdown-renderer"
import { ActivityPhase, ChatCitationSource, getCitationSourceDisplayName, isDocumentSource, getDocumentRoute, SourceFavicon } from "@/components/chat-interface"
import { TaskActivityTimeline } from "@/components/ui/task-activity-timeline"

interface TabularReviewChatProps {
    projectId: string
    projectTitle: string
    columns: ReviewColumn[]
    cells: Map<string, ReviewCell>
    documents: DocumentFile[]
    onClose: () => void
    initialMessages?: ChatMessage[]
    onSaveMessages?: (messages: ChatMessage[]) => void
}

interface ChatMessage {
    role: "user" | "assistant"
    content: string
}

export function TabularReviewChat({
    projectId,
    projectTitle,
    columns,
    cells,
    documents,
    onClose,
    initialMessages,
    onSaveMessages,
}: TabularReviewChatProps) {
    const [messages, setMessages] = useState<ChatMessage[]>(initialMessages || [])
    const [input, setInput] = useState("")
    const [isStreaming, setIsStreaming] = useState(false)
    const messagesEndRef = useRef<HTMLDivElement>(null)
    const inputRef = useRef<HTMLInputElement>(null)
    const latestMessagesRef = useRef<ChatMessage[]>(messages)

    // Activity indicator state
    const [activityPhase, setActivityPhase] = useState<ActivityPhase>(null)
    const [activityEntries, setActivityEntries] = useState<{ phase: string; detail: string; time: Date }[]>([])
    const [completedPhases, setCompletedPhases] = useState<string[]>([])
    const [activityExpanded, setActivityExpanded] = useState(true)

    // Citations Sidebar state
    const [isCitationsSidebarOpen, setIsCitationsSidebarOpen] = useState(false)
    const [openCitationsIndex, setOpenCitationsIndex] = useState<number | null>(null)
    const [showClearConfirm, setShowClearConfirm] = useState(false)

    const openCitationsSidebar = (messageIndex: number) => {
        setOpenCitationsIndex(messageIndex)
        setIsCitationsSidebarOpen(true)
    }

    const closeCitationsSidebar = () => {
        setIsCitationsSidebarOpen(false)
        setOpenCitationsIndex(null)
    }

    const handleClearChat = () => {
        setMessages([]);
        if (onSaveMessages) {
            onSaveMessages([]);
        }
        setShowClearConfirm(false);
    }

    // Sync initialMessages when they load asynchronously from the DB
    useEffect(() => {
        if (initialMessages && initialMessages.length > 0) {
            setMessages(initialMessages)
        }
    }, [initialMessages])

    useEffect(() => {
        latestMessagesRef.current = messages
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" })
    }, [messages])

    // Build context from tabular data for the AI
    const buildTabularContext = () => {
        const completedCells = Array.from(cells.entries())
            .filter(([, cell]) => cell.status === "completed")
            .map(([key, cell]) => {
                const [docId, colId] = key.split("__")
                const doc = documents.find(d => d.id === docId)
                const col = columns.find(c => c.id === colId)
                return { docName: doc?.name || "Unknown", colName: col?.name || "Unknown", content: cell.content }
            })

        if (completedCells.length === 0) return ""

        let context = `TABULAR REVIEW DATA (${documents.length} documents, ${columns.length} columns):\n\n`
        const docGroups = new Map<string, Array<{ colName: string; content: string }>>()

        for (const cell of completedCells) {
            if (!docGroups.has(cell.docName)) docGroups.set(cell.docName, [])
            docGroups.get(cell.docName)!.push({ colName: cell.colName, content: cell.content })
        }

        for (const [docName, cellData] of docGroups) {
            context += `--- ${docName} ---\n`
            for (const { colName, content } of cellData) {
                context += `  ${colName}: ${content}\n`
            }
            context += "\n"
        }

        return context
    }

    const handleSend = async () => {
        if (!input.trim() || isStreaming) return

        const userMessage = input.trim()
        setInput("")
        setMessages(prev => [...prev, { role: "user", content: userMessage }])
        setIsStreaming(true)

        // Reset activity state for new message
        setActivityPhase(null)
        setActivityEntries([])
        setCompletedPhases([])
        setActivityExpanded(true)

        try {
            const tabularContext = buildTabularContext()

            // Set initial phase
            setActivityPhase('thinking')
            setActivityEntries([{ phase: 'thinking', detail: 'Analyzed query', time: new Date() }])

            // Simulate the inspection phase since it's local
            setTimeout(() => {
                setCompletedPhases(['thinking'])
                setActivityPhase('reading_extraction')
                setActivityEntries(prev => [...prev, { phase: 'reading_extraction', detail: 'Tabular review inspected', time: new Date() }])

                setTimeout(() => {
                    setCompletedPhases(prev => [...prev, 'reading_extraction'])
                    setActivityPhase('synthesis')
                    setActivityEntries(prev => [...prev, { phase: 'synthesis', detail: `Analyzed ${columns.length} columns by sorting table`, time: new Date() }])

                    setTimeout(() => {
                        setCompletedPhases(prev => [...prev, 'synthesis'])
                        setActivityPhase('drafting')
                        setActivityEntries(prev => [...prev, { phase: 'drafting', detail: 'Generating response...', time: new Date() }])
                    }, 800)
                }, 800)
            }, 500)

            const response = await fetch("/api/chat", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    message: userMessage,
                    projectId,
                    customization: {
                        role: "Wesley Assistant — Tabular Review Mode",
                        instructions: `You are analyzing a tabular review of ${documents.length} documents in the project "${projectTitle}". The user has extracted structured data across ${columns.length} columns (${columns.map(c => c.name).join(", ")}). Use the tabular review data below as your primary context to answer questions. Be concise and cite specific documents when relevant.\n\n${tabularContext}`,
                    }
                })
            })

            if (!response.ok) throw new Error("Chat request failed")

            const reader = response.body?.getReader()
            if (!reader) throw new Error("No reader")

            const decoder = new TextDecoder()
            let assistantContent = ""

            setMessages(prev => [...prev, { role: "assistant", content: "" }])

            let firstTokenReceived = false

            while (true) {
                const { done, value } = await reader.read()
                if (done) break

                const text = decoder.decode(value, { stream: true })
                const lines = text.split("\n")

                for (const line of lines) {
                    if (line.startsWith("data: ")) {
                        const data = line.slice(6)
                        if (data === "[DONE]") {
                            break
                        }

                        try {
                            const parsed = JSON.parse(data)



                            if (parsed.content) {
                                if (!firstTokenReceived) {
                                    firstTokenReceived = true
                                    // Ensure visual transition to 'writing' state
                                    setActivityPhase('writing')
                                }

                                assistantContent += parsed.content
                                setMessages(prev => {
                                    const updated = [...prev]
                                    updated[updated.length - 1] = {
                                        role: "assistant",
                                        content: assistantContent,
                                    }
                                    return updated
                                })
                            }
                        } catch {
                            // Skip non-JSON lines
                        }
                    }
                }
            }
        } catch (err) {
            setMessages(prev => [...prev, {
                role: "assistant",
                content: "Sorry, I encountered an error. Please try again.",
            }])
        } finally {
            setIsStreaming(false)
            setActivityPhase('complete')
            setActivityExpanded(false)
            // Save messages after streaming completes, deferred to avoid setState in render warning
            setTimeout(() => {
                onSaveMessages?.(latestMessagesRef.current)
            }, 10)
        }
    }

    const completedCount = Array.from(cells.values()).filter(c => c.status === "completed").length
    const totalPossible = documents.length * columns.length

    return (
        <div className="flex flex-col h-full bg-background border-l shadow-xl relative overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between px-3 py-2 border-b shrink-0">
                <div className="flex items-center gap-2">
                    <Sparkles className="h-4 w-4 text-amber-500" />
                    <span className="text-sm font-medium">Review Chat</span>
                </div>
                <div className="flex items-center gap-1">
                    <Button variant="ghost" size="icon" onClick={() => setShowClearConfirm(true)} className="h-7 w-7 text-muted-foreground hover:text-destructive transition-colors" title="Clear Chat">
                        <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                    <Button variant="ghost" size="icon" onClick={onClose} className="h-7 w-7">
                        <X className="h-3.5 w-3.5" />
                    </Button>
                </div>
            </div>

            {/* Context indicator */}
            <div className="px-3 py-1.5 border-b bg-muted/30 shrink-0">
                <div className="flex items-center gap-1.5 text-[11px] text-muted-foreground">
                    <FileText className="h-3 w-3" />
                    <span>Context:</span>
                    <span className="font-medium text-foreground flex items-center gap-1">
                        <span className="w-2 h-2 rounded-full bg-red-500 inline-block"></span>
                        {projectTitle}
                    </span>
                </div>
                {completedCount > 0 && (
                    <div className="text-[10px] text-muted-foreground mt-0.5">
                        {completedCount}/{totalPossible} cells extracted
                    </div>
                )}
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto px-3 py-3 space-y-3">
                {messages.length === 0 && (
                    <div className="text-center py-8 space-y-3">
                        <Sparkles className="h-8 w-8 mx-auto text-amber-500/50" />
                        <div>
                            <p className="text-sm font-medium">Analyze your tabular review</p>
                            <p className="text-[11px] text-muted-foreground mt-1">
                                Ask questions about the extracted data across your documents
                            </p>
                        </div>
                        <div className="space-y-1.5">
                            {[
                                "What are the three most valuable contracts?",
                                "Compare the termination clauses across documents",
                                "Which agreements have the highest financial obligations?",
                            ].map(q => (
                                <button
                                    key={q}
                                    className="block w-full text-left text-[11px] px-3 py-1.5 rounded-lg border hover:bg-muted/50 transition-colors text-muted-foreground"
                                    onClick={() => {
                                        setInput(q)
                                        inputRef.current?.focus()
                                    }}
                                >
                                    {q}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
                {(() => {
                    let userCount = 0;
                    let startIndex = 0;
                    for (let i = messages.length - 1; i >= 0; i--) {
                        if (messages[i].role === "user") {
                            userCount++;
                            if (userCount === 20) {
                                startIndex = i;
                                break;
                            }
                        }
                    }
                    const visibleMessages = messages.slice(startIndex);

                    return visibleMessages.map((msg, idx) => {
                        const actualIndex = startIndex + idx;
                        const isLastMessage = actualIndex === messages.length - 1;
                        const isCurrentlyStreamingAssistant = isLastMessage && msg.role === "assistant" && activityPhase;

                        return (
                            <React.Fragment key={actualIndex}>
                                {isCurrentlyStreamingAssistant && activityExpanded && (
                                    <div className="mb-4">
                                        <TaskActivityTimeline
                                            phase={activityPhase}
                                            entries={activityEntries}
                                            completedPhases={completedPhases}
                                            onClose={() => setActivityExpanded(false)}
                                        />
                                    </div>
                                )}
                                <div className={msg.role === "user" ? "flex justify-end" : ""}>
                                    <div
                                        className={
                                            msg.role === "user"
                                                ? "bg-foreground text-background px-3 py-1.5 rounded-2xl rounded-br-sm text-[12px] max-w-[85%]"
                                                : "text-[12px] leading-relaxed"
                                        }
                                    >
                                        {msg.role === "assistant" ? (
                                            <>
                                                <MarkdownRenderer
                                                    content={msg.content}
                                                    onSourceClick={() => openCitationsSidebar(actualIndex)}
                                                />
                                                {isStreaming && actualIndex === messages.length - 1 && (
                                                    <span className="inline-block w-1.5 h-3.5 bg-foreground/60 ml-0.5 animate-pulse" />
                                                )}
                                            </>
                                        ) : (
                                            msg.content
                                        )}
                                    </div>
                                </div>
                                {/* If the last message is from the user and we are waiting for the assistant, show timeline here */}
                                {isLastMessage && msg.role === "user" && activityPhase && activityExpanded && (
                                    <div className="mt-4 mb-4">
                                        <TaskActivityTimeline
                                            phase={activityPhase}
                                            entries={activityEntries}
                                            completedPhases={completedPhases}
                                            onClose={() => setActivityExpanded(false)}
                                        />
                                    </div>
                                )}
                            </React.Fragment>
                        );
                    });
                })()}

                {/* AI Activity Timeline moved inside messages loop */}

                <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="px-3 py-2 border-t shrink-0">
                <div className="flex items-center gap-2">
                    <input
                        ref={inputRef}
                        className="flex-1 text-sm bg-transparent outline-none placeholder:text-muted-foreground/50"
                        placeholder="Ask a follow up..."
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyDown={e => e.key === "Enter" && !e.shiftKey && handleSend()}
                        disabled={isStreaming}
                    />
                    <Button
                        size="icon"
                        variant="ghost"
                        onClick={handleSend}
                        disabled={!input.trim() || isStreaming}
                        className="h-7 w-7"
                    >
                        {isStreaming ? (
                            <Loader2 className="h-3.5 w-3.5 animate-spin" />
                        ) : (
                            <Send className="h-3.5 w-3.5" />
                        )}
                    </Button>
                </div>
            </div>

            {/* Citations Sidebar */}
            {isCitationsSidebarOpen && openCitationsIndex !== null && (() => {
                const msg = messages[openCitationsIndex]
                if (!msg) return null

                const sourcesMatch = msg.content.match(/<!--SOURCES:?\s*([\s\S]*?)(?:-->|$)/i)
                const sources: ChatCitationSource[] = sourcesMatch ? sourcesMatch[1].trim().split('\n').map((line: string) => {
                    const match = line.match(/\[(\d+)\]\s*([^|]+)(?:\s*\|\s*([^|]*?))?(?:\s*\|\s*(.*))?$/)
                    if (!match) return null

                    let url = (match[3] || '').trim()
                    if (url && !url.startsWith('http') && !url.includes('.')) url = ''

                    return {
                        num: match[1],
                        title: match[2].trim(),
                        url: url || 'https://legal-source.internal',
                        snippet: (match[4] || '').trim()
                    } as ChatCitationSource
                }).filter((x): x is ChatCitationSource => x !== null) : []

                return (
                    <div className="absolute inset-y-0 right-0 w-[300px] border-l bg-background flex flex-col shadow-xl animate-in slide-in-from-right duration-300 z-50">
                        <div className="flex items-center justify-between px-4 py-3 border-b shrink-0">
                            <h2 className="font-semibold text-sm">Citations</h2>
                            <Button variant="ghost" size="icon" className="h-7 w-7 rounded-full" onClick={closeCitationsSidebar}>
                                <X className="h-4 w-4" />
                            </Button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-5">
                            {sources.length === 0 ? (
                                <p className="text-xs text-muted-foreground text-center mt-10">No citations found.</p>
                            ) : (
                                sources.map((src, idx) => {
                                    const isDocument = isDocumentSource(src.url)
                                    const route = isDocument ? getDocumentRoute(src.url) : null

                                    const inner = (
                                        <div className="space-y-1.5">
                                            <div className="flex items-center gap-2">
                                                <div className="h-4 w-4 rounded-sm overflow-hidden bg-muted flex items-center justify-center shrink-0">
                                                    {isDocument ? (
                                                        <FileText className="h-3 w-3 text-primary/70" />
                                                    ) : (
                                                        <SourceFavicon url={src.url} size={16} className="h-4 w-4 object-contain" />
                                                    )}
                                                </div>
                                                <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider truncate">
                                                    {isDocument ? 'Document' : getCitationSourceDisplayName(src.url, src.title)}
                                                </span>
                                                {!isDocument && (
                                                    <ExternalLink className="h-3 w-3 text-muted-foreground/30 group-hover:text-primary transition-colors ml-auto" />
                                                )}
                                            </div>
                                            <h3 className="text-xs font-bold leading-tight group-hover:text-primary transition-colors line-clamp-2">
                                                {src.title}
                                            </h3>
                                            <p className="text-[11px] text-muted-foreground/70 line-clamp-2 leading-relaxed">
                                                {src.snippet || (isDocument ? 'Document' : src.url)}
                                            </p>
                                        </div>
                                    )

                                    if (isDocument && route) {
                                        return (
                                            <div
                                                key={idx}
                                                className="group block space-y-2 border-b border-border/40 pb-4 last:border-0 cursor-pointer"
                                                onClick={() => { closeCitationsSidebar(); window.open(route, '_blank') }}
                                            >
                                                {inner}
                                            </div>
                                        )
                                    }

                                    return (
                                        <a
                                            key={idx}
                                            href={src.url}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="group block space-y-2 border-b border-border/40 pb-4 last:border-0"
                                        >
                                            {inner}
                                        </a>
                                    )
                                })
                            )}
                        </div>
                    </div>
                )
            })()}
            {/* Clear Chat Confirmation Dialog */}
            {showClearConfirm && createPortal(
                <div className="fixed inset-0 z-50 flex items-center justify-center">
                    {/* Overlay */}
                    <div
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in-0 duration-200"
                        onClick={() => setShowClearConfirm(false)}
                    />
                    {/* Dialog */}
                    <div className="relative z-50 w-full max-w-md mx-4 bg-white dark:bg-zinc-900 rounded-xl border border-border/60 shadow-2xl p-6 animate-in fade-in-0 zoom-in-95 duration-200">
                        <div className="space-y-2">
                            <h2 className="text-lg font-semibold text-foreground">Clear chat history?</h2>
                            <p className="text-sm text-muted-foreground">
                                This will permanently delete all messages in this review chat. This action cannot be undone.
                            </p>
                        </div>
                        <div className="flex justify-end gap-3 mt-6">
                            <Button
                                variant="outline"
                                onClick={() => setShowClearConfirm(false)}
                                className="rounded-lg"
                            >
                                Cancel
                            </Button>
                            <Button
                                onClick={handleClearChat}
                                className="rounded-lg bg-red-600 text-white hover:bg-red-700 dark:bg-red-600 dark:hover:bg-red-700"
                            >
                                Clear Chat
                            </Button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    )
}

"use client"

import { useState, useCallback, useMemo, useEffect, useRef } from "react"
import { Project, DocumentFile } from "@/types"
import { TabularReviewToolbar } from "./tabular-review-toolbar"
import { TabularReviewGrid } from "./tabular-review-grid"
import { TabularReviewChat } from "./tabular-review-chat"
import { toast } from "sonner"

export interface ReviewColumn {
    id: string
    name: string
    prompt: string
    width: number
    order: number
}

export interface ReviewCell {
    documentId: string
    columnId: string
    content: string
    status: "pending" | "processing" | "completed" | "error"
}

export interface TabularReviewState {
    columns: ReviewColumn[]
    cells: Map<string, ReviewCell>
    documents: DocumentFile[]
}

const FALLBACK_COLUMNS: ReviewColumn[] = [
    { id: "summary", name: "Summary", prompt: "Provide a 2-3 sentence summary of this document.", width: 220, order: 0 },
    { id: "parties", name: "Parties", prompt: "List all parties involved in this document with their roles. Be concise.", width: 220, order: 1 },
    { id: "effective_date", name: "Effective Date", prompt: "What is the effective date of this document? If not specified, say '—'.", width: 220, order: 2 },
    { id: "key_terms", name: "Key Terms", prompt: "What are the top 3-5 key terms in this document? Be concise.", width: 220, order: 3 },
    { id: "key_obligations", name: "Key Obligations", prompt: "What are the main obligations of each party? Be concise.", width: 220, order: 4 },
]



function getCellKey(documentId: string, columnId: string) {
    return `${documentId}__${columnId}`
}

interface TabularReviewViewProps {
    project: Project
    projectId: string
}

export function TabularReviewView({ project, projectId }: TabularReviewViewProps) {
    const [columns, setColumns] = useState<ReviewColumn[]>([])
    const [cells, setCells] = useState<Map<string, ReviewCell>>(new Map())
    const [isRunning, setIsRunning] = useState(false)
    const [chatOpen, setChatOpen] = useState(true)
    const [runProgress, setRunProgress] = useState({ total: 0, completed: 0 })
    const [isGeneratingColumns, setIsGeneratingColumns] = useState(true)
    const [isLoadingCached, setIsLoadingCached] = useState(true)
    const [chatMessages, setChatMessages] = useState<{ role: "user" | "assistant"; content: string }[]>([])
    const [chatWidth, setChatWidth] = useState(340)

    const hasInitialized = useRef(false)
    const autoRunTriggered = useRef(false)
    const savedFileIds = useRef<Set<string>>(new Set())
    const pendingNewDocs = useRef<DocumentFile[]>([])
    const isDraggingRef = useRef(false)

    const documents = useMemo(() => project.files || [], [project.files])
    const docsWithText = useMemo(() => documents.filter(d => d.extracted_text), [documents])

    // ──────────────────────────────────────────────────
    // Helper: Save columns + cells to the database
    // ──────────────────────────────────────────────────
    const saveToDatabase = useCallback(async (cols: ReviewColumn[], cellMap: Map<string, ReviewCell>, msgs?: { role: "user" | "assistant"; content: string }[]) => {
        try {
            const cellArray = Array.from(cellMap.values())
            await fetch('/api/tabular-review/save', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    projectId,
                    columns: cols,
                    cells: cellArray,
                    chatMessages: msgs
                })
            })
        } catch (err) {
        }
    }, [projectId])

    // ──────────────────────────────────────────────────
    // 1. Load cached data OR AI Column Generation on mount
    // ──────────────────────────────────────────────────
    useEffect(() => {
        if (hasInitialized.current) return
        hasInitialized.current = true

        const initialize = async () => {
            setIsGeneratingColumns(true)
            setIsLoadingCached(true)

            // STEP 1: Try loading from database first
            try {
                const loadRes = await fetch(`/api/tabular-review/load?projectId=${projectId}`)
                if (loadRes.ok) {
                    const cached = await loadRes.json()

                    if (cached.columns && cached.columns.length > 0) {
                        setColumns(cached.columns)

                        const restoredCells = new Map<string, ReviewCell>()
                        for (const cell of cached.cells || []) {
                            restoredCells.set(getCellKey(cell.documentId, cell.columnId), cell)
                        }
                        setCells(restoredCells)

                        if (cached.chatMessages) {
                            setChatMessages(cached.chatMessages)
                        }

                        // Track which file IDs we already have data for
                        const cachedFileIds = new Set<string>((cached.cells || []).map((c: { documentId: string }) => c.documentId))
                        savedFileIds.current = cachedFileIds

                        // Detect new documents not in cached data
                        const newDocs = docsWithText.filter(d => !cachedFileIds.has(d.id))

                        setIsGeneratingColumns(false)
                        setIsLoadingCached(false)

                        if (newDocs.length > 0) {
                            toast.success(`Loaded from cache. ${newDocs.length} new document(s) to extract.`)
                            pendingNewDocs.current = newDocs
                            // autoRunTriggered stays false so the auto-run effect picks up new docs
                        } else {
                            toast.success(`Loaded ${cached.columns.length} columns from cache`)
                            autoRunTriggered.current = true
                        }
                        return
                    }
                }
            } catch (err) {
            }

            setIsLoadingCached(false)

            // STEP 2: No cached data — generate columns with AI
            if (docsWithText.length === 0) {
                setColumns(FALLBACK_COLUMNS)
                setIsGeneratingColumns(false)
                return
            }

            try {
                const documentSamples = docsWithText.slice(0, 5).map(doc => ({
                    name: doc.name,
                    text: doc.extracted_text?.slice(0, 2000) || ''
                }))

                const response = await fetch('/api/tabular-review/suggest-columns', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ projectId, documentSamples })
                })

                if (!response.ok) throw new Error('Failed to suggest columns')

                const data = await response.json()

                if (data.columns && data.columns.length > 0) {
                    const aiColumns: ReviewColumn[] = data.columns.map(
                        (col: { name: string; prompt: string }, i: number) => ({
                            id: col.name.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '') + '_' + i,
                            name: col.name,
                            prompt: col.prompt,
                            width: 220,
                            order: i,
                        })
                    )
                    setColumns(aiColumns)
                    toast.success(`AI suggested ${aiColumns.length} columns`)
                } else {
                    throw new Error('No columns returned')
                }
            } catch (err) {
                setColumns(FALLBACK_COLUMNS)
                toast.error('Using default columns (AI suggestion failed)')
            } finally {
                setIsGeneratingColumns(false)
            }
        }

        initialize()
    }, [docsWithText, projectId, saveToDatabase])

    // ──────────────────────────────────────────────────
    // 2. Run AI extraction for a single cell
    // ──────────────────────────────────────────────────
    const runCell = useCallback(async (docId: string, columnId: string, column: ReviewColumn, docText: string) => {
        const key = getCellKey(docId, columnId)

        setCells(prev => {
            const next = new Map(prev)
            next.set(key, { documentId: docId, columnId, content: "", status: "processing" })
            return next
        })

        try {
            const response = await fetch("/api/tabular-review/extract", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    projectId,
                    documentId: docId,
                    columnPrompt: column.prompt,
                    columnName: column.name,
                    documentText: docText.slice(0, 15000),
                })
            })

            if (!response.ok) throw new Error("Extraction failed")

            const data = await response.json()

            setCells(prev => {
                const next = new Map(prev)
                next.set(key, {
                    documentId: docId,
                    columnId,
                    content: data.content || "—",
                    status: "completed",
                })
                return next
            })
        } catch {
            setCells(prev => {
                const next = new Map(prev)
                next.set(key, {
                    documentId: docId,
                    columnId,
                    content: "Error extracting",
                    status: "error",
                })
                return next
            })
        }
    }, [projectId])

    // ──────────────────────────────────────────────────
    // 3. Batch extraction for a document
    // ──────────────────────────────────────────────────
    const runDocumentBatch = useCallback(async (doc: DocumentFile, targetColumns: ReviewColumn[]) => {
        if (targetColumns.length === 0) return

        setCells(prev => {
            const next = new Map(prev)
            for (const col of targetColumns) {
                next.set(getCellKey(doc.id, col.id), { documentId: doc.id, columnId: col.id, content: "", status: "processing" })
            }
            return next
        })

        try {
            const response = await fetch("/api/tabular-review/extract-batch", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    projectId,
                    documentId: doc.id,
                    documentText: doc.extracted_text || "",
                    columns: targetColumns.map(c => ({ id: c.id, name: c.name, prompt: c.prompt }))
                })
            })

            if (!response.ok) throw new Error("Batch extraction failed")
            const data = await response.json()

            setCells(prev => {
                const next = new Map(prev)
                for (const col of targetColumns) {
                    const content = data.results?.[col.id] || "—"
                    next.set(getCellKey(doc.id, col.id), {
                        documentId: doc.id,
                        columnId: col.id,
                        content,
                        status: "completed"
                    })
                }
                return next
            })
        } catch {
            setCells(prev => {
                const next = new Map(prev)
                for (const col of targetColumns) {
                    next.set(getCellKey(doc.id, col.id), {
                        documentId: doc.id,
                        columnId: col.id,
                        content: "Error extracting",
                        status: "error"
                    })
                }
                return next
            })
        }
    }, [projectId])

    // ──────────────────────────────────────────────────
    // 4. Run extraction for specific columns on specific docs
    // ──────────────────────────────────────────────────
    const runColumns = useCallback(async (targetColumns: ReviewColumn[], targetDocs?: DocumentFile[]) => {
        if (isRunning) return
        setIsRunning(true)

        const docs = targetDocs || docsWithText
        const totalCells = docs.length * targetColumns.length

        let initialCompleted = 0
        const docTasks: Array<{ doc: DocumentFile, cols: ReviewColumn[] }> = []

        // Group columns that need extraction by document
        for (const doc of docs) {
            const colsToRun = targetColumns.filter(col => {
                const existing = cells.get(getCellKey(doc.id, col.id))
                // Skip if already completed OR already processing to prevent duplicate API calls
                if (existing?.status === "completed" || existing?.status === "processing") {
                    if (existing?.status === "completed") initialCompleted++
                    return false
                }
                return true
            })
            if (colsToRun.length > 0) {
                docTasks.push({ doc, cols: colsToRun })
            }
        }

        setRunProgress({ total: totalCells, completed: initialCompleted })
        let currentCompleted = initialCompleted

        // Process a few documents concurrently
        const batchSize = 3
        for (let i = 0; i < docTasks.length; i += batchSize) {
            const batch = docTasks.slice(i, i + batchSize)
            await Promise.all(
                batch.map(({ doc, cols }) =>
                    runDocumentBatch(doc, cols).then(() => {
                        currentCompleted += cols.length
                        setRunProgress(prev => ({ ...prev, completed: currentCompleted }))
                    })
                )
            )
        }

        setIsRunning(false)

        // Auto-save after extraction completes
        setCells(currentCells => {
            setColumns(currentCols => {
                setChatMessages(currentMsgs => {
                    saveToDatabase(currentCols, currentCells, currentMsgs)
                    return currentMsgs
                })
                return currentCols
            })
            return currentCells
        })
    }, [isRunning, docsWithText, cells, runDocumentBatch, saveToDatabase])

    // ──────────────────────────────────────────────────
    // 5. Run ALL cells (force re-run, used by Run all button)
    // ──────────────────────────────────────────────────
    const runAll = useCallback(async () => {
        if (isRunning || columns.length === 0) return
        setIsRunning(true)

        const totalCells = docsWithText.length * columns.length
        setRunProgress({ total: totalCells, completed: 0 })

        let currentCompleted = 0

        const batchSize = 3
        for (let i = 0; i < docsWithText.length; i += batchSize) {
            const batch = docsWithText.slice(i, i + batchSize)
            await Promise.all(
                batch.map((doc) =>
                    runDocumentBatch(doc, columns).then(() => {
                        currentCompleted += columns.length
                        setRunProgress(prev => ({ ...prev, completed: currentCompleted }))
                    })
                )
            )
        }

        setIsRunning(false)
        toast.success("Tabular review completed!")

        // Auto-save after full run
        setCells(currentCells => {
            setColumns(currentCols => {
                setChatMessages(currentMsgs => {
                    saveToDatabase(currentCols, currentCells, currentMsgs)
                    return currentMsgs
                })
                return currentCols
            })
            return currentCells
        })
    }, [isRunning, docsWithText, columns, runDocumentBatch, saveToDatabase])

    // ──────────────────────────────────────────────────
    // 5. Auto-run extraction after columns are set
    // ──────────────────────────────────────────────────
    useEffect(() => {
        if (isGeneratingColumns) return
        if (isLoadingCached) return
        if (autoRunTriggered.current) return
        if (columns.length === 0 || docsWithText.length === 0) return

        autoRunTriggered.current = true

        // If we have pending new docs from cached load, only run those
        const newDocs = pendingNewDocs.current
        const timer = setTimeout(() => {
            if (newDocs.length > 0) {
                pendingNewDocs.current = []
                runColumns(columns, newDocs)
            } else {
                runColumns(columns)
            }
        }, 300)
        return () => clearTimeout(timer)
    }, [isGeneratingColumns, isLoadingCached, columns, docsWithText, runColumns])

    // ──────────────────────────────────────────────────
    // Add a new column (auto-triggers extraction)
    // ──────────────────────────────────────────────────
    const addColumn = useCallback((name: string, prompt?: string) => {
        const id = name.toLowerCase().replace(/\s+/g, "_").replace(/[^a-z0-9_]/g, "") + "_" + Date.now()
        const newCol: ReviewColumn = {
            id,
            name,
            prompt: prompt || `Extract information about "${name}" from this document. Be concise and specific.`,
            width: 220,
            order: columns.length
        }
        setColumns(prev => {
            const nextCols = [...prev, newCol]
            // Immediately auto-save
            setCells(currentCells => {
                setChatMessages(currentMsgs => {
                    saveToDatabase(nextCols, currentCells, currentMsgs)
                    return currentMsgs
                })
                return currentCells
            })
            return nextCols
        })

        // Auto-extract for this new column
        if (docsWithText.length > 0) {
            setTimeout(() => {
                runColumns([newCol])
            }, 100)
        }

        toast.success(`Column "${name}" added`)
    }, [columns.length, docsWithText, runColumns, saveToDatabase])

    // Remove a column
    const removeColumn = useCallback((columnId: string) => {
        setColumns(prev => {
            const updated = prev.filter(c => c.id !== columnId)
            // Auto-save after column removal
            setCells(currentCells => {
                const next = new Map(currentCells)
                for (const key of next.keys()) {
                    if (key.endsWith(`__${columnId}`)) next.delete(key)
                }
                setChatMessages(currentMsgs => {
                    saveToDatabase(updated, next, currentMsgs)
                    return currentMsgs
                })
                return next
            })
            return updated
        })
    }, [saveToDatabase])



    // Get cell data
    const getCell = useCallback((docId: string, colId: string): ReviewCell | undefined => {
        return cells.get(getCellKey(docId, colId))
    }, [cells])

    // Handle saving messages from chat
    const handleSaveMessages = useCallback((newMessages: { role: "user" | "assistant"; content: string }[]) => {
        setChatMessages(newMessages)
        setCells(currentCells => {
            setColumns(currentCols => {
                saveToDatabase(currentCols, currentCells, newMessages)
                return currentCols
            })
            return currentCells
        })
    }, [saveToDatabase])

    // Handle chat resizing
    const startResizing = useCallback((mouseDownEvent: React.MouseEvent) => {
        mouseDownEvent.preventDefault()
        isDraggingRef.current = true

        const startX = mouseDownEvent.clientX
        const startWidth = chatWidth

        const onMouseMove = (mouseMoveEvent: MouseEvent) => {
            if (!isDraggingRef.current) return
            const newWidth = startWidth + (mouseMoveEvent.clientX - startX)
            setChatWidth(Math.min(Math.max(newWidth, 250), 800))
        }

        const onMouseUp = () => {
            isDraggingRef.current = false
            document.removeEventListener("mousemove", onMouseMove)
            document.removeEventListener("mouseup", onMouseUp)
            document.body.style.cursor = 'default'
        }

        document.body.style.cursor = 'col-resize'
        document.addEventListener("mousemove", onMouseMove)
        document.addEventListener("mouseup", onMouseUp)
    }, [chatWidth])

    return (
        <div className="flex flex-1 h-full overflow-hidden">
            {/* Chat Sidebar */}
            {chatOpen && (
                <div
                    // Edge Tools often flag inline styles dynamically injected by React, but this is required for smooth sliding
                    style={{ width: `${chatWidth}px` }}
                    className="shrink-0 border-r bg-background flex flex-col h-full relative group"
                >
                    <TabularReviewChat
                        projectId={projectId}
                        projectTitle={project.title}
                        columns={columns}
                        cells={cells}
                        documents={documents}
                        onClose={() => setChatOpen(false)}
                        initialMessages={chatMessages}
                        onSaveMessages={handleSaveMessages}
                    />

                    {/* Drag Handle */}
                    <div
                        onMouseDown={startResizing}
                        className="absolute right-[-4px] top-0 bottom-0 w-2 cursor-col-resize z-10 hover:bg-primary/20 transition-colors"
                    />
                </div>
            )}

            {/* Main grid area */}
            <div className="flex-1 flex flex-col h-full overflow-hidden">
                <TabularReviewToolbar
                    columns={columns}
                    onAddColumn={addColumn}
                    onRunAll={runAll}
                    isRunning={isRunning}
                    isGeneratingColumns={isGeneratingColumns}
                    runProgress={runProgress}
                    chatOpen={chatOpen}
                    onToggleChat={() => setChatOpen(prev => !prev)}
                    documentCount={documents.length}
                />

                <TabularReviewGrid
                    documents={documents}
                    columns={columns}
                    getCell={getCell}
                    onRemoveColumn={removeColumn}
                    onRunCell={(docId, colId) => {
                        const col = columns.find(c => c.id === colId)
                        const doc = documents.find(d => d.id === docId)
                        if (col && doc?.extracted_text) {
                            runCell(docId, colId, col, doc.extracted_text)
                        }
                    }}
                />
            </div>
        </div>
    )
}

"use client"

import * as React from "react"
