// ─── Document Text Viewer ─────────────────────────────────────────
// Fetches extracted text from the API and renders the full content
// with the matching passage highlighted in yellow.

function DocTextViewer({
    fileId,
    highlightText,
}: {
    fileId: string
    highlightText: string
}) {
    const [text, setText] = React.useState<string | null>(null)
    const [loading, setLoading] = React.useState(true)
    const [error, setError] = React.useState<string | null>(null)
    const containerRef = React.useRef<HTMLDivElement>(null)

    // Fetch extracted text
    React.useEffect(() => {
        let cancelled = false
        setLoading(true)
        setError(null)

        async function fetchText() {
            try {
                const res = await fetch(`/api/documents/${fileId}/text`)
                if (!res.ok) throw new Error(`Failed to fetch text: ${res.status}`)
                const data = await res.json()
                if (!cancelled) {
                    setText(data.text || '')
                }
            } catch (err) {
                if (!cancelled) setError('Failed to load document text')
            } finally {
                if (!cancelled) setLoading(false)
            }
        }

        fetchText()
        return () => { cancelled = true }
    }, [fileId])

    // Scroll to highlighted section after render
    React.useEffect(() => {
        if (!text || !containerRef.current) return
        const timer = setTimeout(() => {
            const highlighted = containerRef.current?.querySelector('.doc-highlight-active')
            if (highlighted) {
                highlighted.scrollIntoView({ behavior: 'smooth', block: 'center' })
            }
        }, 100)
        return () => clearTimeout(timer)
    }, [text, highlightText])

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center h-full gap-3">
                <Loader2 className="h-6 w-6 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">Loading document...</p>
            </div>
        )
    }

    if (error || !text) {
        return (
            <div className="flex flex-col items-center justify-center h-full gap-3 p-8 text-center">
                <FileText className="h-10 w-10 text-muted-foreground" />
                <p className="text-sm text-muted-foreground">{error || 'No text available'}</p>
            </div>
        )
    }

    // Build highlighted HTML by finding the snippet in the full text
    const renderHighlightedText = () => {
        if (!highlightText || highlightText.length < 20) {
            return <pre className="whitespace-pre-wrap text-sm leading-relaxed font-sans">{text}</pre>
        }

        // Build an index map mapping normalized text indices back to original text indices
        let normalizedText = ''
        let isSpace = false
        const indexMap: number[] = []

        // To handle leading whitespace appropriately
        const trimmedOriginalMatch = text.match(/^\s+/)
        if (trimmedOriginalMatch) {
            // we will skip mapping leading spaces into `normalizedText` or handle them carefully
        }

        for (let i = 0; i < text.length; i++) {
            const char = text[i]
            if (/\s/.test(char)) {
                if (!isSpace) {
                    // Only add a single space to normalized text if we haven't just added one
                    if (normalizedText.length > 0) { // skip leading spaces entirely
                        normalizedText += ' '
                        indexMap.push(i)
                        isSpace = true
                    }
                }
            } else {
                normalizedText += char
                indexMap.push(i)
                isSpace = false
            }
        }
        indexMap.push(text.length)

        const normalizedSnippet = highlightText.replace(/\s+/g, ' ').trim()

        // Try progressively shorter snippets for matching
        let matchIndex = -1
        let matchLength = 0
        const searchLengths = [
            Math.min(normalizedSnippet.length, 200),
            Math.min(normalizedSnippet.length, 100),
            Math.min(normalizedSnippet.length, 60),
            Math.min(normalizedSnippet.length, 30),
        ]

        for (const len of searchLengths) {
            if (len < 15) continue
            const searchStr = normalizedSnippet.substring(0, len).toLowerCase()
            const idx = normalizedText.toLowerCase().indexOf(searchStr)
            if (idx !== -1) {
                matchIndex = idx
                // Extend match to full snippet length if possible
                matchLength = Math.min(normalizedSnippet.length, normalizedText.length - idx)
                break
            }
        }

        if (matchIndex === -1) {
            // No match found, show text with snippet callout at top
            return (
                <div>
                    <div className="mb-4 p-3 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800">
                        <p className="text-[10px] font-bold text-yellow-700 dark:text-yellow-400 uppercase tracking-wider mb-1">
                            Cited Passage
                        </p>
                        <p className="text-sm text-yellow-900 dark:text-yellow-200 leading-relaxed italic">
                            &ldquo;{highlightText.substring(0, 300)}{highlightText.length > 300 ? '…' : ''}&rdquo;
                        </p>
                    </div>
                    <pre className="whitespace-pre-wrap text-sm leading-relaxed font-sans">{text}</pre>
                </div>
            )
        }

        // Split original text using mapped indices
        const originalStart = indexMap[matchIndex]
        const originalEnd = indexMap[Math.min(matchIndex + matchLength, indexMap.length - 1)]

        const before = text.substring(0, originalStart)
        const match = text.substring(originalStart, originalEnd)
        const after = text.substring(originalEnd)

        return (
            <pre className="whitespace-pre-wrap text-sm leading-relaxed font-sans">
                {before}
                <mark className="doc-highlight-active bg-yellow-200 dark:bg-yellow-700/50 px-0.5 rounded-sm">{match}</mark>
                {after}
            </pre>
        )
    }

    return (
        <div ref={containerRef} className="h-full overflow-y-auto p-6 bg-white dark:bg-neutral-900">
            {renderHighlightedText()}
        </div>
    )
}

// ─── Component ────────────────────────────────────────────────────

export function PdfCitationPanel({ target, sources, onClose, onCitationClick }: PdfCitationPanelProps) {
    const [zoom, setZoom] = React.useState(1.0)
    const [pageCount, setPageCount] = React.useState<number | null>(null)
    const [pdfError, setPdfError] = React.useState(false)

    // Reset zoom when target changes
    React.useEffect(() => {
        setZoom(1.0)
        setPageCount(null)
        setPdfError(false)
    }, [target?.fileId, target?.chunkIndex])

    if (!target) return null

    const pdfUrl = `/api/documents/${target.fileId}/pdf`
    const fileName = target.fileName?.toLowerCase() || ''
    const isPdf = fileName.endsWith('.pdf')
    const isDocx = fileName.endsWith('.docx') || fileName.endsWith('.doc')
    const fileType = isPdf ? 'PDF' : isDocx ? 'Word Document' : 'Document'

    const zoomIn = () => setZoom(z => Math.min(z + 0.25, 3.0))
    const zoomOut = () => setZoom(z => Math.max(z - 0.25, 0.5))
    const fitWidth = () => setZoom(1.0)

    return (
        <div className="w-[520px] h-full border-l bg-background flex flex-col shadow-lg animate-in slide-in-from-right duration-300 shrink-0">
            {/* ── Header ── */}
            <div className="flex items-center justify-between px-4 py-3 border-b shrink-0 bg-muted/30">
                <div className="flex items-center gap-2 min-w-0">
                    <div className={`p-1.5 rounded-md ${isPdf ? 'bg-red-500/10' : isDocx ? 'bg-blue-500/10' : 'bg-primary/10'}`}>
                        <FileText className={`h-4 w-4 ${isPdf ? 'text-red-500' : isDocx ? 'text-blue-500' : 'text-primary'}`} />
                    </div>
                    <div className="min-w-0">
                        <h2 className="text-sm font-semibold truncate">{target.fileName || "Document"}</h2>
                        <p className="text-[10px] text-muted-foreground">
                            {fileType}
                            {target.pageNumber ? ` · Page ${target.pageNumber}` : ""}
                            {target.pageNumber && pageCount ? ` of ${pageCount}` : ""}
                        </p>
                    </div>
                </div>
                <Button variant="ghost" size="icon" className="h-7 w-7 rounded-full shrink-0" onClick={onClose}>
                    <X className="h-4 w-4" />
                </Button>
            </div>

            {/* ── Citation Strip ── */}
            {sources.length > 1 && (
                <div className="flex items-center gap-1 px-3 py-2 border-b overflow-x-auto scrollbar-none shrink-0 bg-muted/10">
                    {sources.map((src, i) => {
                        const isActive = src.num === target.citationNum
                        return (
                            <button
                                key={`${src.num}-${i}`}
                                onClick={() => onCitationClick?.(src)}
                                className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-[11px] font-medium transition-all shrink-0 ${isActive
                                    ? "bg-primary text-primary-foreground shadow-sm"
                                    : "bg-muted/60 text-muted-foreground hover:bg-muted hover:text-foreground"
                                    }`}
                            >
                                <FileText className="h-3 w-3" />
                                [{src.num}]
                            </button>
                        )
                    })}
                </div>
            )}

            {/* ── Zoom Controls (PDF only) ── */}
            {isPdf && (
                <div className="flex items-center justify-center gap-1 px-3 py-1.5 border-b shrink-0">
                    <Button variant="ghost" size="icon" className="h-7 w-7" onClick={zoomOut} disabled={zoom <= 0.5}>
                        <ZoomOut className="h-3.5 w-3.5" />
                    </Button>
                    <span className="text-[11px] text-muted-foreground w-12 text-center tabular-nums">
                        {Math.round(zoom * 100)}%
                    </span>
                    <Button variant="ghost" size="icon" className="h-7 w-7" onClick={zoomIn} disabled={zoom >= 3.0}>
                        <ZoomIn className="h-3.5 w-3.5" />
                    </Button>
                    <Button variant="ghost" size="icon" className="h-7 w-7" onClick={fitWidth} title="Fit width">
                        <Maximize2 className="h-3.5 w-3.5" />
                    </Button>
                </div>
            )}

            {/* ── Document Viewer ── */}
            <div className="flex-1 min-h-0 overflow-hidden">
                {isPdf && !pdfError ? (
                    <PdfViewer
                        url={pdfUrl}
                        highlightText={target.snippet}
                        initialPage={target.pageNumber || undefined}
                        zoom={zoom}
                        onPageCountChange={setPageCount}
                        className="h-full"
                    />
                ) : (
                    /* Text-based viewer for DOCX, TXT, CSV, and other file types */
                    <DocTextViewer
                        fileId={target.fileId}
                        highlightText={target.snippet}
                    />
                )}
            </div>

            {/* ── Snippet Quote Bar ── */}
            {target.snippet && (
                <div className="shrink-0 border-t bg-muted/20 px-4 py-3">
                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">
                        Cited Passage
                    </p>
                    <p className="text-xs text-foreground/80 line-clamp-3 leading-relaxed">
                        &ldquo;{target.snippet.substring(0, 250)}{target.snippet.length > 250 ? "…" : ""}&rdquo;
                    </p>
                </div>
            )}
        </div>
    )
}

"use client"

import * as React from "react"
import { Loader2 } from "lucide-react"

// ─── Types ────────────────────────────────────────────────────────
export interface PdfHighlight {
    page: number
    rects: { left: number; top: number; width: number; height: number }[]
}

interface PdfViewerProps {
    /** URL to fetch the PDF binary from */
    url: string
    /** Text snippet to search and highlight in the PDF */
    highlightText?: string
    /** Page to scroll to initially (1-indexed) */
    initialPage?: number
    /** Zoom level (1= 100%) */
    zoom?: number
    /** Called when total page count is determined */
    onPageCountChange?: (count: number) => void
    /** CSS classes */
    className?: string
}

// ─── Constants ────────────────────────────────────────────────────
const WORKER_SRC = "/pdf.worker.min.mjs"
const CMAP_URL = "https://cdn.jsdelivr.net/npm/pdfjs-dist@5.4.530/cmaps/"

// Base scale multiplier for rendering clarity
const BASE_SCALE = 1.5

// ─── Component ────────────────────────────────────────────────────
export function PdfViewer({
    url,
    highlightText,
    initialPage,
    zoom = 1.0,
    onPageCountChange,
    className,
}: PdfViewerProps) {
    const containerRef = React.useRef<HTMLDivElement>(null)
    const [loading, setLoading] = React.useState(true)
    const [error, setError] = React.useState<string | null>(null)

    // Load and render the PDF
    React.useEffect(() => {
        let cancelled = false

        const loadPdf = async () => {
            try {
                setLoading(true)
                setError(null)

                // Dynamic import to avoid SSR issues
                const pdfjsLib = await import("pdfjs-dist")
                pdfjsLib.GlobalWorkerOptions.workerSrc = WORKER_SRC

                const loadingTask = pdfjsLib.getDocument({
                    url,
                    cMapUrl: CMAP_URL,
                    cMapPacked: true,
                })

                const pdf = await loadingTask.promise
                if (cancelled) return

                const numPages = pdf.numPages
                onPageCountChange?.(numPages)

                const container = containerRef.current
                if (!container) return

                // Clear previous renders and reset scroll
                container.innerHTML = ""
                container.scrollTop = 0

                let firstHighlightEl: HTMLElement | null = null

                // Render all pages
                for (let pageNum = 1; pageNum <= numPages; pageNum++) {
                    if (cancelled) return

                    const page = await pdf.getPage(pageNum)
                    const scale = zoom * BASE_SCALE
                    const viewport = page.getViewport({ scale })

                    // ── Page wrapper ──
                    const pageDiv = document.createElement("div")
                    pageDiv.className = "pdf-page-wrapper"
                    pageDiv.dataset.pageNumber = String(pageNum)
                    Object.assign(pageDiv.style, {
                        position: "relative",
                        width: `${viewport.width}px`,
                        height: `${viewport.height}px`,
                        margin: "0 auto 16px auto",
                        background: "white",
                        boxShadow: "0 1px 4px rgba(0,0,0,0.12)",
                        borderRadius: "4px",
                        overflow: "hidden",
                    })

                    // ── Canvas for PDF rendering ──
                    const canvas = document.createElement("canvas")
                    canvas.width = viewport.width
                    canvas.height = viewport.height
                    Object.assign(canvas.style, {
                        width: `${viewport.width}px`,
                        height: `${viewport.height}px`,
                        display: "block",
                    })
                    pageDiv.appendChild(canvas)

                    const ctx = canvas.getContext("2d")
                    if (ctx) {
                        await page.render({
                            canvasContext: ctx,
                            viewport,
                            canvas,
                        } as unknown as Parameters<typeof page.render>[0]).promise
                    }

                    // ── Text layer using PDF.js built-in TextLayer ──
                    // This gives pixel-perfect text positioning using actual font metrics
                    const textContent = await page.getTextContent()
                    const textLayerDiv = document.createElement("div")
                    textLayerDiv.className = "textLayer"
                    pageDiv.appendChild(textLayerDiv)

                    // Use PDF.js's built-in TextLayer for pixel-perfect positioning
                    const textLayer = new pdfjsLib.TextLayer({
                        textContentSource: textContent,
                        container: textLayerDiv,
                        viewport: viewport,
                    })
                    await textLayer.render()

                    // ── Highlight matching text ──
                    if (highlightText && highlightText.length > 10) {
                        const highlighted = highlightMatchingSpans(
                            textLayerDiv,
                            highlightText
                        )
                        if (highlighted && !firstHighlightEl) {
                            firstHighlightEl = highlighted
                        }
                    }

                    container.appendChild(pageDiv)
                }

                if (!cancelled) {
                    setLoading(false)

                    // Scroll to the highlighted area or initialPage
                    requestAnimationFrame(() => {
                        if (firstHighlightEl) {
                            setTimeout(() => {
                                firstHighlightEl!.scrollIntoView({
                                    behavior: "smooth",
                                    block: "center",
                                })
                            }, 100)
                        } else if (initialPage) {
                            const pageEl = container.querySelector(
                                `[data-page-number="${initialPage}"]`
                            ) as HTMLElement | null
                            if (pageEl) {
                                pageEl.scrollIntoView({ behavior: "smooth", block: "start" })
                            }
                        }
                    })
                }
            } catch (err) {
                if (!cancelled) {
                    setError("Failed to load PDF")
                    setLoading(false)
                }
            }
        }

        loadPdf()
        return () => { cancelled = true }
    }, [url, highlightText, initialPage, zoom, onPageCountChange])

    if (error) {
        return (
            <div className={`flex items-center justify-center h-full ${className || ""}`}>
                <p className="text-sm text-muted-foreground">{error}</p>
            </div>
        )
    }

    return (
        <div className={`relative h-full ${className || ""}`}>
            {loading && (
                <div className="absolute inset-0 flex items-center justify-center bg-background/80 z-10">
                    <div className="flex flex-col items-center gap-2">
                        <Loader2 className="h-6 w-6 animate-spin text-primary" />
                        <span className="text-xs text-muted-foreground">Loading PDF…</span>
                    </div>
                </div>
            )}
            <div
                ref={containerRef}
                className="h-full overflow-y-auto overflow-x-auto p-4 bg-muted/30 scroll-smooth"
            />
        </div>
    )
}

// ─── Text Highlight Matching (DOM-based, pixel-perfect) ──────────

/**
 * Walk through the TextLayer's rendered spans and highlight those
 * whose text matches the search snippet. Returns the first highlighted
 * element for scroll-into-view, or null if nothing matched.
 */
function highlightMatchingSpans(
    textLayerDiv: HTMLElement,
    searchText: string
): HTMLElement | null {
    // Build full page text from all spans
    const spans = Array.from(textLayerDiv.querySelectorAll("span")) as HTMLSpanElement[]
    if (spans.length === 0) return null

    // Build running text with span index tracking
    const spanRanges: { start: number; end: number; span: HTMLSpanElement }[] = []
    let runningText = ""

    for (const span of spans) {
        const text = span.textContent || ""
        if (!text.trim()) continue
        const start = runningText.length
        runningText += text + " "
        spanRanges.push({ start, end: runningText.length - 1, span })
    }

    // Build an index map mapping normalized text indices back to original chunk string
    let normalizedPage = ""
    let isSpace = false
    const indexMap: number[] = []

    for (let i = 0; i < runningText.length; i++) {
        const char = runningText[i]
        if (/\s/.test(char)) {
            if (!isSpace) {
                // Only add a single space to normalized text if we haven't just added one
                if (normalizedPage.length > 0) {
                    normalizedPage += " "
                    indexMap.push(i)
                    isSpace = true
                }
            }
        } else {
            normalizedPage += char.toLowerCase()
            indexMap.push(i)
            isSpace = false
        }
    }
    indexMap.push(runningText.length)

    const normalizedSearch = searchText.replace(/\s+/g, " ").trim().toLowerCase()

    // Try progressively shorter snippets for matching to handle PDF.js extraction anomalies
    const searchLengths = [
        Math.min(normalizedSearch.length, 200),
        Math.min(normalizedSearch.length, 100),
        Math.min(normalizedSearch.length, 60),
        Math.min(normalizedSearch.length, 30),
    ]

    let matchIndex = -1
    let matchLength = 0

    for (const len of searchLengths) {
        if (len < 15) continue
        const fragment = normalizedSearch.substring(0, len)
        matchIndex = normalizedPage.indexOf(fragment)
        if (matchIndex !== -1) {
            matchLength = Math.min(normalizedSearch.length, normalizedPage.length - matchIndex)
            break
        }
    }

    if (matchIndex === -1) return null

    const originalStart = indexMap[matchIndex]
    const originalEnd = indexMap[Math.min(matchIndex + matchLength, indexMap.length - 1)]

    let firstHighlighted: HTMLElement | null = null

    // Highlight spans that overlap with the match range
    for (const { start, end, span } of spanRanges) {
        if (end > originalStart && start < originalEnd) {
            // This span overlaps with the matched text — highlight it
            span.style.backgroundColor = "rgba(250, 204, 21, 0.4)"
            span.style.borderRadius = "2px"
            span.style.mixBlendMode = "multiply"
            span.classList.add("pdf-highlight-active")

            if (!firstHighlighted) {
                firstHighlighted = span
            }
        }
    }

    return firstHighlighted
}

"use client"

import * as React from "react"
import { FileText, Loader2, XCircle, Send, Plus, Minus, RefreshCw, FileEdit } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Textarea } from "@/components/ui/textarea"
import { toast } from "sonner"
import { DuplicateFileModal } from "@/components/ui/duplicate-file-modal"
import { ToolPageLayout } from "@/components/ui/tool-page-layout"
import { FileUploadZone } from "@/components/ui/file-upload-zone"

interface ComparisonResult {
    summary: string
    changes: {
        additions: string[]
        deletions: string[]
        modifications: string[]
    }
    statistics: {
        totalChanges: number
        addedLines: number
        deletedLines: number
        modifiedLines: number
    }
}

export default function RedlineAnalysis() {
    const [originalFile, setOriginalFile] = React.useState<File | null>(null)
    const [revisedFile, setRevisedFile] = React.useState<File | null>(null)
    const [isProcessing, setIsProcessing] = React.useState(false)
    const [result, setResult] = React.useState<ComparisonResult | null>(null)
    const [isDuplicateModalOpen, setIsDuplicateModalOpen] = React.useState(false)
    const [question, setQuestion] = React.useState("")
    const [conversation, setConversation] = React.useState<Array<{ role: 'user' | 'assistant', content: string }>>([])
    const [isAsking, setIsAsking] = React.useState(false)

    const handleFileSelect = (type: 'original' | 'revised', file: File) => {
        if ((type === 'original' && revisedFile && revisedFile.name === file.name) ||
            (type === 'revised' && originalFile && originalFile.name === file.name) ||
            (type === 'original' && originalFile && originalFile.name === file.name) ||
            (type === 'revised' && revisedFile && revisedFile.name === file.name)) {
            setIsDuplicateModalOpen(true)
            return
        }
        if (type === 'original') {
            setOriginalFile(file)
        } else {
            setRevisedFile(file)
        }
        toast.success(`${type === 'original' ? 'Original' : 'Revised'} file uploaded`)
    }

    const handleCompare = async () => {
        if (!originalFile || !revisedFile) {
            toast.error("Please upload both original and revised files")
            return
        }

        setIsProcessing(true)
        const formData = new FormData()
        formData.append('original', originalFile)
        formData.append('revised', revisedFile)

        try {
            const response = await fetch('/api/templates/redline-analysis', {
                method: 'POST',
                body: formData
            })

            if (!response.ok) {
                const error = await response.json()
                throw new Error(error.error || 'Failed to process documents')
            }

            const data = await response.json()
            setResult(data)
            toast.success("Documents compared successfully!")
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : "Failed to compare documents"
            toast.error(message)
        } finally {
            setIsProcessing(false)
        }
    }

    const handleAskQuestion = async () => {
        if (!question.trim() || !result) return

        setIsAsking(true)
        const userMessage = question
        setConversation(prev => [...prev, { role: 'user', content: userMessage }])
        setQuestion("")

        try {
            const response = await fetch('/api/templates/redline-analysis/query', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    question: userMessage,
                    context: result
                })
            })

            if (!response.ok) {
                throw new Error('Failed to get answer')
            }

            const data = await response.json()
            setConversation(prev => [...prev, { role: 'assistant', content: data.answer }])
        } catch (error) {
            toast.error("Failed to get answer")
        } finally {
            setIsAsking(false)
        }
    }

    const resetAnalysis = () => {
        setOriginalFile(null)
        setRevisedFile(null)
        setResult(null)
        setConversation([])
        setQuestion("")
    }

    return (
        <ToolPageLayout
            title="Redline Analysis"
            description="Compare document versions and analyze changes with AI"
            icon={<FileEdit className="h-4 w-4" />}
            accentColor="bg-indigo-500/10 text-indigo-600 dark:text-indigo-400"
        >

            {!result ? (
                /* Upload Section */
                <div className="space-y-5 max-w-4xl mx-auto">
                    <div className="grid md:grid-cols-2 gap-4">
                        <Card className="border-dashed">
                            <CardHeader className="pb-3">
                                <div className="flex items-center gap-2">
                                    <Badge variant="outline" className="text-xs">Original</Badge>
                                    <CardTitle className="text-base">Original Document</CardTitle>
                                </div>
                                <CardDescription>Upload the original version</CardDescription>
                            </CardHeader>
                            <CardContent>
                                <FileUploadZone id="original-file" file={originalFile} onFileSelect={(f) => handleFileSelect('original', f)} />
                            </CardContent>
                        </Card>

                        <Card className="border-dashed">
                            <CardHeader className="pb-3">
                                <div className="flex items-center gap-2">
                                    <Badge variant="outline" className="text-xs">Revised</Badge>
                                    <CardTitle className="text-base">Revised Document</CardTitle>
                                </div>
                                <CardDescription>Upload the revised version</CardDescription>
                            </CardHeader>
                            <CardContent>
                                <FileUploadZone id="revised-file" file={revisedFile} onFileSelect={(f) => handleFileSelect('revised', f)} />
                            </CardContent>
                        </Card>
                    </div>

                    <Button
                        onClick={handleCompare}
                        disabled={!originalFile || !revisedFile || isProcessing}
                        size="lg"
                        className="w-full gap-2"
                    >
                        {isProcessing ? (
                            <><Loader2 className="h-4 w-4 animate-spin" /> Processing...</>
                        ) : (
                            <><FileEdit className="h-4 w-4" /> Compare Documents</>
                        )}
                    </Button>
                </div>
            ) : (
                /* Results Section */
                <div className="space-y-5">
                    {/* Statistics */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                        <Card className="bg-muted/30">
                            <CardContent className="pt-5 pb-4 text-center">
                                <div className="text-2xl font-bold font-mono">{result.statistics.totalChanges}</div>
                                <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide mt-0.5">Total Changes</p>
                            </CardContent>
                        </Card>
                        <Card className="bg-emerald-500/5 border-emerald-500/20">
                            <CardContent className="pt-5 pb-4 text-center">
                                <div className="text-2xl font-bold font-mono text-emerald-600 dark:text-emerald-400">{result.statistics.addedLines}</div>
                                <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide mt-0.5">Additions</p>
                            </CardContent>
                        </Card>
                        <Card className="bg-red-500/5 border-red-500/20">
                            <CardContent className="pt-5 pb-4 text-center">
                                <div className="text-2xl font-bold font-mono text-red-600 dark:text-red-400">{result.statistics.deletedLines}</div>
                                <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide mt-0.5">Deletions</p>
                            </CardContent>
                        </Card>
                        <Card className="bg-blue-500/5 border-blue-500/20">
                            <CardContent className="pt-5 pb-4 text-center">
                                <div className="text-2xl font-bold font-mono text-blue-600 dark:text-blue-400">{result.statistics.modifiedLines}</div>
                                <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wide mt-0.5">Modifications</p>
                            </CardContent>
                        </Card>
                    </div>

                    {/* Summary */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-indigo-500/10 flex items-center justify-center">
                                    <FileText className="h-3.5 w-3.5 text-indigo-600 dark:text-indigo-400" />
                                </div>
                                Summary
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm leading-relaxed text-foreground/90">{result.summary}</p>
                        </CardContent>
                    </Card>

                    {/* Changes Details */}
                    <div className="grid md:grid-cols-3 gap-4">
                        {result.changes.additions.length > 0 && (
                            <Card className="border-emerald-500/20">
                                <CardHeader className="pb-3">
                                    <CardTitle className="flex items-center gap-2 text-sm">
                                        <Plus className="h-4 w-4 text-emerald-600 dark:text-emerald-400" />
                                        <span className="text-emerald-700 dark:text-emerald-300">Additions</span>
                                        <Badge variant="secondary" className="ml-auto text-[10px]">{result.changes.additions.length}</Badge>
                                    </CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <ul className="space-y-2 text-sm">
                                        {result.changes.additions.map((change, i) => (
                                            <li key={i} className="flex items-start gap-2 border-l-2 border-emerald-500/40 pl-3 py-0.5">
                                                <span className="text-foreground/90">{change}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </CardContent>
                            </Card>
                        )}

                        {result.changes.deletions.length > 0 && (
                            <Card className="border-red-500/20">
                                <CardHeader className="pb-3">
                                    <CardTitle className="flex items-center gap-2 text-sm">
                                        <Minus className="h-4 w-4 text-red-600 dark:text-red-400" />
                                        <span className="text-red-700 dark:text-red-300">Deletions</span>
                                        <Badge variant="secondary" className="ml-auto text-[10px]">{result.changes.deletions.length}</Badge>
                                    </CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <ul className="space-y-2 text-sm">
                                        {result.changes.deletions.map((change, i) => (
                                            <li key={i} className="flex items-start gap-2 border-l-2 border-red-500/40 pl-3 py-0.5 line-through text-muted-foreground">
                                                <span>{change}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </CardContent>
                            </Card>
                        )}

                        {result.changes.modifications.length > 0 && (
                            <Card className="border-blue-500/20">
                                <CardHeader className="pb-3">
                                    <CardTitle className="flex items-center gap-2 text-sm">
                                        <RefreshCw className="h-4 w-4 text-blue-600 dark:text-blue-400" />
                                        <span className="text-blue-700 dark:text-blue-300">Modifications</span>
                                        <Badge variant="secondary" className="ml-auto text-[10px]">{result.changes.modifications.length}</Badge>
                                    </CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <ul className="space-y-2 text-sm">
                                        {result.changes.modifications.map((change, i) => (
                                            <li key={i} className="flex items-start gap-2 border-l-2 border-blue-500/40 pl-3 py-0.5">
                                                <span className="text-foreground/90">{change}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </CardContent>
                            </Card>
                        )}
                    </div>

                    {/* Q&A Section */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="text-base">Ask Questions</CardTitle>
                            <CardDescription>Ask questions about the changes in the document</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {conversation.length > 0 && (
                                <div className="space-y-3 max-h-64 overflow-auto mb-4">
                                    {conversation.map((msg, i) => (
                                        <div key={i} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                            <div className={`rounded-lg px-4 py-2 max-w-[80%] ${msg.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-muted'}`}>
                                                <p className="text-sm">{msg.content}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                            <div className="flex gap-2">
                                <Textarea
                                    placeholder="Ask about the changes..."
                                    value={question}
                                    onChange={(e) => setQuestion(e.target.value)}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter' && !e.shiftKey) {
                                            e.preventDefault()
                                            handleAskQuestion()
                                        }
                                    }}
                                    className="min-h-[60px]"
                                />
                                <Button onClick={handleAskQuestion} disabled={isAsking || !question.trim()}>
                                    {isAsking ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                                </Button>
                            </div>
                        </CardContent>
                    </Card>

                    <Button onClick={resetAnalysis} variant="outline" className="gap-2">
                        <XCircle className="h-4 w-4" />
                        New Analysis
                    </Button>
                </div>
            )}
            <DuplicateFileModal
                isOpen={isDuplicateModalOpen}
                onOpenChange={setIsDuplicateModalOpen}
            />
        </ToolPageLayout>
    )
}

"use client"

import * as React from "react"
import {
    FileText, Copy, FileCheck, FileSignature, Languages,
    FileEdit, FileWarning, Gavel, ScanSearch, ArrowRight,
    Scale, Sparkles, Building2
} from "lucide-react"
import { Skeleton } from "@/components/ui/skeleton"
