                                                        <p className="text-[13px] leading-relaxed text-muted-foreground line-clamp-3 mb-3">
                                                            {workflow.description}
                                                        </p>

                                                        {/* Hover Arrow */}
                                                        <div className="flex items-center gap-1 text-xs font-medium text-primary opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                                                            <span>Open</span>
                                                            <ArrowRight className="h-3 w-3" />
                                                        </div>
                                                    </button>
                                                )
                                            })}
                                        </div>
                                    </section>
                                )
                            })}
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

"use client"

import * as React from "react"
import { Loader2, FileText, CheckCircle2, MessageSquare, Send, Users, AlertTriangle, BookOpen } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Textarea } from "@/components/ui/textarea"
import { Badge } from "@/components/ui/badge"
import { toast } from "sonner"
import { DuplicateFileModal } from "@/components/ui/duplicate-file-modal"
import { ToolPageLayout } from "@/components/ui/tool-page-layout"
import { FileUploadZone } from "@/components/ui/file-upload-zone"

interface TranscriptAnalysis {
    summary: string
    keyThemes: Array<{
        theme: string
        description: string
        importance: 'high' | 'medium' | 'low'
    }>
    witnesses: Array<{
        name: string
        role: string
        keyTestimony: string[]
        credibilityNotes: string
    }>
    contradictions: string[]
    importantAdmissions: string[]
    timeline: Array<{
        date: string
        event: string
    }>
}

export default function Transcripts() {
    const [transcriptFile, setTranscriptFile] = React.useState<File | null>(null)
    const [isAnalyzing, setIsAnalyzing] = React.useState(false)
    const [analysis, setAnalysis] = React.useState<TranscriptAnalysis | null>(null)
    const [isDuplicateModalOpen, setIsDuplicateModalOpen] = React.useState(false)
    const [question, setQuestion] = React.useState("")
    const [conversation, setConversation] = React.useState<Array<{ role: 'user' | 'assistant', content: string }>>([])
    const [isAsking, setIsAsking] = React.useState(false)

    const handleFileSelect = (file: File) => {
        if (transcriptFile && transcriptFile.name === file.name) {
            setIsDuplicateModalOpen(true)
            return
        }
        setTranscriptFile(file)
        toast.success("Transcript uploaded")
    }

    const handleAnalyze = async () => {
        if (!transcriptFile) {
            toast.error("Please upload a transcript file")
            return
        }
        setIsAnalyzing(true)
        const formData = new FormData()
        formData.append('transcript', transcriptFile)
        try {
            const response = await fetch('/api/templates/transcripts', { method: 'POST', body: formData })
            if (!response.ok) {
                const error = await response.json()
                throw new Error(error.error || 'Failed to analyze transcript')
            }
            const data = await response.json()
            setAnalysis(data)
            toast.success("Transcript analyzed successfully!")
        } catch (error: unknown) {
            const message = error instanceof Error ? error.message : "Failed to analyze transcript"
            toast.error(message)
        } finally {
            setIsAnalyzing(false)
        }
    }

    const handleAskQuestion = async () => {
        if (!question.trim() || !analysis) return
        setIsAsking(true)
        const userMessage = question
        setConversation(prev => [...prev, { role: 'user', content: userMessage }])
        setQuestion("")
        try {
            const response = await fetch('/api/templates/transcripts/query', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ question: userMessage, context: analysis })
            })
            if (!response.ok) throw new Error('Failed to get answer')
            const data = await response.json()
            setConversation(prev => [...prev, { role: 'assistant', content: data.answer }])
        } catch (error) {
            toast.error("Failed to get answer")
        } finally {
            setIsAsking(false)
        }
    }

    const resetAnalysis = () => {
        setTranscriptFile(null)
        setAnalysis(null)
        setConversation([])
        setQuestion("")
    }

    const importanceBorderColor = (importance: string) => {
        switch (importance) {
            case 'high': return 'border-red-500/40'
            case 'medium': return 'border-amber-500/40'
            default: return 'border-blue-500/30'
        }
    }

    const importanceBadgeVariant = (importance: string): 'destructive' | 'default' | 'secondary' => {
        switch (importance) {
            case 'high': return 'destructive'
            case 'medium': return 'default'
            default: return 'secondary'
        }
    }

    return (
        <ToolPageLayout
            title="Transcripts"
            description="Analyze deposition and trial transcripts for key insights"
            icon={<BookOpen className="h-4 w-4" />}
            accentColor="bg-orange-500/10 text-orange-600 dark:text-orange-400"
        >

            {!analysis ? (
                <Card className="max-w-2xl mx-auto">
                    <CardHeader className="pb-3">
                        <CardTitle className="text-base">Upload Transcript</CardTitle>
                        <CardDescription>Upload a deposition, trial, or hearing transcript</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                        <FileUploadZone id="transcript" file={transcriptFile} onFileSelect={handleFileSelect} />
                        <Button onClick={handleAnalyze} disabled={!transcriptFile || isAnalyzing} size="lg" className="w-full gap-2">
                            {isAnalyzing ? (
                                <><Loader2 className="h-4 w-4 animate-spin" /> Analyzing Transcript...</>
                            ) : (
                                <><BookOpen className="h-4 w-4" /> Analyze Transcript</>
                            )}
                        </Button>
                    </CardContent>
                </Card>
            ) : (
                <div className="space-y-5">
                    {/* Summary */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-orange-500/10 flex items-center justify-center">
                                    <BookOpen className="h-3.5 w-3.5 text-orange-600 dark:text-orange-400" />
                                </div>
                                Executive Summary
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <p className="text-sm leading-relaxed text-foreground/90">{analysis.summary}</p>
                        </CardContent>
                    </Card>

                    {/* Key Themes */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-indigo-500/10 flex items-center justify-center">
                                    <FileText className="h-3.5 w-3.5 text-indigo-600 dark:text-indigo-400" />
                                </div>
                                Key Themes
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-3">
                                {analysis.keyThemes.map((theme, i) => (
                                    <div key={i} className={`border-l-2 ${importanceBorderColor(theme.importance)} pl-4 py-1`}>
                                        <div className="flex items-center gap-2 mb-0.5">
                                            <h3 className="font-semibold text-sm">{theme.theme}</h3>
                                            <Badge variant={importanceBadgeVariant(theme.importance)} className="text-[10px]">{theme.importance}</Badge>
                                        </div>
                                        <p className="text-sm text-muted-foreground">{theme.description}</p>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Witnesses */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <div className="h-7 w-7 rounded-md bg-purple-500/10 flex items-center justify-center">
                                    <Users className="h-3.5 w-3.5 text-purple-600 dark:text-purple-400" />
                                </div>
                                Witness Analysis
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-4">
                                {analysis.witnesses.map((witness, i) => (
                                    <div key={i} className="border rounded-lg p-4 bg-muted/10">
                                        <div className="mb-2">
                                            <h3 className="font-semibold text-sm">{witness.name}</h3>
                                            <p className="text-xs text-muted-foreground">{witness.role}</p>
                                        </div>
                                        <div className="space-y-2">
                                            <div>
                                                <p className="text-[10px] font-bold tracking-wide uppercase text-muted-foreground mb-1">Key Testimony</p>
                                                <ul className="space-y-1">
                                                    {witness.keyTestimony.map((testimony, j) => (
                                                        <li key={j} className="text-sm flex items-start gap-2 border-l-2 border-primary/20 pl-2.5 py-0.5 text-foreground/90">{testimony}</li>
                                                    ))}
                                                </ul>
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-bold tracking-wide uppercase text-muted-foreground mb-1">Credibility Assessment</p>
                                                <p className="text-sm text-foreground/80 italic">{witness.credibilityNotes}</p>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>

                    {/* Contradictions */}
                    {analysis.contradictions.length > 0 && (
                        <Card className="border-amber-500/30">
                            <CardHeader className="pb-3">
                                <CardTitle className="flex items-center gap-2 text-base">
                                    <div className="h-7 w-7 rounded-md bg-amber-500/10 flex items-center justify-center">
                                        <AlertTriangle className="h-3.5 w-3.5 text-amber-600 dark:text-amber-400" />
                                    </div>
                                    Contradictions & Inconsistencies
                                    <Badge variant="destructive" className="ml-auto text-[10px]">{analysis.contradictions.length}</Badge>
                                </CardTitle>
                            </CardHeader>
                            <CardContent>
                                <ul className="space-y-2">
                                    {analysis.contradictions.map((contradiction, i) => (
                                        <li key={i} className="flex items-start gap-2 text-sm rounded-md bg-amber-500/5 p-3">
                                            <AlertTriangle className="h-3.5 w-3.5 text-amber-500 mt-0.5 shrink-0" />
                                            <span className="text-foreground/90">{contradiction}</span>
                                        </li>
                                    ))}
                                </ul>
                            </CardContent>
                        </Card>
                    )}

                    {/* Important Admissions */}
                    {analysis.importantAdmissions.length > 0 && (
                        <Card>
                            <CardHeader className="pb-3">
                                <CardTitle className="flex items-center gap-2 text-base">
                                    <div className="h-7 w-7 rounded-md bg-emerald-500/10 flex items-center justify-center">
                                        <CheckCircle2 className="h-3.5 w-3.5 text-emerald-600 dark:text-emerald-400" />
                                    </div>
                                    Important Admissions
                                </CardTitle>
                            </CardHeader>
                            <CardContent>
                                <ul className="space-y-2">
                                    {analysis.importantAdmissions.map((admission, i) => (
                                        <li key={i} className="flex items-start gap-2.5 text-sm">
                                            <span className="h-5 w-5 rounded-full bg-emerald-500/10 flex items-center justify-center shrink-0 mt-0.5">
                                                <CheckCircle2 className="h-3 w-3 text-emerald-600 dark:text-emerald-400" />
                                            </span>
                                            <span className="text-foreground/90">{admission}</span>
                                        </li>
                                    ))}
                                </ul>
                            </CardContent>
                        </Card>
                    )}

                    {/* Q&A */}
                    <Card>
                        <CardHeader className="pb-3">
                            <CardTitle className="flex items-center gap-2 text-base">
                                <MessageSquare className="h-4 w-4" />
                                Ask Questions
                            </CardTitle>
                            <CardDescription>Query the transcript for specific information</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {conversation.length > 0 && (
                                <div className="space-y-3 max-h-64 overflow-auto mb-4">
                                    {conversation.map((msg, i) => (
                                        <div key={i} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                            <div className={`rounded-lg px-4 py-2 max-w-[80%] ${msg.role === 'user' ? 'bg-primary text-primary-foreground' : 'bg-muted'}`}>
                                                <p className="text-sm">{msg.content}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                            <div className="flex gap-2">
                                <Textarea
                                    placeholder="Ask about the transcript..."
                                    value={question}
                                    onChange={(e) => setQuestion(e.target.value)}
                                    onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleAskQuestion() } }}
                                    className="min-h-[60px]"
                                />
                                <Button onClick={handleAskQuestion} disabled={isAsking || !question.trim()}>
                                    {isAsking ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
                                </Button>
                            </div>
                        </CardContent>
                    </Card>

                    <Button onClick={resetAnalysis} variant="outline" className="gap-2">
                        <FileText className="h-4 w-4" />
                        Analyze New Transcript
                    </Button>
                </div>
            )}
            <DuplicateFileModal isOpen={isDuplicateModalOpen} onOpenChange={setIsDuplicateModalOpen} />
        </ToolPageLayout>
    )
}

"use client"

import * as React from "react"
import Image from "next/image"
import { FileText, Cloud, AlertTriangle, Sparkles } from "lucide-react"
import Papa from "papaparse"
import { Attachment } from "@/types"

/**
 * High-fidelity DOCX renderer using docx-preview library.
 * Renders Word documents with original formatting preserved —
 * fonts, alignment, indentation, tables, page layout, etc.
 */
function DocxRenderer({ arrayBuffer }: { arrayBuffer: ArrayBuffer }) {
    const containerRef = React.useRef<HTMLDivElement>(null)
    const [error, setError] = React.useState<string | null>(null)

    React.useEffect(() => {
        if (!containerRef.current) return

        const renderDoc = async () => {
            try {
                // Dynamic import — docx-preview is client-only
                const docxPreview = await import('docx-preview')

                // Clear any previous content
                containerRef.current!.innerHTML = ''

                await docxPreview.renderAsync(arrayBuffer, containerRef.current!, undefined, {
                    className: 'docx-viewer',
                    inWrapper: true,
                    ignoreWidth: false,
                    ignoreHeight: true,
                    ignoreFonts: false,
                    breakPages: true,
                    ignoreLastRenderedPageBreak: false,
                    experimental: false,
                    trimXmlDeclaration: true,
                    useBase64URL: true,
                    renderHeaders: true,
                    renderFooters: true,
                    renderFootnotes: true,
                    renderEndnotes: true,
                })
            } catch (err) {
                setError('Failed to render document preview')
            }
        }

        renderDoc()
    }, [arrayBuffer])

    if (error) {
        return (
            <div className="flex flex-col items-center gap-3 text-muted-foreground h-full justify-center p-8">
                <AlertTriangle className="h-10 w-10" />
                <p>{error}</p>
            </div>
        )
    }

    return (
        <div
            ref={containerRef}
            className="docx-preview-wrapper w-full min-h-full bg-[#e8e8e8] dark:bg-neutral-800 overflow-auto"
        />
    )
}

interface FilePreviewContentProps {
    attachment: Attachment
}

export function FilePreviewContent({ attachment }: FilePreviewContentProps) {
    const [content, setContent] = React.useState<React.ReactNode | null>(null)
    const [loading, setLoading] = React.useState(false)

    React.useEffect(() => {
        const loadContent = async () => {
            if (!attachment.file && attachment.source === 'upload' && !attachment.url) return
            setLoading(true)

            try {
                if (attachment.source === 'drive') {
                    setContent(
                        <div className="flex flex-col items-center justify-center p-8 text-center h-full">
                            <Cloud className="h-16 w-16 text-muted-foreground mb-4" />
                            <h3 className="text-lg font-semibold mb-2">Drive File Preview</h3>
                            <p className="text-muted-foreground">Preview not available for remote Drive files yet.</p>
                            <p className="text-xs text-muted-foreground mt-2">({attachment.name})</p>
                        </div>
                    )
                } else if (attachment.type === 'docx' && (attachment.file || attachment.url)) {
                    let arrayBuffer: ArrayBuffer

                    if (attachment.file) {
                        arrayBuffer = await attachment.file.arrayBuffer()
                    } else {
                        const fetchUrl = attachment.url!
                        const res = await fetch(fetchUrl)
                        if (!res.ok) {
                            throw new Error(`Failed to fetch file: ${res.status}`)
                        }
                        const contentType = res.headers.get('content-type') || ''
                        if (contentType.includes('text/html') || contentType.includes('text/xml')) {
                            throw new Error('Received HTML/XML instead of document binary')
                        }
                        arrayBuffer = await res.arrayBuffer()
                        // Validate it looks like a ZIP (docx = zip with PK header)
                        const header = new Uint8Array(arrayBuffer.slice(0, 4))
                        if (header[0] !== 0x50 || header[1] !== 0x4B) {
                            throw new Error('File does not appear to be a valid .docx document')
                        }
                    }

                    // Use docx-preview for high-fidelity Word document rendering
                    setContent(
                        <DocxRenderer arrayBuffer={arrayBuffer} />
                    )
                } else if (attachment.type === 'csv' && (attachment.file || attachment.url)) {
                    const parseSource = attachment.file || attachment.url
                    if (parseSource) {
                        const config: Papa.ParseConfig<string[]> = {
                            complete: (results) => {
                                setContent(
                                    <div className="overflow-auto p-4">
                                        <table className="w-full text-sm border-collapse">
                                            <tbody>
                                                {results.data.slice(0, 100).map((row, i) => (
                                                    <tr key={i} className="border-b hover:bg-muted/50">
                                                        {(row as string[]).map((cell, j) => (
                                                            <td key={j} className="p-2 border-r last:border-r-0 max-w-[200px] truncate">{cell}</td>
                                                        ))}
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                        {results.data.length > 100 && (
                                            <p className="text-xs text-muted-foreground mt-4 text-center">Showing first 100 rows</p>
                                        )}
                                    </div>
                                )
                            },
                            header: false
                        }

                        if (attachment.file) {
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            Papa.parse(attachment.file as any, config)
                        } else if (attachment.url) {
                            Papa.parse(attachment.url, {
                                ...config,
                                download: true
                            } as Papa.ParseConfig<string[]>)
                        }
                    }
                } else if (attachment.type === 'text' && attachment.file) {
                    const text = await attachment.file.text()
                    setContent(
                        <pre className="p-6 text-sm font-mono whitespace-pre-wrap overflow-auto h-full bg-muted/20 text-foreground">
                            {text}
                        </pre>
                    )
                } else if (attachment.type === 'text' && attachment.url) {
                    const res = await fetch(attachment.url)
                    const text = await res.text()
                    setContent(
                        <pre className="p-6 text-sm font-mono whitespace-pre-wrap overflow-auto h-full bg-muted/20 text-foreground">
                            {text}
                        </pre>
                    )
                } else if (attachment.type === 'image' && attachment.url) {
                    setContent(
                        <div className="relative w-full h-full flex items-center justify-center">
                            <Image
                                src={attachment.url}
                                alt={attachment.name}
                                fill
                                className="object-contain"
                                unoptimized
                            />
                        </div>
                    )
                } else if (attachment.type === 'pdf' && attachment.url) {
                    setContent(<iframe src={attachment.url} title="Document Preview" className="w-full h-full border-0 bg-white" />)
                } else {
                    setContent(
                        <div className="flex flex-col items-center gap-2 text-muted-foreground h-full justify-center">
                            <FileText className="h-12 w-12" />
                            <p>Preview not available for this file type</p>
                        </div>
                    )
                }
            } catch (error) {
                // Show extracted text as fallback if available
                if (attachment.extractedText) {
                    setContent(
                        <div className="p-6 h-full overflow-auto">
                            <div className="flex items-center gap-2 mb-4 text-amber-600 dark:text-amber-400 text-sm">
                                <AlertTriangle className="h-4 w-4 shrink-0" />
                                <span>Showing extracted text (document preview unavailable)</span>
                            </div>
                            <pre className="text-sm font-mono whitespace-pre-wrap text-foreground bg-muted/20 p-4 rounded-lg">
                                {attachment.extractedText}
                            </pre>
                        </div>
                    )
                } else {
                    setContent(
                        <div className="flex flex-col items-center gap-3 text-destructive h-full justify-center p-8">
                            <AlertTriangle className="h-12 w-12" />
                            <p className="font-medium">Failed to load preview</p>
                            <p className="text-xs text-muted-foreground text-center max-w-sm">
                                The file may have expired or is not in a supported format. Try re-uploading the document.
                            </p>
                        </div>
                    )
                }
            } finally {
                setLoading(false)
            }
        }

        loadContent()
    }, [attachment])

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center h-full gap-4 min-h-[400px]">
                <Sparkles className="h-8 w-8 text-primary animate-spin" />
                <p className="text-sm text-muted-foreground">Loading preview...</p>
            </div>
        )
    }

    return <div className="h-full w-full">{content}</div>
}

"use client"

import { useEffect, useRef, useCallback } from "react"
import { toast } from "sonner"
import { Info } from "lucide-react"

export function VersionWatcher() {
    const toastShownRef = useRef(false)
    const checkIntervalRef = useRef<NodeJS.Timeout | null>(null)

    const showUpdateToast = useCallback(() => {
        toast.custom((t) => (
            <div className="flex flex-col gap-3 w-[356px] bg-card border border-border p-4 rounded-xl shadow-lg text-foreground">
                <div className="flex gap-3">
                    <div className="mt-0.5 flex-shrink-0">
                        <div className="w-6 h-6 bg-primary/10 rounded-md flex items-center justify-center">
                            <Info className="w-3.5 h-3.5 text-primary" />
                        </div>
                    </div>
                    <div className="flex flex-col gap-1">
                        <p className="text-[14px] font-semibold leading-snug text-foreground">The platform has been updated</p>
                        <p className="text-[13px] text-muted-foreground">Please refresh the page to see changes.</p>
                    </div>
                </div>
                <div className="flex justify-end gap-2 mt-1">
                    <button
                        onClick={() => toast.dismiss(t)}
                        className="px-3 py-1.5 text-[13px] font-medium text-muted-foreground bg-secondary hover:bg-accent border border-border rounded-md transition-colors"
                    >
                        Not now
                    </button>
                    <button
                        onClick={() => window.location.reload()}
                        className="px-3 py-1.5 text-[13px] font-medium text-primary-foreground bg-primary hover:bg-primary/90 rounded-md transition-colors"
                    >
                        Refresh
                    </button>
                </div>
            </div>
        ), {
            duration: Infinity,
            position: 'bottom-right'
        })
    }, [])

    const checkVersion = useCallback(async () => {
        // Stop checking if we already showed the toast
        if (toastShownRef.current) return

        try {
            const res = await fetch('/api/version', { cache: 'no-store' })
            if (!res.ok) return
            const data = await res.json()
            const fetchedVersion = data.version

            // We store the initial version in a module-level variable to avoid React state re-renders
            // since this component renders nothing and shouldn't trigger tree updates
            const currentVersion = window.sessionStorage.getItem('app-version')

            if (!currentVersion) {
                // First check, just store it
                window.sessionStorage.setItem('app-version', fetchedVersion)
            } else if (currentVersion !== fetchedVersion) {
                // Version changed — a new deployment happened, show toast
                showUpdateToast()
                toastShownRef.current = true
                // Update stored version so we don't keep showing it if they dismiss
                window.sessionStorage.setItem('app-version', fetchedVersion)
            }
        } catch (error) {
        }
    }, [showUpdateToast])

    useEffect(() => {
        // Don't run on server
        if (typeof window === 'undefined') return

        // Initial check to set the baseline version
        checkVersion()

        // Check every 5 minutes
        checkIntervalRef.current = setInterval(checkVersion, 5 * 60 * 1000)

        // Also check when user returns to the tab
        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                checkVersion()
            }
        }

        document.addEventListener('visibilitychange', handleVisibilityChange)

        return () => {
            if (checkIntervalRef.current) clearInterval(checkIntervalRef.current)
            document.removeEventListener('visibilitychange', handleVisibilityChange)
        }
    }, [checkVersion])

    // This component renders nothing, it just manages the background polling
    return null
}
